/** Reads exactly 12 lines from the scanner and builds the 12×12 grid. */
private static int[][] readArea(Scanner sc) {
    int[][] area = new int[12][12];
    for (int i = 0; i < area.length; i++) {
        char[] nums = sc.nextLine().toCharArray();
        for (int j = 0; j < area.length; j++) {
            area[i][j] = Character.getNumericValue(nums[j]);
        }
    }
    return area;
}

/** Scans the grid, counts islands and mutates the grid via `checkIsland`. */
private static int countIslands(int[][] area) {
    int count = 0;
    for (int i = 0; i < area.length; i++) {
        for (int j = 0; j < area.length; j++) {
            if (area[i][j] == 1) {
                count++;
                area = checkIsland(area, i, j);
            }
        }
    }
    return count;
}

