public static void main(String[] args) {
    FastScanner scanner = new FastScanner();
    PrintWriter out = new PrintWriter(System.out);
    int T = scanner.nextInt();
    while (T-- > 0) {
        int N = scanner.nextInt();
        PriorityQueue<Point> queue = buildQueue(scanner, N);
        ProcessResult result = processQueue(queue, N);
        outputResult(out, result.outArr, result.assign);
    }
    out.flush();
}

/**
 * Builds the priority queue that holds the start and end points of all intervals.
 */
private static PriorityQueue<Point> buildQueue(FastScanner scanner, int N) {
    PriorityQueue<Point> queue = new PriorityQueue<>();
    for (int i = 0; i < N; i++) {
        queue.offer(new Point(scanner.nextInt(), true, i));   // start point
        queue.offer(new Point(scanner.nextInt(), false, i));  // end point
    }
    return queue;
}

/**
 * Processes the queue to assign groups (1 or 2) to each interval.
 * Returns both the assignment array and the final assign flag.
 */
private static ProcessResult processQueue(PriorityQueue<Point> queue, int N) {
    int cur = 0;                 // number of currently open intervals
    int assign = 1;              // 1 = all intervals in one group, 2 = split required
    int[] outArr = new int[N];   // assignment per original interval

    while (!queue.isEmpty()) {
        Point next = queue.poll();
        if (next.start) {
            cur++;
            outArr[next.num] = assign;
        } else {
            cur--;
        }
        if (cur == 0 && !queue.isEmpty()) {
            assign = 2;           // we have closed a component, need a second group
        }
    }
    return new ProcessResult(outArr, assign);
}

/**
 * Prints the result for a single test case.
 */
private static void outputResult(PrintWriter out, int[] outArr, int assign) {
    if (assign == 1) {
        out.println(-1);
    } else {
        for (int i = 0; i < outArr.length; i++) {
            if (i > 0) out.print(' ');
            out.print(outArr[i]);
        }
        out.println();
    }
}

/**
 * Simple holder for the processing outcome.
 */
private static class ProcessResult {
    final int[] outArr;
    final int assign;

    ProcessResult(int[] outArr, int assign) {
        this.outArr = outArr;
        this.assign = assign;
    }
}

