        ans = Math.max(ans, readSpanArea(sc, (long) h));

        // third segment (horizontal, keep the larger area)
        ans = Math.max(ans, readSpanArea(sc, (long) w));

        // fourth segment (horizontal, keep the larger area)
        ans = Math.max(ans, readSpanArea(sc, (long) w));

