    }
}

/**
 * Reads a sequence of positions from the scanner, extracts the first and last
 * values, and returns the span multiplied by the given factor.
 *
 * @param sc     the scanner positioned at the start of the data block
 * @param factor the multiplier (width or height) to produce the area
 * @return the computed area for this block
 */
private static long readSpanArea(Scanner sc, long factor) {
    int k = sc.nextInt();          // number of points in this block
    long first = 0L;
    long last = 0L;
    for (int i = 0; i < k; i++) {
        long x = sc.nextLong();
        if (i == 0) {
            first = x;
        }
        if (i == k - 1) {
            last = x;
        }
    }
    return (last - first) * factor;
}

