        long ans = computeArea(sc, h);                 // first segment (vertical)
        ans = Math.max(ans, computeArea(sc, h));       // second segment (vertical)
        ans = Math.max(ans, computeArea(sc, w));       // third segment (horizontal)
        ans = Math.max(ans, computeArea(sc, w));       // fourth segment (horizontal)

        System.out.println(ans);
