}

/**
 * Reads a sequence of coordinates from the scanner, extracts the first and last
 * values, and returns the area obtained by multiplying the span with the given factor.
 *
 * The input format for a segment is:
 *   int k          – number of coordinates
 *   long x1 x2 ... xk
 *
 * @param sc     scanner positioned at the start of the segment
 * @param factor multiplier (either width or height)
 * @return the computed area for this segment
 */
private static long computeArea(Scanner sc, long factor) {
    int k = sc.nextInt();
    long first = sc.nextLong();   // i == 0
    long last = first;            // will be overwritten when i == k-1

    for (int i = 1; i < k; i++) {
        long x = sc.nextLong();
        if (i == k - 1) {
            last = x;
        }
    }
    return (last - first) * factor;
}

public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int t = sc.nextInt();

    for (int caseIdx = 0; caseIdx < t; caseIdx++) {
        int w = sc.nextInt();
        int h = sc.nextInt();

        long ans = 0L;

        // first list – uses height as factor
        ans = updateAnswer(sc, ans, h);
        // second list – also uses height as factor
        ans = updateAnswer(sc, ans, h);
        // third list – uses width as factor
        ans = updateAnswer(sc, ans, w);
        // fourth list – also uses width as factor
        ans = updateAnswer(sc, ans, w);

        System.out.println(ans);
    }
}

/**
 * Reads a sequence of {@code k} positions, extracts the first and last values,
 * computes the product of their distance with the given {@code factor},
 * and returns the maximum between the current {@code currentAns} and the new product.
 *
 * @param sc          scanner positioned at the integer {@code k} followed by {@code k} longs
 * @param currentAns  the answer computed so far
 * @param factor      the multiplier (either {@code w} or {@code h})
 * @return the updated answer
 */
private static long updateAnswer(Scanner sc, long currentAns, long factor) {
    int k = sc.nextInt();
    long first = 0L;
    long last = 0L;
    for (int i = 0; i < k; i++) {
        long x = sc.nextLong();
        if (i == 0) {
            first = x;
        }
        if (i == k - 1) {
            last = x;
        }
    }
    long candidate = (last - first) * factor;
    return Math.max(currentAns, candidate);
}

