/* --------------------------------------------------------------------- *
 *  Helper that fills the `precomp` matrix.                              *
 *  The original nested loops are moved here, keeping the same logic.     *
 * --------------------------------------------------------------------- */
private void fillPrecomputation(FastReader scan) {
    for (int at = 0; at < n; at++) {
        char[] digits = scan.next().toCharArray();
        computePrecompRow(at, digits);
    }
}

/* --------------------------------------------------------------------- *
 *  Computes one row of the `precomp` matrix for the given digit string. *
 * --------------------------------------------------------------------- */
private void computePrecompRow(int row, char[] digits) {
    outer:
    for (int j = 0; j <= 9; j++) {
        int diffCount = 0;
        for (int pos = 0; pos < 7; pos++) {
            if (digits[pos] == '1' && s[j].charAt(pos) == '0') {
                precomp[row][j] = -1;
                continue outer;
            }
            if (digits[pos] == '0' && s[j].charAt(pos) == '1') {
                diffCount++;
            }
        }
        precomp[row][j] = diffCount;
    }
}

