/** builds the board with a one‑cell '.' border and prepares the distance matrix */
private static void initialiseBoard(FS in) {
    b = new char[R + 2][C + 2];
    for (char[] row : b) {
        Arrays.fill(row, '.');
    }

    for (int i = 1; i <= R; i++) {
        char[] line = in.next().toCharArray();
        for (int j = 1; j <= C; j++) {
            b[i][j] = line[j - 1];
        }
    }

    // add the border to the dimensions
    R += 2;
    C += 2;

    box = new int[R][C];
    for (int[] row : box) {
        Arrays.fill(row, -1);
    }
}

/** multi‑source BFS that fills {@code box} with distances and remembers the maximum */
private static void computeDistances() {
    int max = -1;
    ArrayDeque<Pair> q = new ArrayDeque<>();

    // start BFS from every '.' cell (including the added border)
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (b[i][j] == '.') {
                q.add(new Pair(i, j));
                box[i][j] = 0;
            }
        }
    }

    // BFS
    while (!q.isEmpty()) {
        Pair p = q.poll();
        max = Math.max(max, box[p.r][p.c]);

        for (int k = 0; k < dr.length; k++) {
            int nr = p.r + dr[k];
            int nc = p.c + dc[k];
            if (!valid(nr, nc) || box[nr][nc] != -1) {
                continue;
            }
            box[nr][nc] = box[p.r][p.c] + 1;
            q.add(new Pair(nr, nc));
        }
    }

    // store for the binary search step
    maxDist = max;
}

/** binary search over possible radii using the existing {@code works} predicate */
private static int findBestRadius() {
    int lo = 0, hi = maxDist;
    int best = -1;

    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (works(mid)) {
            best = Math.max(best, mid);
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return best;
}

