public static void main(String[] args) {
    FS in = new FS();
    readDimensions(in);
    initialiseBoard(in);
    int maxDistance = calculateDistances();
    int best = binarySearchBest(maxDistance);
    if (debug) {
        printDebugGrid();
    }
    outputResult(best);
}

/* --------- Input & board initialisation --------- */
private static void readDimensions(FS in) {
    R = in.nextInt();
    C = in.nextInt();
}

private static void initialiseBoard(FS in) {
    // board with a one‑cell padding on each side
    b = new char[R + 2][C + 2];
    for (char[] row : b) {
        Arrays.fill(row, '.');
    }

    // copy the actual input into the padded board
    for (int i = 1; i <= R; i++) {
        char[] line = in.next().toCharArray();
        for (int j = 1; j <= C; j++) {
            b[i][j] = line[j - 1];
        }
    }

    // adjust dimensions to include the padding
    R += 2;
    C += 2;

    // distance array, initialised to “unvisited”
    box = new int[R][C];
    for (int[] row : box) {
        Arrays.fill(row, -1);
    }
}

/* --------- Breadth‑first search for distances --------- */
private static int calculateDistances() {
    int max = -1;
    ArrayDeque<Pair> q = new ArrayDeque<>();

    // start BFS from every '.' cell on the padded border
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (b[i][j] == '.') {
                q.add(new Pair(i, j));
                box[i][j] = 0;
            }
        }
    }

    while (!q.isEmpty()) {
        Pair p = q.poll();
        max = Math.max(max, box[p.r][p.c]);

        for (int k = 0; k < dr.length; k++) {
            int nr = p.r + dr[k];
            int nc = p.c + dc[k];
            if (!valid(nr, nc) || box[nr][nc] != -1) {
                continue;
            }
            box[nr][nc] = box[p.r][p.c] + 1;
            q.add(new Pair(nr, nc));
        }
    }
    return max;
}

/* --------- Binary search for the maximal feasible distance --------- */
private static int binarySearchBest(int maxDistance) {
    int lo = 0, hi = maxDistance;
    int best = -1;

    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (works(mid)) {
            best = Math.max(best, mid);
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return best;
}

/* --------- Debug printing (optional) --------- */
private static void printDebugGrid() {
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            System.out.print(box[i][j]);
        }
        System.out.println();
    }
}

/* --------- Final output --------- */
private static void outputResult(int best) {
    out.println(best);
    for (int i = 1; i < R - 1; i++) {
        for (int j = 1; j < C - 1; j++) {
            out.print(box[i][j] > best ? 'X' : '.');
        }
        out.println();
    }
    out.close();
}

