/* ---------- Helper methods ---------- */

private static void readInput(FastScanner sc, int m, int[] a, int[] b, int[] q) {
    for (int i = 0; i < m; i++) {
        a[i] = sc.nextInt() - 1;
        b[i] = sc.nextInt() - 1;
        q[i] = sc.nextInt();
    }
}

/**
 * Constructs the “OR” segment tree and applies all constraints.
 */
private static RangeTree buildOrTree(int n, int m, int[] a, int[] b, int[] q) {
    RangeTree or = new RangeTree(n, 0);
    for (int i = 0; i < m; i++) {
        or.update(a[i], b[i], q[i], 0);
    }
    return or;
}

/**
 * Constructs the “AND” segment tree using the values stored in the OR tree.
 */
private static RangeTree buildAndTree(int n, RangeTree or, int[] a, int[] b) {
    RangeTree and = new RangeTree(n, 1);
    for (int i = 0; i < n; i++) {
        long value = or.query(i, i, 0);
        and.update(i, i, value, 1);
    }
    // propagate the initially stored values for the pairs (a[i], b[i])
    for (int i = 0; i < a.length; i++) {
        long segment = and.query(a[i], b[i], 1);
        // No side‑effect needed here; the loop simply mirrors the original
        // validation step, which is performed later in {@link #validateConstraints}.
    }
    return and;
}

/**
 * Checks whether every original constraint is satisfied by the AND tree.
 *
 * @return {@code true} if any constraint mismatches (i.e., the whole answer is “NO”).
 */
private static boolean validateConstraints(int m, int[] a, int[] b, int[] q, RangeTree and) {
    for (int i = 0; i < m; i++) {
        long aux = and.query(a[i], b[i], 1);
        if (aux != q[i]) {
            return true;            // fail detected
        }
    }
    return false;                   // no failures
}

/**
 * Prints either “YES” followed by the constructed array or “NO”.
 */
private static void printResult(boolean fail, RangeTree or, int n, PrintWriter out) {
    if (!fail) {
        out.println("YES");
        out.print(or.query(0, 0, 0));
        for (int i = 1; i < n; i++) {
            out.print(' ');
            out.print(or.query(i, i, 0));
        }
        out.println();
    } else {
        out.println("NO");
    }
}

