/* -------------------------------------------------------------------- */
/* Helper that reads the m (first,second) string pairs and fills the     */
/* auxiliary arrays.                                                    */
private static void readPairs(Scanner s, int m,
                              String[] first,
                              String[] second,
                              int[] temp) {
    for (int i = 0; i < m; i++) {
        String a = s.next();
        first[i] = a;
        String b = s.next();
        second[i] = b;
        temp[i] = (a.length() <= b.length()) ? 1 : 0;
    }
}

/* -------------------------------------------------------------------- */
/* Consumes the rest of the input and returns the final line split into */
/* words.                                                               */
private static String[] readRemainingWords(Scanner s) {
    String lastLine = "";
    while (s.hasNext()) {
        lastLine = s.nextLine();
    }
    return lastLine.split(" ");
}

/* -------------------------------------------------------------------- */
/* Performs the replacement logic that originally lived inside the two  */
/* nested loops. It returns the (possibly) transformed word. If the word*/
/* matches the second array (arr1) the original code printed             */
/* `ans[i]` (which is null). To keep identical behaviour we print a null*/
/* reference here as well.                                              */
private static String replaceWord(String word,
                                  String[] arr,
                                  String[] arr1,
                                  int[] temp,
                                  String[] ans,
                                  int index) {
    // first attempt: match against the first array
    for (int j = 0; j < arr.length; j++) {
        if (word.equals(arr[j])) {
            return (temp[j] == 1) ? arr[j] : arr1[j];
        }
    }

    // second attempt: match against the second array
    for (int j = 0; j < arr1.length; j++) {
        if (word.equals(arr1[j])) {
            // original code printed ans[i]; ans[i] is always null
            System.out.println((String) null);
            return (temp[j] == 1) ? arr[j] : arr1[j];
        }
    }

    // no match found – return the original word
    return word;
}

