/*--- helper methods ---------------------------------------------------*/

private static long[] computePowers(int n) {
    long[] p = new long[n + 1];
    p[0] = 1L;
    for (int i = 1; i <= n; i++) {
        p[i] = p[i - 1] * 13L;
    }
    return p;
}

private static long[] computeHashes(String s, long[] p) {
    int n = s.length();
    long[] h = new long[n];
    h[0] = s.charAt(0) - '0' + 1;
    for (int i = 1; i < n; i++) {
        h[i] = h[i - 1] + (s.charAt(i) - '0' + 1) * p[i];
    }
    return h;
}

/**
 * Computes the index {@code i} required by the DP transition.
 * The logic corresponds to the original nested block that performed
 * a binary search on hash values and possibly incremented {@code i}.
 */
private static int computeNextIndex(String s, long[] h, long[] p, int j, int k) {
    int i = 2 * j - k;
    if (i < 0) {
        return 0;
    }

    int hi = k - j;
    int lo = -1;
    while (lo + 1 < hi) {
        int mid = (lo + hi) >>> 1;

        long h1 = h[i + mid] - (i > 0 ? h[i - 1] : 0);
        long h2 = h[j + mid] - (j > 0 ? h[j - 1] : 0);

        if (h1 * p[j - i] == h2) {
            lo = mid;
        } else {
            hi = mid;
        }
    }

    if (hi == k - j || s.charAt(i + hi) >= s.charAt(j + hi)) {
        i++;
    }
    return i;
}

