    // 1️⃣ convert the input number to base‑3 (least‑significant digit first)
    List<BigInteger> digits = toBase3(n);

    // keep a copy of the original representation for later comparison
    List<BigInteger> originalDigits = new ArrayList<>(digits);
    int originalSize = digits.size();

    // 2️⃣ normalise the digit list (handle carries, turn “2” into “0+1” etc.)
    normaliseDigits(digits);

    // 3️⃣ after normalisation, possibly truncate lower‑order digits
    postProcessDigits(digits, originalDigits, originalSize);

    // 4️⃣ finally, compute the answer (sum of 3^i for every digit equal to 1)
    return computeResult(digits);
}

/* --------------------------------------------------------------------- *
 *  Helper methods – each one encapsulates a cohesive piece of the logic *
 * --------------------------------------------------------------------- */

/** Convert a non‑negative integer to a list of its base‑3 digits
 *  (least‑significant digit first). */
private static List<BigInteger> toBase3(BigInteger value) {
    List<BigInteger> list = new ArrayList<>();
    BigInteger three = BigInteger.valueOf(3);

    BigInteger tp = value;
    while (!tp.equals(BigInteger.ZERO)) {
        list.add(tp.mod(three));
        tp = tp.divide(three);
    }
    return list;
}

/** Perform the carry‑propagation and the “2 → 0 + 1” transformation
 *  that the original code performed inside the first for‑loop. */
private static void normaliseDigits(List<BigInteger> list) {
    BigInteger three = BigInteger.valueOf(3);
    BigInteger two   = BigInteger.valueOf(2);

    for (int i = 0; i < list.size(); i++) {
        BigInteger digit = list.get(i);

        // propagate any digit that became ≥3 (result of a previous carry)
        BigInteger overflow = digit.divide(three);
        if (overflow.compareTo(BigInteger.ZERO) > 0) {
            BigInteger remainder = digit.mod(three);
            if (i == list.size() - 1) {
                list.add(BigInteger.ZERO);
            }
            // add the overflow (digit‑3) to the next position
            list.set(i + 1, list.get(i + 1).add(digit.subtract(two)));
            list.set(i, remainder);
            digit = remainder;                 // keep the updated value for the next test
        }

        // turn a “2” into “0” and carry a “1” to the next digit
        if (digit.equals(two)) {
            if (i == list.size() - 1) {
                list.add(BigInteger.ZERO);
            }
            list.set(i + 1, list.get(i + 1).add(BigInteger.ONE));
            list.set(i, BigInteger.ZERO);
        }
    }
}

/** After normalisation, either truncate the lower‑order digits
 *  (when the list grew) or zero‑out everything up to the first change
 *  when the list kept its original size. */
private static void postProcessDigits(List<BigInteger> list,
                                      List<BigInteger> original,
                                      int originalSize) {
    // case 1 – the list grew (a new most‑significant digit was added)
    if (list.size() > originalSize) {
        for (int i = list.size() - 2; i >= 0; i--) {
            list.set(i, BigInteger.ZERO);
        }
        return;
    }

    // case 2 – the size stayed the same; compare with the original digits
    for (int i = list.size() - 2; i >= 0; i--) {
        BigInteger current = list.get(i);
        BigInteger before  = original.get(i);
        if (!current.equals(before)) {
            // zero out all less‑significant positions
            for (int j = i - 1; j >= 0; j--) {
                list.set(j, BigInteger.ZERO);
            }
            break;
        }
    }
}

/** Compute Σ 3^i for each position i whose digit equals 1. */
private static BigInteger computeResult(List<BigInteger> list) {
    BigInteger ans = BigInteger.ZERO;
    BigInteger three = BigInteger.valueOf(3);

    for (int i = 0; i < list.size(); i++) {
        if (list.get(i).equals(BigInteger.ONE)) {
            ans = ans.add(three.pow(i));
        }
    }
    return ans;
}

