public void solve(int testNumber, Scanner in, PrintWriter out) {
    int n = in.nextInt();
    int m = in.nextInt();

    int[] arr = buildAdjustedArray(n, in);
    UnchangeResult uc = readUnchangable(m, in, arr);
    int[] unchangable = uc.unchangable;
    boolean monotonic = uc.monotonic;

    int ans = computeChanges(arr, unchangable);
    out.println(monotonic ? ans : -1);
}

/* --------------------------------------------------------------------- */
/* Helper data structure for the result of reading the “unchangable” list */
private static class UnchangeResult {
    final int[] unchangable;
    final boolean monotonic;

    UnchangeResult(int[] unchangable, boolean monotonic) {
        this.unchangable = unchangable;
        this.monotonic = monotonic;
    }
}

/* --------------------------------------------------------------------- */
/* 1️⃣ Build the transformed array `arr` (original value minus its index) */
private int[] buildAdjustedArray(int n, Scanner in) {
    int[] arr = new int[n + 2];
    arr[0] = -(int) 1e9;                     // sentinel: very small
    arr[n + 1] = (int) 1e9 - n - 1;          // sentinel: very large
    for (int i = 1; i <= n; i++) {
        arr[i] = in.nextInt() - i;
    }
    return arr;
}

/* --------------------------------------------------------------------- */
/* 2️⃣ Read the fixed positions, store sentinels and check monotonicity */
private UnchangeResult readUnchangable(int m, Scanner in, int[] arr) {
    int[] unchangable = new int[m + 2];
    unchangable[0] = 0;
    unchangable[m + 1] = arr.length - 2; // n + 1

    boolean monotonic = true;
    for (int i = 1; i <= m; i++) {
        unchangable[i] = in.nextInt();
        monotonic &= arr[unchangable[i]] >= arr[unchangable[i - 1]];
    }
    return new UnchangeResult(unchangable, monotonic);
}

/* --------------------------------------------------------------------- */
/* 3️⃣ Compute the minimum number of changes needed */
private int computeChanges(int[] arr, int[] unchangable) {
    int ans = 0;
    for (int i = 0; i < unchangable.length - 1; i++) {
        int left = unchangable[i];
        int right = unchangable[i + 1];
        int lisLength = longestIncreasingSubsequenceWithinBounds(arr, left, right);
        ans += (right - left - 1) - lisLength;
    }
    return ans;
}

/* --------------------------------------------------------------------- */
/* 4️⃣ Find the length of the longest non‑decreasing subsequence of the
   segment (left, right) that stays inside the allowed value range. */
private int longestIncreasingSubsequenceWithinBounds(int[] arr, int left, int right) {
    ArrayList<Integer> tails = new ArrayList<>();
    for (int j = left + 1; j < right; j++) {
        int val = arr[j];
        if (arr[left] <= val && val <= arr[right]) {
            if (tails.isEmpty()) {
                tails.add(val);
            } else {
                int idx = bs(tails, val);
                if (idx + 1 == tails.size()) {
                    tails.add(val);
                } else {
                    tails.set(idx + 1, val);
                }
            }
        }
    }
    return tails.size();
}

/* --------------------------------------------------------------------- */
/* Binary search used by the LIS construction:
   returns the index of the greatest element < value (or -1 if none). */
private int bs(ArrayList<Integer> list, int value) {
    int lo = 0, hi = list.size() - 1;
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1;
        if (list.get(mid) < value) {
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return hi;
}

public void solve(int testNumber, Scanner in, PrintWriter out) {
    int n = in.nextInt();
    int m = in.nextInt();

    int[] arr = buildAdjustedArray(in, n);
    int[] unchangable = readUnchangable(in, m, n);

    boolean monotonic = checkMonotonic(arr, unchangable);
    int changesNeeded = computeChanges(arr, unchangable);

    out.println(monotonic ? changesNeeded : -1);
}

/* -------------------------------------------------------------------- */
/* Helper that builds the array “arr” with the required sentinels.       */
/* Each input value is shifted by its (1‑based) index as in the original.*/
/* -------------------------------------------------------------------- */
private int[] buildAdjustedArray(Scanner in, int n) {
    int[] arr = new int[n + 2];
    arr[0] = -(int) 1e9;                     // very small sentinel
    arr[n + 1] = (int) 1e9 - n - 1;          // very large sentinel
    for (int i = 1; i <= n; i++) {
        arr[i] = in.nextInt() - i;          // original transformation
    }
    return arr;
}

/* -------------------------------------------------------------------- */
/* Reads the “unchangable” positions and adds the two artificial ends.*/
/* -------------------------------------------------------------------- */
private int[] readUnchangable(Scanner in, int m, int n) {
    int[] unchangable = new int[m + 2];
    unchangable[0] = 0;
    unchangable[m + 1] = n + 1;
    for (int i = 1; i <= m; i++) {
        unchangable[i] = in.nextInt();
    }
    return unchangable;
}

/* -------------------------------------------------------------------- */
/* Verifies that the values at the un‑changeable indices are non‑decreasing.*/
/* -------------------------------------------------------------------- */
private boolean checkMonotonic(int[] arr, int[] unchangable) {
    boolean ok = true;
    for (int i = 1; i < unchangable.length - 1; i++) {
        ok &= arr[unchangable[i]] >= arr[unchangable[i - 1]];
    }
    return ok;
}

/* -------------------------------------------------------------------- */
/* Main driver that computes the total number of required changes.      */
/* -------------------------------------------------------------------- */
private int computeChanges(int[] arr, int[] unchangable) {
    int ans = 0;
    for (int i = 0; i < unchangable.length - 1; i++) {
        int leftIdx  = unchangable[i];
        int rightIdx = unchangable[i + 1];

        int longest = longestValidSubsequenceLength(arr, leftIdx, rightIdx);
        // elements that are not part of the longest subsequence must be changed
        ans += (rightIdx - leftIdx - 1) - longest;
    }
    return ans;
}

/* -------------------------------------------------------------------- */
/* Returns the length of the longest non‑decreasing subsequence of       */
/* arr[j] (leftIdx < j < rightIdx) that stays inside the inclusive       */
/* bounds [arr[leftIdx], arr[rightIdx]].                               */
/* -------------------------------------------------------------------- */
private int longestValidSubsequenceLength(int[] arr, int leftIdx, int rightIdx) {
    ArrayList<Integer> list = new ArrayList<>();
    int lower = arr[leftIdx];
    int upper = arr[rightIdx];

    for (int j = leftIdx + 1; j < rightIdx; j++) {
        int value = arr[j];
        if (value < lower || value > upper) {
            continue;                       // outside allowed range
        }

        if (list.isEmpty()) {
            list.add(value);
        } else {
            int pos = bs(list, value);
            // pos is the index of the greatest element <= value
            // we want to place value after that element
            if (pos + 1 == list.size()) {
                list.add(value);
            } else {
                list.set(pos + 1, value);
            }
        }
    }
    return list.size();
}

/* -------------------------------------------------------------------- */
/* Binary‑search helper used by the LIS‑like routine.                    */
/* Returns the index of the greatest element <= key.                    */
/* -------------------------------------------------------------------- */
private int bs(ArrayList<Integer> list, int key) {
    int lo = 0, hi = list.size() - 1, ans = -1;
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1;
        if (list.get(mid) <= key) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
}

