/* ---------- helper methods ---------- */

private static int[] readArray(BufferedReader br, int n) throws IOException {
    StringTokenizer st = new StringTokenizer(br.readLine());
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = Integer.parseInt(st.nextToken());
    }
