}

private static Integer[] createIndexArray(int n) {
    Integer[] idx = new Integer[n];
    for (int i = 0; i < n; i++) {
        idx[i] = i;
    }
    return idx;
}

private static void sortByValueAndIndex(Integer[] idx, int[] values) {
    Arrays.sort(idx, (i, j) -> values[i] != values[j] ? values[i] - values[j] : i - j);
}

/* builds pp – previous index with a *different* value in the sorted order */
private static int[] buildPrevSameValue(Integer[] sortedIdx, int[] values) {
    int n = values.length;
    int[] prev = new int[n];
    for (int i = 0, j; i < n; i = j) {
        j = i + 1;
        while (j < n && values[sortedIdx[j]] == values[sortedIdx[i]]) {
            j++;
        }
        int p = -1;
        for (int h = i; h < j; h++) {
            prev[sortedIdx[h]] = p;
            p = sortedIdx[h];
        }
    }
    return prev;
}

/* builds bb – for each position and each bit, the nearest previous index
   where that bit is set (or -1 if none) */
private static int[][] buildPrevBitIndices(int[] values) {
    int n = values.length;
    int[][] prevBits = new int[n][K];
    for (int h = 0; h < K; h++) {
        int last = -1;
        for (int i = 0; i < n; i++) {
            prevBits[i][h] = last;
            if ((values[i] & (1 << h)) != 0) {
                last = i;
            }
        }
    }
    return prevBits;
}

/* builds dd – for each position and each bit, the nearest next index
   where that bit is set (or n if none) */
private static int[][] buildNextBitIndices(int[] values) {
    int n = values.length;
    int[][] nextBits = new int[n][K];
    for (int h = 0; h < K; h++) {
        int next = n;
        for (int i = n - 1; i >= 0; i--) {
            nextBits[i][h] = next;
            if ((values[i] & (1 << h)) != 0) {
                next = i;
            }
        }
    }
    return nextBits;
}

/* dp[i] = max previous index (to the left of i) that shares a zero‑bit
   with aa[i] */
private static int[] buildLeftLimits(int[] values, int[][] prevBits) {
    int n = values.length;
    int[] left = new int[n];
    for (int i = 0; i < n; i++) {
        int best = -1;
        for (int h = 0; h < K; h++) {
            if ((values[i] & (1 << h)) == 0) {
                best = Math.max(best, prevBits[i][h]);
            }
        }
        left[i] = best;
    }
    return left;
}

/* dq[i] = min next index (to the right of i) that shares a zero‑bit
   with aa[i] */
private static int[] buildRightLimits(int[] values, int[][] nextBits) {
    int n = values.length;
    int[] right = new int[n];
    for (int i = n - 1; i >= 0; i--) {
        int best = n;
        for (int h = 0; h < K; h++) {
            if ((values[i] & (1 << h)) == 0) {
                best = Math.min(best, nextBits[i][h]);
            }
        }
        right[i] = best;
    }
    return right;
}

/* final aggregation step */
private static long computeAnswer(int n, int[] dp, int[] pp, int[] dq) {
    long total = (long) n * (n + 1) / 2; // total number of sub‑arrays
    for (int i = 0; i < n; i++) {
        int leftBound = Math.max(dp[i], pp[i]);
        long leftChoices = i - leftBound;
        long rightChoices = dq[i] - i;
        total -= leftChoices * rightChoices;
    }
    return total;
}

