/**
 * Returns the length of the shortest contiguous sub‑array whose
 * cumulative GCD becomes {@code 1}. If no such sub‑array exists,
 * returns {@code -1}. If a sub‑array of length {@code 0} (i.e. an
 * element equal to {@code 1}) is found, returns {@code 0}.
 */
private static int findShortestSubarrayWithGcdOne(int[] input) {
    int n = input.length;
    int min = -1;
    int i = 0;

    while (i < n && min != 0) {
        int nod = input[i];
        int j = i;

        while (j + 1 < n && nod != 1) {
            j++;
            nod = gcd(nod, input[j]);
        }

        if (nod == 1) {
            int length = j - i;
            if (min == -1) {
                min = length;
            } else {
                min = Math.min(min, length);
            }
        }
        i++;
    }
    return min;
}

