    }

    // then, try to match or skip characters of the word "hard"
    for (int p = 0; p < 4; p++) {
        if (s.charAt(j) == hard.charAt(p)) {
            dp[j][p] = min(dp[j][p], dp[j + 1][p + 1]);
        } else {
            dp[j][p] = min(dp[j][p], dp[j + 1][p]);
        }
    }
