private void handleRangeQuery(SegmentTree tree1, SegmentTree tree2, long[] fib) throws IOException {
    int l = nextInt() - 1;
    int r = nextInt() - 1;

    // special case when the left bound is 0 – tree2 already contains the correct value
    if (l == 0) {
