public void solve(int testNumber, InputReader in, OutputWriter out) {
    int n = in.nextInt();
    int m = in.nextInt();
    k = in.nextInt();                     // k is assumed to be a field of the class

    IntList[] adj = new IntList[n];
    int[] result = new int[m];
    int[] degree = new int[n];
    for (int i = 0; i < n; i++) {
        adj[i] = new IntList(3);
    }

    int[] u = new int[m];
    int[] v = new int[m];

    // -------- build the undirected edge list ----------
    for (int i = 0; i < m; ++i) {
        u[i] = in.nextInt() - 1;
        v[i] = in.nextInt() - 1;

        adj[u[i]].add(i);
        adj[v[i]].add(i);
        degree[u[i]]++;
        degree[v[i]]++;
    }

    IntList que = new IntList(n);
    boolean[] alive = ArrayUtils.createArray(m, true);
    int[] head = new int[]{0};   // mutable holder for the queue head

    // -------- initialise queue with vertices whose degree < k ----------
    for (int i = 0; i < n; ++i) {
        if (degree[i] < k) {
            que.add(i);
        }
    }

    // -------- process days in reverse order ----------
    for (int day = m - 1; day >= 0; --day) {
        // remove all vertices that have become invalid before handling the current edge
        processQueue(que, degree, alive, adj, u, v, head);

        // record answer for this day
        result[day] = n - que.size();

        // finally, try to delete the edge belonging to this day
        handleCurrentEdge(day, u, v, degree, alive, que);
    }

    for (int e : result) {
        out.println(e);
    }
}

/**
 * Removes vertices from the graph whose degree fell below {@code k}.
 * The method processes the queue until no more vertices are left to handle.
 */
private void processQueue(IntList que,
                          int[] degree,
                          boolean[] alive,
                          IntList[] adj,
                          int[] u,
                          int[] v,
                          int[] head) {
    while (head[0] < que.size()) {
        int id = que.get(head[0]);

        for (int edgeId : adj[id]) {
            if (!alive[edgeId]) {
                continue;
            }

            int other = (u[edgeId] == id) ? v[edgeId] : u[edgeId];

            // if the neighbour will drop from exactly k to k‑1, it becomes a candidate for removal
            if (degree[other] == k) {
                que.add(other);
            }

            degree[other]--;
            degree[id]--;
            alive[edgeId] = false;
        }
        head[0]++;   // move to next queued vertex
    }
}

/**
 * Handles the deletion of the edge that corresponds to the current day.
 * If the edge is still alive it may cause its incident vertices to become
 * low‑degree and therefore they are added to the removal queue.
 */
private void handleCurrentEdge(int day,
                               int[] u,
                               int[] v,
                               int[] degree,
                               boolean[] alive,
                               IntList que) {
    if (!alive[day]) {
        return;
    }

    if (degree[u[day]] == k) {
        que.add(u[day]);
    }
    if (degree[v[day]] == k) {
        que.add(v[day]);
    }

    degree[u[day]]--;
    degree[v[day]]--;
    alive[day] = false;
}

