    for (int i = 0; i < rows; i++) {
        grid[i] = in.next();
    }
    return grid;
}

/* For every row that does **not** contain an 'S', set all cells in that row to 1. */
private static void markRowsWithoutS(String[] grid, int[][] matrix, int rows, int cols) {
    for (int i = 0; i < rows; i++) {
        boolean hasS = false;
        for (int j = 0; j < cols; j++) {
            if (grid[i].charAt(j) == 'S') {
                hasS = true;
                break;
            }
        }
        if (!hasS) {
            for (int j = 0; j < cols; j++) {
                matrix[i][j] = 1;
            }
        }
    }
}

/* For every column that does **not** contain an 'S', set all cells in that column to 1. */
private static void markColumnsWithoutS(String[] grid, int[][] matrix, int rows, int cols) {
    for (int j = 0; j < cols; j++) {
        boolean hasS = false;
        for (int i = 0; i < rows; i++) {
            if (grid[i].charAt(j) == 'S') {
                hasS = true;
                break;
            }
        }
        if (!hasS) {
            for (int i = 0; i < rows; i++) {
                matrix[i][j] = 1;
            }
        }
    }
}

/* Counts the number of cells that were set to 1. */
private static int countMarkedCells(int[][] matrix, int rows, int cols) {
    int count = 0;
    for (int j = 0; j < cols; j++) {
        for (int i = 0; i < rows; i++) {
            if (matrix[i][j] == 1) {
                count++;
            }
        }
    }
    return count;
}

