            if (o1.val > o2.val) return 1;
            return 0;
        }
    });
    return p;
}

private long[][] computeDP(Pair[] p) {
    int n = p.length;
    long[][] dp = new long[n][3];
    for (int i = 0; i < n; ++i) {
        Arrays.fill(dp[i], Long.MAX_VALUE);
    }

    dp[0][0] = -p[0].val;
    for (int i = 1; i < n; ++i) {
        if (dp[i - 1][2] != Long.MAX_VALUE)
            dp[i][0] = dp[i - 1][2] - p[i].val + p[i - 1].val;
        if (dp[i - 1][0] != Long.MAX_VALUE)
            dp[i][1] = dp[i - 1][0];
        if (dp[i - 1][2] != Long.MAX_VALUE)
            dp[i][2] = dp[i - 1][2];
        if (dp[i - 1][1] != Long.MAX_VALUE && dp[i - 1][1] < dp[i][2]) {
            dp[i][2] = dp[i - 1][1];
        }
    }
    return dp;
}

/**
 * Reconstructs the team assignment by walking the DP table backwards.
 *
 * @return the total number of teams that were created.
 */
private int backtrackTeams(Pair[] p, long[][] dp, int[] teams) {
    int n = p.length;
    int members = 3;
    int curTeam = 1;
    for (int i = n - 1; i >= 0; --i) {
        teams[p[i].ind] = curTeam;

        if (i == 0) break;

        if (members == 3) {
            if (dp[i - 1][1] == dp[i][2])
                members = 2;
        } else if (members == 2) {
            members = 1;
        } else {
            curTeam++;
            members = 3;
        }
    }
    return curTeam;
}

