public void solve(int testNumber, InputReader sc, PrintWriter out) {
    int n = sc.nextInt();

    long[] a = new long[n];
    for (int i = 0; i < n; ++i) {
        a[i] = sc.nextLong();
    }

    Pair[] sortedPairs = createAndSortPairs(a);
    long[][] dp = initialiseDp(n, sortedPairs);
    computeDp(dp, sortedPairs);

    int[] teams = new int[n];
    int curTeam = reconstructTeams(sortedPairs, dp, teams);

    printResult(out, dp, sortedPairs, curTeam, teams);
}

/* ------- helper methods ------------------------------------------ */

private Pair[] createAndSortPairs(long[] values) {
    int n = values.length;
    Pair[] p = new Pair[n];
    for (int i = 0; i < n; ++i) {
        p[i] = new Pair(i, values[i]);
    }
    Arrays.sort(p, new Comparator<Pair>() {
        @Override
        public int compare(Pair o1, Pair o2) {
            if (o1.val < o2.val) return -1;
            if (o1.val > o2.val) return 1;
            return 0;
        }
    });
    return p;
}

private long[][] initialiseDp(int n, Pair[] p) {
    long[][] dp = new long[n][3];
    for (int i = 0; i < n; ++i) {
        Arrays.fill(dp[i], Long.MAX_VALUE);
    }
    dp[0][0] = -p[0].val;
    return dp;
}

private void computeDp(long[][] dp, Pair[] p) {
    int n = p.length;
    for (int i = 1; i < n; ++i) {
        if (dp[i - 1][2] != Long.MAX_VALUE) {
            dp[i][0] = dp[i - 1][2] - p[i].val + p[i - 1].val;
        }
        if (dp[i - 1][0] != Long.MAX_VALUE) {
            dp[i][1] = dp[i - 1][0];
        }
        if (dp[i - 1][2] != Long.MAX_VALUE) {
            dp[i][2] = dp[i - 1][2];
        }
        if (dp[i - 1][1] != Long.MAX_VALUE && dp[i - 1][1] < dp[i][2]) {
            dp[i][2] = dp[i - 1][1];
        }
    }
}

/**
 * Reconstructs the team assignment.
 *
 * @return the total number of teams used.
 */
private int reconstructTeams(Pair[] p, long[][] dp, int[] teams) {
    int n = p.length;
    int members = 3;
    int curTeam = 1;

    for (int i = n - 1; i >= 0; --i) {
        teams[p[i].ind] = curTeam;

        if (i == 0) {
            break;
        }

        if (members == 3) {
            if (dp[i - 1][1] == dp[i][2]) {
                members = 2;
            }
        } else if (members == 2) {
            members = 1;
        } else {
            curTeam++;
            members = 3;
        }
    }
    return curTeam;
}

private void printResult(PrintWriter out, long[][] dp, Pair[] p, int curTeam, int[] teams) {
    out.println((dp[p.length - 1][2] + p[p.length - 1].val) + " " + curTeam);
    for (int i = 0; i < teams.length; ++i) {
        out.print(teams[i] + " ");
    }
}

