/**
 * Constructs the binary‑lifting table used later for counting distinct
 * destinations after 2^20 moves.
 */
private int[][] buildBinaryLifting() {
    int[][] bin = new int[n * m][21];

    // level 0: direct next cell
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            bin[i * m + j][0] = next(i, j);
        }
    }

    // higher levels: 2^i jumps
    for (int i = 1; i < 21; i++) {
        for (int r = 0; r < n; r++) {
            for (int c = 0; c < m; c++) {
                int prev = bin[r * m + c][i - 1];
                bin[r * m + c][i] = bin[prev][i - 1];
            }
        }
    }
    return bin;
}

