/**
 * Tries to build the longest Fibonacci‑like sequence that starts with {@code first}
 * and {@code second}.  The method returns the length of the sequence (at least 2)
 * if this ordered pair has not been processed before; otherwise it returns 0.
 *
 * @param first   first element of the pair
 * @param second  second element of the pair
 * @param visited set that remembers which ordered pairs have already been examined
 * @param valz    map that stores how many times each value appears in the input
 * @param map     temporary map used to count how many times a value is used in the current sequence
 * @return length of the sequence built from this pair, or 0 if the pair was already visited
 */
private int exploreSequence(long first, long second,
                            HashSet<Long> visited,
                            IntHashMap valz,
                            IntHashMap map) {
    long key = first + 1_000_000_000L * second;   // unique identifier for the ordered pair
    if (visited.contains(key)) {
        return 0;
    }
    visited.add(key);

    map.clear();
    map.add(first);
    map.add(second);

    int length = 2;
    long x = first;
    long y = second;

    while (valz.keySet().contains(x + y) && map.get(x + y) < valz.get(x + y)) {
        long sum = x + y;
        map.add(sum);
        long prevY = y;
        y = sum;          // new second element
        x = prevY;        // old second becomes the new first
        length++;
    }
    return length;
}

