/**
 * Splits the input array into maximal contiguous segments of equal value.
 */
private List<Segment> buildSegments(int[] a) {
    List<Segment> segments = new ArrayList<>();
    for (int l = 0, r = 0; l < a.length; ) {
        while (r < a.length && a[r] == a[l]) {
            r++;
        }
        segments.add(new Segment(l, r, a[l], r - l));
        l = r;
    }
    return segments;
}

/**
 * Connects each segment with its predecessor and successor.
 */
private void linkSegments(List<Segment> segments) {
    int last = segments.size() - 1;
    segments.get(0).next = segments.get(1);
    segments.get(last).prev = segments.get(last - 1);
    for (int i = 1; i < last; i++) {
        Segment cur = segments.get(i);
        cur.prev = segments.get(i - 1);
        cur.next = segments.get(i + 1);
    }
}

/**
 * Inserts all segments into a TreeSet ordered by the custom comparator defined in Segment.
 */
private TreeSet<Segment> buildSet(List<Segment> segments) {
    TreeSet<Segment> set = new TreeSet<>();
    for (Segment seg : segments) {
        set.add(seg);
    }
    return set;
}

/**
 * Performs the main removal/merge simulation and returns the number of steps taken.
 */
private int computeAnswer(TreeSet<Segment> set) {
    int ans = 0;
    while (!set.isEmpty()) {
        ans++;
        Segment seg = set.pollFirst();

        // isolated segment – no neighbours left
        if (seg.prev == null && seg.next == null) {
            break;
        }

        // one‑sided removal
        if (seg.prev == null) {
            seg.next.prev = null;
            continue;
        }
        if (seg.next == null) {
            seg.prev.next = null;
            continue;
        }

        // both neighbours exist
        if (seg.prev.x != seg.next.x) {
            // simple unlinking
            seg.prev.next = seg.next;
            seg.next.prev = seg.prev;
        } else {
            // need to merge the two equal neighbours
            mergeNeighbours(seg, set);
        }
    }
    return ans;
}

/**
 * Merges the left and right neighbours of {@code seg} (which have the same value)
 * and updates the linked list and the TreeSet accordingly.
 */
private void mergeNeighbours(Segment seg, TreeSet<Segment> set) {
    Segment left = seg.prev.prev;
    Segment right = seg.next.next;

    // remove the two equal neighbours from the set
    set.remove(seg.prev);
    set.remove(seg.next);

    // create the merged segment
    Segment merged = new Segment(
            seg.prev.l,
            seg.next.r,
            seg.prev.x,
            seg.prev.sz + seg.next.sz
    );

    // reconnect the merged segment with the rest of the list
    merged.prev = left;
    if (left != null) {
        left.next = merged;
    }
    merged.next = right;
    if (right != null) {
        right.prev = merged;
    }

    // insert the new segment back into the set
    set.add(merged);
}

