/**
 * Traverses the matrix from bottom to top, invoking {@code moveUp}
 * for every non‑dot cell. The method short‑circuits as soon as a
 * failure is detected.
 *
 * @return {@code true} if all {@code moveUp} calls succeed,
 *         {@code false} otherwise.
 */
private static boolean processMatrix() {
    boolean ok = true;
    for (int i = N - 1; i >= 0 && ok; i--) {
        for (int j = 0; j < M && ok; j++) {
            if (mat[i][j] != '.') {
                ok &= moveUp(i, j);
            }
        }
    }
    return ok;
}

