/** Reads the input values and builds a map of their frequencies. */
private static Map<Long, Integer> readFrequencies(Scanner sc) {
    Map<Long, Integer> mp = new HashMap<>();
    int n = sc.nextInt();
    for (int i = 1; i <= n; i++) {
        long val = sc.nextInt();
        if (mp.get(val) == null) {
            mp.put(val, 1);
        } else {
            int oldV = mp.get(val);
            mp.replace(val, oldV, oldV + 1);
        }
    }
    return mp;
}

/** Copies the frequency values into the `problem` array and returns the count `N`. */
private static int fillProblemArray(Map<Long, Integer> mp, long[] problem) {
    int N = 0;
    for (int value : mp.values()) {
        problem[++N] = value;
    }
    return N;
}

/** Core algorithm that computes the required answer. */
private static long computeAnswer(long[] problem, int N) {
    Arrays.sort(problem, 1, N + 1);
    if (problem[N] == 1) {
        return 1;
    }

    long ans = -1;
    for (int i = 1; i <= problem[N]; i++) {
        ans = Math.max(ans, evaluateStartingValue(i, problem, N));
    }
    return ans;
}

/** Evaluates the inner logic for a particular starting value `i`. */
private static long evaluateStartingValue(int i, long[] problem, int N) {
    long tot = i;
    long lastT = i;
    long best = tot;
    boolean toBreak = false;

    for (int j = N - 1; j >= 1; j--) {
        if (lastT % 2 == 1) {
            best = Math.max(best, tot);
            toBreak = true;
        }
        if (toBreak) {
            break;
        }
        lastT /= 2;
        if (problem[j] < lastT) {
            best = Math.max(best, tot);
            break;
        }
        tot += lastT;
        best = Math.max(best, tot);
    }
    return best;
}

