public void solve(int testNumber, FastScanner in, PrintWriter out) {
    int n = in.ni(), m = in.ni();
    int[] p = in.na(n);

    // Build adjacency list and jump‑over information
    List<Integer>[] g = createAdjacencyList(n);
    int target = p[n - 1] - 1;
    boolean[] canJumpOver = new boolean[n];
    readEdges(m, in, g, canJumpOver, target);

    boolean[] blockers = new boolean[n];
    int nBlockers = 0;
    int ans = 0;

    for (int i = n - 2; i >= 0; i--) {
        int node = p[i] - 1;
        if (!canJumpOver[node]) {
            // this node can never be jumped over → it becomes a blocker
            blockers[node] = true;
            nBlockers++;
        } else {
            // node can be jumped over – decide whether it stays a blocker
            if (canIncreaseAnswer(node, g, blockers, nBlockers)) {
                ans++;
            } else {
                blockers[node] = true;
                nBlockers++;
            }
        }
    }
    out.println(ans);
}

/** Creates an adjacency list with an empty list for every vertex. */
private List<Integer>[] createAdjacencyList(int n) {
    @SuppressWarnings("unchecked")
    List<Integer>[] g = new List[n];
    for (int i = 0; i < n; i++) {
        g[i] = new LinkedList<>();
    }
    return g;
}

/** Reads the directed edges, fills the adjacency list and populates `canJumpOver`. */
private void readEdges(int m, FastScanner in, List<Integer>[] g,
                       boolean[] canJumpOver, int target) {
    for (int i = 0; i < m; i++) {
        int u = in.ni() - 1;
        int v = in.ni() - 1;
        g[u].add(v);
        if (v == target) {
            canJumpOver[u] = true;
        }
    }
}

/** Determines whether the current node makes the answer increase.
 *  The answer can be increased when every outgoing edge leads to a blocker. */
private boolean canIncreaseAnswer(int node, List<Integer>[] g,
                                  boolean[] blockers, int nBlockers) {
    int swaps = 0;
    for (int v : g[node]) {
        if (blockers[v]) {
            swaps++;
        }
    }
    return swaps == nBlockers;
}

