/* ---------- helper utilities ---------- */

private static long xorAll(long[] arr) {
    long res = 0L;
    for (long v : arr) {
        res ^= v;
    }
    return res;
}

/**
 * Holds the positions of bits that are set (setBits) and not set (unsetBits)
 * in the original xor value. Both arrays are ordered from most‑significant
 * to least‑significant bit, exactly like the original loops.
 */
private static class BitPartitions {
    final int[] setBits;   // corresponds to rm in the original code
    final int[] unsetBits; // corresponds to rs in the original code

    BitPartitions(int[] setBits, int[] unsetBits) {
        this.setBits = setBits;
        this.unsetBits = unsetBits;
    }
}

/**
 * Splits the bits of {@code x} into two arrays:
 *  – setBits  : indices where x has a 1
 *  – unsetBits: indices where x has a 0
 * The method mirrors the original for‑loop that filled {@code rm} and {@code rs}.
 */
private static BitPartitions partitionBits(long x) {
    int[] setBits = new int[Long.bitCount(x)];
    int[] unsetBits = new int[64 - setBits.length];

    int mi = 0, si = 0;
    for (int i = 63; i >= 0; i--) {
        if (BitUtil.test(x, i)) {
            setBits[mi++] = i;
        } else {
            unsetBits[si++] = i;
        }
    }
    return new BitPartitions(setBits, unsetBits);
}

/**
 * Returns a new array where each element of {@code src} has all bits
 * listed in {@code bitsToRemove} cleared (using {@code removeBit}).
 */
private static long[] stripSetBits(long[] src, int[] bitsToRemove) {
    long[] dst = new long[src.length];
    for (int i = 0; i < src.length; i++) {
        long v = src[i];
        for (int bit : bitsToRemove) {
            v = removeBit(v, bit);
        }
        dst[i] = v;
    }
    return dst;
}

/**
 * Constructs a linear basis (over GF(2)) from the array {@code values}.
 * The algorithm is identical to the original nested loops.
 */
private static List<Long> buildBasis(long[] values) {
    List<Long> basis = new ArrayList<>();
    for (long v : values) {
        for (long b : basis) {
            v = Math.min(v, v ^ b);
        }
        if (v != 0) {
            basis.add(v);
        }
    }
    // keep the original ordering (largest first) for the greedy step
    Collections.sort(basis, Collections.reverseOrder());
    return basis;
}

/**
 * Computes the maximum xor that can be obtained by xor‑ing any subset
 * of the given basis. This reproduces the greedy pass from the original code.
 */
private static long maxXorFromBasis(List<Long> basis) {
    long best = 0L;
    for (long v : basis) {
        best = Math.max(best, best ^ v);
    }
    return best;
}

/**
 * Translates the bits of {@code y} onto the positions stored in {@code rs}
 * (the original unset‑bit positions). The mapping follows the original
 * reverse‑order assignment.
 */
private static long mapYToH(long y, int[] rs) {
    long h = 0L;
    for (int i = 0; i < rs.length; i++) {
        if (BitUtil.test(y, i)) {
            h |= 1L << rs[rs.length - 1 - i];
        }
    }
    return h;
}

