/**
 * Constructs the dpLeft array:
 * dpLeft[i] holds the length of the longest prefix of {@code t}
 * that can be matched using characters s[0..i].
 */
private static int[] buildDpLeft(char[] s, char[] t) {
    int n = s.length;
    int m = t.length;
    int[] dpLeft = new int[n];
    int i = 0, j = 0, matched = 0;

    while (i < n && j < m) {
        if (s[i] == t[j]) {
            dpLeft[i++] = ++j;
            matched++;
        } else {
            dpLeft[i++] = matched;
        }
    }
    // Fill remaining positions, if any, with the last matched count
    while (i < n) {
        dpLeft[i++] = matched;
    }
    return dpLeft;
}

/**
 * Constructs the dpRight array:
 * dpRight[i] holds the length of the longest suffix of {@code t}
 * that can be matched using characters s[i..n‑1].
 */
private static int[] buildDpRight(char[] s, char[] t) {
    int n = s.length;
    int m = t.length;
    int[] dpRight = new int[n];
    int i = n - 1, j = m - 1, matched = 0;

    while (i >= 0 && j >= 0) {
        if (s[i] == t[j]) {
            dpRight[i--] = m - j;
            j--;
            matched++;
        } else {
            dpRight[i--] = matched;
        }
    }
    // Fill remaining positions, if any, with the last matched count
    while (i >= 0) {
        dpRight[i--] = matched;
    }
    return dpRight;
}

/**
 * Performs a binary search over possible lengths and uses {@code check}
 * to determine the greatest length that satisfies the condition.
 */
private static int findMaximumLength(int[] dpLeft, int[] dpRight, int tLength) {
    int low = 0;
    int high = dpLeft.length; // maximum possible length
    int best = 0;

    while (low <= high) {
        int mid = (low + high) / 2;
        if (check(dpLeft, dpRight, mid, tLength)) {
            best = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }
    return best;
}

