		boolean[] visited = new boolean[N];
		int ec = 0;
		int oc = 0;
		for (int i = 0; i < N; ++i) {
			if (visited[i]) continue;
			int count = 1;
			visited[i] = true;
			ArrayDeque<Integer> q = new ArrayDeque<Integer>();
			q.add(i);
			while (!q.isEmpty()) {
				int pos = q.poll();
				for (int j = 0; j < N; ++j) {
					if (!visited[j] && g[pos][j]) {
						++count;
						q.add(j);
						visited[j] = true;
					}
				}
			}
			if (count % 2 == 0) {
				++ec;
			} else {
				++oc;
			}
		}
		boolean taroEven = ((N * (N - 1)) / 2 - E) % 2 != 0;
		if (taroEven) {
			int turnTaro = ((ec + oc) - 1) / 2;
			return oc <= turnTaro * 2;
		} else {
