/** Updates DP entries for the case where we do NOT use a change at position i. */
private void updateWithoutChange(int i, int j, int k, char command,
                                 int[][][] minPos, int[][][] maxPos) {
    if (command == 'T') {
        minPos[i][j][k] = Math.min(minPos[i][j][k],
                                   minPos[i - 1][j][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k],
                                   maxPos[i - 1][j][1 - k]);
    } else {
        minPos[i][j][k] = Math.min(minPos[i][j][k],
                                   minPos[i - 1][j][k] + toward(k));
        maxPos[i][j][k] = Math.max(maxPos[i][j][k],
                                   maxPos[i - 1][j][k] + toward(k));
    }
}

/** Updates DP entries for the case where we USE a change at position i. */
private void updateWithChange(int i, int j, int k, char command,
                              int[][][] minPos, int[][][] maxPos) {
    if (command == 'T') {
        minPos[i][j][k] = Math.min(minPos[i][j][k],
                                   minPos[i - 1][j - 1][k] + toward(k));
        maxPos[i][j][k] = Math.max(maxPos[i][j][k],
                                   maxPos[i - 1][j - 1][k] + toward(k));
    } else {
        minPos[i][j][k] = Math.min(minPos[i][j][k],
                                   minPos[i - 1][j - 1][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k],
                                   maxPos[i - 1][j - 1][1 - k]);
    }
}

/** Computes the final answer from the filled DP tables. */
private int computeAnswer(int[][][] minPos, int[][][] maxPos,
                          int n, int toChange) {
    int answer = 0;
    for (int j = toChange % 2; j <= toChange; j += 2) {
        for (int k = 0; k < 2; k++) {
            answer = Math.max(answer, -minPos[n][j][k]);
            answer = Math.max(answer, maxPos[n][j][k]);
        }
    }
    return answer;
}

