static int[] BinarySearch(int[] arr, int x, int l, int r, int lb, int rb) {
    int[] outOfRange = checkOutOfRange(arr, x);
    if (outOfRange != null) {
        return outOfRange;
    }

    if (l > r) {
        return handleEmptyRange(l, r, lb, rb);
    }

    int mid = (l + r) / 2;

    if (arr[mid] == x) {
        return handleFound(mid, lb, rb);
    } else if (arr[mid] > x) {
        return searchLeft(arr, x, l, mid - 1, lb, mid);
    } else {
        return searchRight(arr, x, mid + 1, r, mid, rb);
    }
}

/* ----------- Extracted helpers ----------- */

private static int[] checkOutOfRange(int[] arr, int x) {
    if (x < arr[0]) {
        return new int[]{-1, -1, 0};
    }
    if (x > arr[arr.length - 1]) {
        return new int[]{-1, arr.length - 1, -1};
    }
    return null; // not out of range
}

private static int[] handleEmptyRange(int l, int r, int lb, int rb) {
    if (lb == -1) {
        lb = r;
    }
    if (rb == -1) {
        rb = l;
    }
    return new int[]{-1, lb, rb};
}

private static int[] handleFound(int index, int lb, int rb) {
    if (lb == -1) {
        lb = index;
    }
    if (rb == -1) {
        rb = index;
    }
    return new int[]{index, lb, rb};
}

private static int[] searchLeft(int[] arr, int x, int l, int r, int lb, int newRb) {
    // newRb is the current middle index, becomes tentative right bound
    return BinarySearch(arr, x, l, newRb - 1, lb, newRb);
}

private static int[] searchRight(int[] arr, int x, int l, int r, int newLb, int rb) {
    // newLb is the current middle index, becomes tentative left bound
    return BinarySearch(arr, x, newLb + 1, r, newLb, rb);
}

