public static int twopointers(int outconsider, int[] arr, int[][] prefixArr) {
    int lp = findFirstIndex(arr, outconsider);
    if (lp == -1) {
        return 0;
    }

    int rp = findLastIndex(arr, outconsider);
    if (rp == -1) {
        return 0;
    }

    int bestAns = 1;
    int csize = 2;

    while (lp < rp) {
        int mr = maxRangeQuery(prefixArr, lp, rp);
        if (mr >= 0) {
            bestAns = Math.max(mr + csize, bestAns);
        }
        csize += 2;

        lp = advanceLeft(arr, outconsider, lp + 1);
        if (lp == -1) {
            return bestAns;
        }

        rp = retreatRight(arr, outconsider, rp - 1);
        if (rp == -1) {
            return bestAns;
        }
    }
    return bestAns;
}

/* -------------------------------------------------------------------- */
/* Helper methods that encapsulate the individual “bumpy” logic blocks. */

private static int findFirstIndex(int[] arr, int target) {
    for (int i = 0; i < arr.length; i++) {
        if (arr[i] == target) {
            return i;
        }
    }
    return -1;          // not found
}

private static int findLastIndex(int[] arr, int target) {
    for (int i = arr.length - 1; i >= 0; i--) {
        if (arr[i] == target) {
            return i;
        }
    }
    return -1;          // not found
}

/* Move the left pointer to the next occurrence of `target` after `start`. */
private static int advanceLeft(int[] arr, int target, int start) {
    for (int i = start; i < arr.length; i++) {
        if (arr[i] == target) {
            return i;
        }
    }
    return -1;          // no further occurrence
}

/* Move the right pointer to the previous occurrence of `target` before `start`. */
private static int retreatRight(int[] arr, int target, int start) {
    for (int i = start; i >= 0; i--) {
        if (arr[i] == target) {
            return i;
        }
    }
    return -1;          // no further occurrence
}

