/* -------------------------------------------------------------
 *  Extraction #1 – placement logic
 * ------------------------------------------------------------- */
private static void placePassengers(final int tickets, final List<Entry<Integer, List<Boolean>>> bus) {
    int lastPlaced = -1;

    for (int i = 0; i < tickets; i++) {
        int columnIndex = 0;

        // reset when we have reached the last row
        if (lastPlaced + 1 == ROWS) {
            lastPlaced = -1;
        }

        for (Entry<Integer, List<Boolean>> row : bus) {
            // find the first row that still has capacity and is after the previous placement
            if (row.getKey() != row.getValue().size() && columnIndex > lastPlaced) {
                row.getValue().add(Boolean.TRUE);
                lastPlaced = columnIndex;
                break;          // move to the next ticket
            }
            columnIndex++;
        }
    }
}

/* -------------------------------------------------------------
 *  Extraction #2 – rendering logic
 * ------------------------------------------------------------- */
private static void renderBus(final List<Entry<Integer, List<Boolean>>> bus) {
    final String border = "+------------------------+";
    final String[] endWith = {"|D|)", "|.|", "..|", "|.|)"};

    System.out.println(border);

    for (int i = 0; i < ROWS; i++) {
        System.out.print('|');

        int occupied   = bus.get(i).getValue().size();
        int capacity   = bus.get(i).getKey();

        printOccupiedSeats(occupied);
        printEmptySeats(capacity - occupied);

        if (capacity == SHORT_ROW) {
            printShortRowPadding();
        }

        System.out.println(endWith[i]);
    }

    System.out.println(border);
}

