public static int min(int index, int pos, int n, int direction) {
        if (index == inp.length() && n == 0)
            return Math.abs(pos);
        else if (index == inp.length())
            return Integer.MIN_VALUE;
        else if (dp[index][pos + 100][n][direction + 1] != -1)
            return dp[index][pos + 100][n][direction + 1];
        else {
            if (n == 0) {
                if (inp.charAt(index) == 'T') {
                    return dp[index][pos + 100][n][direction + 1] = min(
                            index + 1, pos, n, -direction);
                } else
                    return dp[index][pos + 100][n][direction + 1] = min(
                            index + 1, pos + direction, n, direction);
            }

            else {
                if (inp.charAt(index) == 'T') {
                    int max = min(index + 1, pos, n, -direction);
                    for (int i = 1; i <= n; i++) {
                        if (i % 2 == 0) {
                            max = Math.max(max,
                                    min(index + 1, pos, n - i, -direction));
                        } else {
                            max = Math.max(
                                    min(index + 1, pos + direction, n - i,
                                            direction), max);
                        }
                    }
                    return dp[index][pos + 100][n][direction + 1] = max;

                } else {
                    int max = min(index + 1, pos + direction, n, direction);
                    for (int i = 1; i <= n; i++) {
                        if (i % 2 == 0) {
                            max = Math.max(
                                    max,
                                    min(index + 1, pos + direction, n - i,
                                            direction));
                        } else {
                            max = Math.max(max,
                                    min(index + 1, pos, n - i, -direction));
                        }
                    }
                    return dp[index][pos + 100][n][direction + 1] = max;
                }
            }
        }
    }

