public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    int m = sc.nextInt();

    // allocate containers
    a = new int[n][];
    long[] s = new long[n];
    long[] maxP = new long[n];
    int[] max2 = new int[n];
    maxContSum = new long[n];
    Arrays.fill(maxContSum, -1);

    // ---------- 1. read the sequence data ----------
    readSequenceData(sc, n, a, s, maxP, max2);

    // ---------- 2. compute suffix‑maximum sums ----------
    long[] maxS = new long[n];
    computeSuffixMaximums(n, maxS);

    // ---------- 3. read the list of indices ----------
    int[] indices = readIndices(sc, m);

    // ---------- 4. determine the overall maximum element ----------
    int globalMax = computeGlobalMaximum(indices, max2);
    if (globalMax <= 0) {
        System.out.println(globalMax);
        return;
    }

    // ---------- 5. evaluate the answer ----------
    long answer = evaluateAnswer(indices, s, maxP, maxS);

    PrintWriter pw = new PrintWriter(System.out);
    pw.println(answer);
    pw.flush();
    pw.close();
}

/** Fill a, s, maxP and max2 with the information of each sequence. */
private static void readSequenceData(Scanner sc, int n,
                                     int[][] a,
                                     long[] s,
                                     long[] maxP,
                                     int[] max2) {
    for (int i = 0; i < n; i++) {
        int len = sc.nextInt();
        int maxInSeq = Integer.MIN_VALUE;
        long maxPrefix = 0;
        a[i] = new int[len];

        for (int j = 0; j < len; j++) {
            a[i][j] = sc.nextInt();
            s[i] += a[i][j];
            maxInSeq = Math.max(maxInSeq, a[i][j]);
            maxPrefix = Math.max(maxPrefix, s[i]);
        }
        maxP[i] = maxPrefix;
        max2[i] = maxInSeq;
    }
}

/** For every sequence compute the maximum sum of a suffix. */
private static void computeSuffixMaximums(int n, long[] maxS) {
    for (int i = 0; i < n; i++) {
        long suffixSum = 0;
        long best = 0;
        for (int j = a[i].length - 1; j >= 0; j--) {
            suffixSum += a[i][j];
            best = Math.max(best, suffixSum);
        }
        maxS[i] = best;
    }
}

/** Read the list of indices (1‑based in the input, 0‑based internally). */
private static int[] readIndices(Scanner sc, int m) {
    int[] indices = new int[m];
    for (int i = 0; i < m; i++) {
        indices[i] = sc.nextInt() - 1;
    }
    return indices;
}

/** Compute the maximum single element among the selected sequences. */
private static int computeGlobalMaximum(int[] indices, int[] max2) {
    int max = Integer.MIN_VALUE;
    for (int idx : indices) {
        max = Math.max(max, max2[idx]);
    }
    return max;
}

/** Core loop that calculates the required answer. */
private static long evaluateAnswer(int[] indices,
                                   long[] s,
                                   long[] maxP,
                                   long[] maxS) {
    long sum = 0;
    long ans = 0;

    for (int idx : indices) {
        // best using a contiguous sub‑array inside the current sequence
        ans = Math.max(ans, maxContSum(idx));

        // best by concatenating the current prefix with previously accumulated sum
        ans = Math.max(ans, sum + maxP[idx]);

        // update the accumulated sum with the whole current sequence
        sum += s[idx];

        // keep the larger of the accumulated sum and the best suffix of the current sequence
        sum = Math.max(maxS[idx], sum);

        // overall best so far
        ans = Math.max(ans, sum);
    }
    return ans;
}

public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    int m = sc.nextInt();

    // read the arrays and compute per‑array statistics
    readArrayData(sc, n);

    // compute suffix maximum sums for every array
    computeSuffixMaximums();

    // read the sequence of indices (0‑based)
    int[] indices = readIndices(sc, m);

    // overall maximum element among the selected arrays
    int globalMax = findGlobalMaximum(indices);
    if (globalMax <= 0) {
        System.out.println(globalMax);
        return;
    }

    // main processing loop – calculates the answer
    long answer = evaluateIndices(indices);

    PrintWriter pw = new PrintWriter(System.out);
    pw.println(answer);
    pw.flush();
    pw.close();
}

