private static long evaluateIndices(int[] indices) {
    long sum = 0;
    long ans = 0;

    for (int idx : indices) {
        // 1. best contiguous sum inside the current array
        ans = Math.max(ans, maxContSum(idx));

        // 2. best prefix sum if we start a new segment at this array
        ans = Math.max(ans, sum + maxP[idx]);

        // 3. extend the running total with the whole array
        sum += s[idx];
        sum = Math.max(maxS[idx], sum);

        // 4. best overall value after processing this array
        ans = Math.max(ans, sum);
    }
    return ans;
}

