/**
 * Returns the first pokemon that matches the given pattern, or {@code null}
 * if none match.
 *
 * @param pattern   pattern that may contain '.' as a wildcard
 * @param candidates array of possible pokemon names
 * @return the matching pokemon name or {@code null}
 */
private String findMatchingPokemon(String pattern, String[] candidates) {
    for (String pokemon : candidates) {
        if (pokemon.length() != pattern.length()) {
            continue;
        }
        if (matchesPattern(pokemon, pattern)) {
            return pokemon;
        }
    }
    return null;
}

/**
 * Checks whether a pokemon name matches the supplied pattern.
 * The pattern may contain '.' characters that match any character.
 *
 * @param pokemon the pokemon name to test
 * @param pattern the pattern containing optional '.' wildcards
 * @return {@code true} if the name matches the pattern; {@code false} otherwise
 */
private boolean matchesPattern(String pokemon, String pattern) {
    for (int i = 0; i < pokemon.length(); i++) {
        char pChar = pattern.charAt(i);
        if (pChar == '.') {
            continue;               // wildcard matches any character
        }
        if (pokemon.charAt(i) != pChar) {
            return false;
        }
    }
    return true;
}

