private static int processKnownPairs(StringBuilder s, int n, boolean[] used, PrintWriter out) {
    int len = s.length();
    int nb = 0;
    int mid = len / 2 + (len % 2 == 0 ? 0 : 1);

    for (int i = 0; i < mid; i++) {
        char left = s.charAt(i);
        char right = s.charAt(len - 1 - i);

        if (left == '?' && right == '?') {
            nb++;
            continue;
        }

        if (left == '?' || right == '?') {
            if (left == '?') {
                s.setCharAt(i, right);
            } else {
                s.setCharAt(len - 1 - i, left);
            }
        }

        // after possible replacement, both sides are non‑'?' characters
        if (s.charAt(i) != s.charAt(len - 1 - i)) {
            out.println("IMPOSSIBLE");
            return -1;
        }

        used[s.charAt(i) - 'a'] = true;
    }
    return nb;
}

