/**
 * Mirrors known characters, resolves single‑side ‘?’ and checks
 * palindrome feasibility. Fills {@code used} array and stores
 * the amount of “??” pairs in {@code nb[0]}.
 *
 * @return {@code true} if the current string can still become a palindrome,
 *         {@code false} otherwise.
 */
private static boolean preprocessPalindrome(StringBuilder s,
                                            boolean[] used,
                                            int[] nb) {
    int len = s.length();
    int half = len / 2 + (len % 2 == 0 ? 0 : 1);

    for (int i = 0; i < half; i++) {
        char left = s.charAt(i);
        char right = s.charAt(len - 1 - i);

        if (left == '?' && right == '?') {
            nb[0]++;                       // a pair of unknowns
            continue;
        }

        // Resolve a single unknown side
        if (left == '?' || right == '?') {
            if (left == '?') {
                s.setCharAt(i, right);
            } else {
                s.setCharAt(len - 1 - i, left);
            }
        }

        // After possible resolution the characters must match
        if (s.charAt(i) != s.charAt(len - 1 - i)) {
            return false;
        }

        used[s.charAt(i) - 'a'] = true;   // mark the character as used
    }
    return true;
}

/**
 * Counts how many letters from the first {@code n} letters of the alphabet
 * have not been used yet.
 */
private static int countUnusedLetters(boolean[] used, int n) {
    int missing = 0;
    for (int i = 0; i < n; i++) {
        if (!used[i]) {
            missing++;
        }
    }
    return missing;
}

/**
 * Finds the smallest index of an unused letter.
 */
private static int findNextUnusedLetter(boolean[] used, int n) {
    for (int i = 0; i < n; i++) {
        if (!used[i]) {
            return i;
        }
    }
    return n; // all letters are used – caller guarantees this never happens
}

/**
 * Replaces remaining “??” pairs with either ‘a’ (if we have surplus pairs)
 * or with the smallest unused letters, updating {@code used} and {@code nxt}
 * accordingly.
 */
private static void fillRemainingPlaceholders(StringBuilder s,
                                               int nb,
                                               int toAdd,
                                               boolean[] used,
                                               int[] nxt,
                                               PrintWriter out) {
    int len = s.length();
    int half = len / 2 + (len % 2 == 0 ? 0 : 1);

    for (int i = 0; i < half; i++) {
        if (s.charAt(i) != '?') {
            continue; // already resolved in the first pass
        }

        if (nb > toAdd) {                     // we have spare “??” pairs
            s.setCharAt(i, 'a');
            s.setCharAt(len - 1 - i, 'a');
            nb--;
        } else {                              // need to introduce new letters
            char ch = (char) (nxt[0] + 'a');
            s.setCharAt(i, ch);
            s.setCharAt(len - 1 - i, ch);
            used[nxt[0]] = true;

            // advance nxt to the next unused letter
            do {
                nxt[0]++;
            } while (nxt[0] < used.length && used[nxt[0]]);
        }
    }
}

