public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    String n = sc.next();

    // special case: the number starts with '1'
    if (n.charAt(0) == '1') {
        System.out.println(computeAllNinesProduct(n.length() - 1));
        return;
    }

    long maxByDecrement = computeMaxProductAfterDecrement(n);
    long productAllDigits = computeProductOfAllDigits(n);

    System.out.println(Math.max(productAllDigits, maxByDecrement));
}

/**
 * When the first digit is '1' the best product is 9^(len-1).
 * This method returns that product.
 */
private static long computeAllNinesProduct(int countOfNines) {
    long result = 1L;
    for (int i = 0; i < countOfNines; i++) {
        result *= 9L;
    }
    return result;
}

/**
 * Evaluates every position i of the string, decreases the digit at i
 * (if it is not '0'), sets all following digits to '9' and computes the
 * product of the resulting digits. Returns the maximum product found.
 */
private static long computeMaxProductAfterDecrement(String n) {
    long best = 0L;
    int length = n.length();

    for (int i = 0; i < length; i++) {
        // product of digits before position i
        long prefixProduct = 1L;
        for (int k = 0; k < i; k++) {
            prefixProduct *= digitValue(n.charAt(k));
        }

        // if the current digit is '0' we cannot decrement it
        if (n.charAt(i) == '0') {
            continue;
        }

        // decrease the current digit by one
        long currentProduct = prefixProduct * (digitValue(n.charAt(i)) - 1L);

        // set all following digits to '9'
        for (int j = i + 1; j < length; j++) {
            currentProduct *= 9L;
        }

        best = Math.max(best, currentProduct);
    }
    return best;
}

/**
 * Computes the product of all digits of the given numeric string.
 */
private static long computeProductOfAllDigits(String n) {
    long product = 1L;
    for (int i = 0; i < n.length(); i++) {
        product *= digitValue(n.charAt(i));
    }
    return product;
}

/**
 * Helper that converts a numeric character to its integer value.
 */
private static int digitValue(char c) {
    return c - '0';
}

