/* --------------------------------------------------------------------- */
/* Helper methods extracted to isolate independent logical chunks          */
/* --------------------------------------------------------------------- */

private static long[] readProblemTypesAndSum(int n, FastReader s,
                                            long a, long b, long[][] t) {
    long c0 = 0, c1 = 0, sum = 0;
    for (int i = 0; i < n; i++) {
        t[i][1] = s.nextInt();               // problem type (0 or 1)
        if (t[i][1] == 0) {
            c0++;
            sum += a;
        } else {
            c1++;
            sum += b;
        }
    }
    return new long[]{c0, c1, sum};
}

private static void readDeadlines(int n, FastReader s, long[][] t) {
    for (int i = 0; i < n; i++) {
        t[i][0] = s.nextInt();               // deadline
    }
}

/**
 * Computes the maximal number of problems that can be solved
 * respecting the time limit T and the given deadlines.
 */
private static long computeMaxProblems(long[][] t, long a, long b,
                                      long c0, long c1, long T) {
    int n = t.length;
    long ans = 0;

    // ----- part before the first deadline -----
    long firstRem = t[0][0] - 1;
    if (firstRem > 0) {
        ans = computeAdditionalProblems(firstRem, a, b, c0, c1);
    }

    // ----- iterate over each solved problem, trying to insert extra ones -----
    long cur0 = 0, cur1 = 0, cur = 0;
    for (int i = 0; i < n - 1; i++) {
        if (t[i][1] == 0) {
            cur0++;
            cur += a;
        } else {
            cur1++;
            cur += b;
        }

        // cannot insert anything before the next deadline
        if (cur >= t[i + 1][0] || cur > T) {
            continue;
        }

        long rem = t[i + 1][0] - cur - 1;          // free time before next deadline
        long r0 = c0 - cur0;                       // remaining type‑0 problems
        long r1 = c1 - cur1;                       // remaining type‑1 problems

        long extra = computeAdditionalProblems(rem, a, b, r0, r1);
        ans = Math.max(ans, i + 1 + extra);
    }
    return ans;
}

/**
 * Greedily fits as many type‑0 problems (cost a) as possible,
 * then fills the remaining time with type‑1 problems (cost b).
 */
private static long computeAdditionalProblems(long rem, long a, long b,
                                             long cnt0, long cnt1) {
    long can0 = Math.min(rem / a, cnt0);
    rem -= can0 * a;
    long can1 = Math.min(rem / b, cnt1);
    return can0 + can1;
}

