private int[] readArray(int n) throws IOException {
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = nextInt();
    }
    return arr;
}

/**
 * Executes the branch where the current element is not smaller than the previous maximum.
 * It simply extends the current increasing subsequence and records the index on the stack.
 */
private void handleIncreasingCase(int i, int[] dp, int[] max, Stack<Integer> stack) {
    dp[i] = dp[i - 1] + 1;
    stack.add(i);
}

/**
 * Executes the branch where the current element breaks the monotone increase.
 * It finds the nearest previous position whose prefix‑maximum is larger,
 * adjusts the helper stack and computes dp[i] based on that position.
 */
private void handleDecreasingCase(int i, int[] a, int[] dp, int[] max, Stack<Integer> stack) {
    int r = findFirstGreaterIndex(max, i, a[i]);
    // make sure the stack top does not point past the found index
    while (stack.peek() > r) {
        stack.pop();
    }
    int maxx = stack.peek();
    if (maxx == 0) {
        dp[i] = 1;
    } else {
        dp[i] = dp[maxx - 1] + 1;
    }
}

/**
 * Binary‑searches the prefix‑maximum array to locate the first index ≤ i‑1
 * whose stored maximum is strictly greater than {@code value}.
 * Returns that index (always in range [0, i‑1]).
 */
private int findFirstGreaterIndex(int[] max, int i, int value) {
    int l = -1;
    int r = i - 1;
    while (r - l > 1) {
        int m = (l + r) >>> 1;      // unsigned right shift = divide by 2
        if (max[m] > value) {
            r = m;
        } else {
            l = m;
        }
    }
    return r;
}

