    int start = 1, end = n;
    long[] ans = new long[m];               // best answer found so far

    while (start <= end) {
        int mid = start + (end - start) / 2;

        EvalResult res = evaluateMid(mid, a, n, m, k);
        if (res.can) {
            ans = res.print.clone();        // store the successful configuration
            start = mid + 1;                // try to take more rows
        } else {
            end = mid - 1;                  // need fewer rows
        }
    }

    for (long x : ans)
        out.print(x + " ");

    out.flush();
    out.close();
}

/* -------------------------------------------------------------------- *
 *  Extracted helper methods                                              *
 * -------------------------------------------------------------------- */

/**
 * Reads an n × m matrix of longs.
 */
private static long[][] readMatrix(Scanner sc, int n, int m) {
    long[][] mat = new long[n][m];
    for (int i = 0; i < n; i++)
        for (int j = 0; j < m; j++)
            mat[i][j] = sc.nextLong();
    return mat;
}

/**
 * Evaluates whether a window of size {@code mid} rows can satisfy the
 * condition (total ≤ k).  Returns an {@link EvalResult} describing the outcome.
 */
private static EvalResult evaluateMid(int mid, long[][] a, int n, int m, long k) {
    // 1️⃣ Build fresh segment‑trees for the current binary‑search step
    SegmentTree[] trees = createSegmentTrees(m, n);

    // 2️⃣ Load the first {@code mid} rows into the trees
    fillRows(trees, a, 0, mid);

    // 3️⃣ Compute the initial sum and fill the {@code print} array
    long[] print = new long[m];
    long curr = sumQueries(trees, print);
    boolean can = curr <= k;
    if (can) {
        return new EvalResult(true, print.clone());
    }

    // 4️⃣ Slide the window forward until we either succeed or run out of rows
    boolean slideSuccess = slideWindow(trees, a, mid, n, m, k, print);
    return new EvalResult(slideSuccess, slideSuccess ? print.clone() : null);
}

/**
 * Creates {@code m} segment‑trees, each capable of handling {@code n} positions.
 */
private static SegmentTree[] createSegmentTrees(int m, int n) {
    SegmentTree[] trees = new SegmentTree[m];
    for (int i = 0; i < m; i++) {
        trees[i] = new SegmentTree(n);
    }
    return trees;
}

/**
 * Inserts rows {@code from} (inclusive) to {@code to} (exclusive) of matrix {@code a}
 * into the corresponding segment‑trees.
 */
private static void fillRows(SegmentTree[] trees, long[][] a, int from, int to) {
    for (int i = from; i < to; i++) {
        for (int col = 0; col < trees.length; col++) {
            trees[col].update_point(i + 1, a[i][col]);
        }
    }
}

/**
 * Executes {@code query()} on each tree, stores the results in {@code out},
 * and returns the total sum of those results.
 */
private static long sumQueries(SegmentTree[] trees, long[] out) {
    long total = 0L;
    for (int i = 0; i < trees.length; i++) {
        total += out[i] = trees[i].query();
    }
    return total;
}

/**
 * Slides a fixed‑size window of rows across the matrix.
 *
 * @param trees   segment‑trees already populated with the first window
 * @param a       original matrix
 * @param mid     size of the window (number of rows)
 * @param n       total number of rows in the matrix
 * @param m       total number of columns
 * @param k       allowed maximum total
 * @param print   array that will hold the last evaluated column results
 * @return {@code true} if any window satisfies the condition, {@code false} otherwise
 */
private static boolean slideWindow(SegmentTree[] trees, long[][] a,
                                   int mid, int n, int m, long k, long[] print) {
    // i – row that leaves the window, j – row that enters
    for (int i = 0, j = mid; j < n; i++, j++) {
        // remove row i
        for (int col = 0; col < m; col++) {
            trees[col].update_point(i + 1, 0L);
        }
        // add row j
        for (int col = 0; col < m; col++) {
            trees[col].update_point(j + 1, a[j][col]);
        }

        // recompute total and column‑wise values
        long curr = sumQueries(trees, print);
        if (curr <= k) {
            return true;                     // early exit – condition satisfied
        }
    }
    return false;                            // none of the windows worked
}

