/* ---------- merge vertices not belonging to any capital component ---------- */
private void mergeRemainingVerticesIntoLargestComponent() {
    int maxSize = 0;
    int indexOfMax = 0;

    for (int i = 0; i < k; i++) {
        int size = map.get(capitals[i]).size();
        if (size > maxSize) {
            maxSize = size;
            indexOfMax = i;
        }
    }

    ArrayList<Integer> biggestComponent = map.get(capitals[indexOfMax]);
    for (int v = 0; v < n; v++) {
        if (!used[v]) {
            biggestComponent.add(v);
        }
    }
    // map already holds a reference to biggestComponent, no further action needed
}

