private void computeAndPrintResult() {
    int[] sum = new int[k];

    for (int i = 0; i < k; i++) {
        ArrayList<Integer> component = map.get(capitals[i]);
        int sz = component.size();

        // maximal number of edges in a complete sub‑graph of this size
        int possibleEdges = (int) (sz * ((double) (sz - 1) / 2));

        // current edges inside the component (each edge appears twice in adjacency lists)
        int existingEdges = 0;
        for (int v : component) {
            existingEdges += graph[v].size();
        }
        existingEdges /= 2;          // each undirected edge counted twice

        sum[i] = possibleEdges - existingEdges;
    }

    int total = 0;
    for (int v : sum) {
        total += v;
    }
    System.out.println(total);
}

