/**
 * Computes the required result for the given character array.
 * The algorithm is unchanged; only the control flow is broken into
 * small, well‑named helper methods to reduce nesting and improve readability.
 */
private static long computeResult(char[] str) {
    final int MOD = 1_000_000_007;
    int n = str.length;

    int i = skipLeadingBs(str, 0);
    int aPower = 1;
    long res = 0L;

    while (i < n) {
        int aEnd = countConsecutiveAs(str, i);
        if (aEnd == n) {
            break; // no trailing 'b' after the last block of 'a's
        }

        int aCount = aEnd - i;
        aPower = updateAPower(aPower, aCount, MOD);

        int bEnd = countConsecutiveBs(str, aEnd + 1);
        int bCount = bEnd - (aEnd + 1);
        res = (res + bCount * ((long) aPower - 1)) % MOD;

        i = bEnd;
    }
    return res;
}

/** Skips over leading 'b' characters starting from index {@code start}. */
private static int skipLeadingBs(char[] str, int start) {
    int i = start;
    while (i < str.length && str[i] == 'b') {
        i++;
    }
    return i;
}

/** Returns the index of the first character that is not 'a' starting from {@code start}. */
private static int countConsecutiveAs(char[] str, int start) {
    int j = start + 1;
    while (j < str.length && str[j] == 'a') {
        j++;
    }
    return j;
}

/** Returns the index of the first character that is not 'b' starting from {@code start}. */
private static int countConsecutiveBs(char[] str, int start) {
    int k = start;
    while (k < str.length && str[k] == 'b') {
        k++;
    }
    return k;
}

/** Updates the accumulated power of two for the given number of consecutive 'a's. */
private static int updateAPower(int currentPower, int aCount, int mod) {
    int power = currentPower;
    for (int p = 0; p < aCount; p++) {
        power = (int) ((long) power * 2 % mod);
    }
    return power;
}

