public void solve(int testNumber, FastScanner in, PrintWriter out) {
    init();
    int n = in.nextInt();
    int m = in.nextInt();
    long L = in.nextInt();
    long R = in.nextInt();
    modulo = in.nextInt();

    long res = 0;
    for (int dx = 1; dx <= n; dx++) {
        res = (res + contributionForDx(dx, n, m, L, R)) % modulo;
    }

    // additional points that lie on the axes
    if (L <= 1) {
        res += (n + 1L) * m + n * (m + 1L);
    }
    out.println(res % modulo);
}

/** Calculates the part of the answer that comes from a single horizontal offset {@code dx}. */
private long contributionForDx(int dx, int n, int m, long L, long R) {
    long low  = L * L - (long) dx * dx;
    long high = R * R - (long) dx * dx;

    if (high < 0) {
        return 0L;                    // nothing fits in the annulus for this dx
    }
    if (low < 0) {
        low = 0;
    }

    long left  = (long) Math.sqrt(low);
    long right = (long) Math.sqrt(high);

    left  = adjustLeft(dx, L, left);
    right = adjustRight(dx, R, right);

    // clamp to the rectangle borders
    if (left < 0)  left = 0;
    if (right > m) right = m;

    if (left >= right) {
        return 0L;                    // no valid y‑coordinates in [left+1 , right]
    }

    long cnt = countInRange(dx, left, right, m);
    long sum = sumInRange(dx, left, right, cnt, m);

    // each pair (dx, dy) appears twice (±dx) and for every x‑coordinate inside the strip
    return (2L * sum % modulo) * (n - dx + 1) % modulo;
}

/** Brings {@code left} to the largest value whose square together with {@code dx²} is still < L². */
private long adjustLeft(int dx, long L, long left) {
    while (left > 0 && left * left + (long) dx * dx >= L * L) {
        left--;
    }
    while (left * left + (long) dx * dx < L * L) {
        left++;
    }
    return left - 1;
}

/** Brings {@code right} to the largest value whose square together with {@code dx²} is still ≤ R². */
private long adjustRight(int dx, long R, long right) {
    while (right > 0 && right * right + (long) dx * dx >= R * R) {
        right--;
    }
    while (right * right + (long) dx * dx <= R * R) {
        right++;
    }
    return right - 1;
}

/** Returns the number of admissible y‑coordinates in (left , right] for the given {@code dx}. */
private long countInRange(int dx, long left, long right, int m) {
    long cntR = right - getCount(dx, (int) right);
    long cntL = left  - getCount(dx, (int) left);
    long cnt  = (cntR - cntL) % modulo;
    if (cnt < 0) cnt += modulo;
    return cnt;
}

/** Returns the summed contribution of all admissible y‑coordinates in (left , right] for {@code dx}. */
private long sumInRange(int dx, long left, long right, long cnt, int m) {
    long sumR = right * (right + 1) / 2 - getSum(dx, (int) right);
    long sumL = left  * (left  + 1) / 2 - getSum(dx, (int) left);
    long sum  = (sumR - sumL) % modulo;
    if (sum < 0) sum += modulo;

    // total contribution of this column
    sum = (cnt * (m + 1) % modulo - sum) % modulo;
    if (sum < 0) sum += modulo;
    return sum;
}

