 * Returns the maximum digit that can be placed at the current position.
 */
private static int getLimit(int pos, int f) {
    return f == 0 ? number.charAt(pos) - '0' : 9;
}

/**
 * Determines whether the updated count would stay within the allowed limit.
 */
private static boolean isCountWithinLimit(int dgt, int cnt) {
    return (dgt == digit ? cnt + 1 : cnt) <= times;
}

/**
 * Computes the new count of matched digits after placing {@code dgt}.
 */
private static int nextCount(int dgt, int cnt) {
    return dgt == digit ? cnt + 1 : cnt;
}

/**
 * Computes the next “tight” flag.
 * It becomes 1 when the current prefix is already smaller than the limit,
 * otherwise it stays as {@code f}.
 */
private static int nextFlag(int pos, int dgt, int limit, int f) {
    return (f == 0 && dgt < limit) ? 1 : f;
}

