private static long[] computeMaxSums(int n, int[] p, long[] sum) {
    long[] ans = new long[n];
    long max = 0L;
    UnionFindTree uft = new UnionFindTree(n + 1, sum);
    boolean[] alive = new boolean[n + 1];

    for (int i = n - 1; i >= 0; i--) {
