public static void sort(int[] arr) {
    // Guard clause for trivial cases
    if (arr == null || arr.length <= 1) {
        return;
    }

    int last = arr.length - 1;
    int[] buffer = new int[arr.length];

    // Bottom‑up merge sort
    for (int segment = 1; segment <= last; segment <<= 1) {
        for (int left = 0; left < last; left += (segment << 1)) {
            int right = Math.min(left + (segment << 1) - 1, last);
            int mid = Math.min(left + segment - 1, last);
            mergeAndCopy(arr, buffer, left, mid, right);
        }
    }
}

/**
 * Merges the two sorted sub‑ranges [left, mid] and [mid+1, right] of {@code src}
 * into {@code dest} and copies the merged result back into {@code src}.
 */
private static void mergeAndCopy(int[] src, int[] dest, int left, int mid, int right) {
    int i = left;       // index in left sub‑range
    int j = mid + 1;    // index in right sub‑range
    int k = left;       // index in destination buffer

    // Merge while both sub‑ranges have elements
    while (i <= mid && j <= right) {
        dest[k++] = (src[i] <= src[j]) ? src[i++] : src[j++];
    }

    // Copy any remaining elements from the left sub‑range
    while (i <= mid) {
        dest[k++] = src[i++];
    }

    // Copy any remaining elements from the right sub‑range
    while (j <= right) {
        dest[k++] = src[j++];
    }

    // Write the merged segment back into the original array
    for (int idx = left; idx <= right; idx++) {
        src[idx] = dest[idx];
    }
}

