private int[] initialiseMask(int k, int n) {
    int[] mask = new int[k];
    for (int i = 0; i < k; i++) {
        mask[i] = i;
    }
    return mask;
}

/**
 * Iterates over every permutation of {@code mask} (via {@code next(mask,n)})
 * and counts how many transformed strings satisfy {@code checkAll}.
 */
private int countValidMasks(String s, int[] mask, int n, int k) {
    int result = 0;
    char[] c = new char[n];

    do {
        buildTransformedArray(s, mask, n, k, c);
        if (checkAll(c)) {
            result++;
        }
    } while (next(mask, n));

    return result;
}

/**
 * Builds the temporary character array {@code c} for the current {@code mask}.
 * Positions listed in {@code mask} keep the original character,
 * all other positions are flipped ('0' ↔ '1').
 */
private void buildTransformedArray(String s, int[] mask, int n, int k, char[] c) {
    int j = 0;
    for (int i = 0; i < n; i++) {
        if (j < k && i == mask[j]) {
            c[i] = s.charAt(mask[j++]);          // keep original character
        } else {
            c[i] = s.charAt(i) == '1' ? '0' : '1'; // flip the bit
        }
    }
}

