public static long getClosestK(long[] a, long x) {
    // Guard clause for empty or null array
    if (a == null || a.length == 0) {
        throw new IllegalArgumentException("The array cannot be empty");
    }

    int low = 0;
    int high = a.length - 1;

    while (low <= high) {
        int mid = (low + high) / 2;

        // Guard clauses for the distinct logical paths
        if (mid == 0) {
            return handleMidZero(a, x);
        }

        if (mid == a.length - 1) {
            return a[a.length - 1];
        }

        if (a[mid] == x || a[mid + 1] == x) {
            return x;
        }

        if (a[mid] < x && a[mid + 1] > x) {
            return handleMidBetween(a, mid, x);
        }

        // Continue binary search
        if (a[mid] < x) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    // This point is reached only when the array is empty, which is already guarded above
    throw new IllegalArgumentException("The array cannot be empty");
}

/**
 * Handles the case where the binary search lands on the first element (mid == 0).
 * Mirrors the original logic: if the array has one element, return it;
 * otherwise return the nearer of the first two elements (expressed as x plus the minimum distance).
 */
private static long handleMidZero(long[] a, long x) {
    if (a.length == 1) {
        return a[0];
    }
    return Math.min(Math.abs(a[0] - x), Math.abs(a[1] - x)) + x;
}

/**
 * Handles the case where x lies between a[mid] and a[mid + 1].
 * Mirrors the original logic of returning the nearer element expressed as x plus the minimum distance.
 */
private static long handleMidBetween(long[] a, int mid, long x) {
    return Math.min(Math.abs(a[mid] - x), Math.abs(a[mid + 1] - x)) + x;
}

