/* ---------- helper methods ---------- */

private static long[] readArray(InputReader in, int size) {
    long[] arr = new long[size];
    for (int i = 0; i < size; i++) {
        arr[i] = in.readInt();
    }
    return arr;
}

/**
 * Creates the 2‑dimensional array of SegmentTree objects.
 * Only indices with {@code i >= 2} are instantiated,
 * matching the original nested‑loop logic.
 */
private static SegmentTree[][] createSegmentTrees(int n) {
    SegmentTree[][] T = new SegmentTree[7][10];          // original dimensions
    for (int i = 2; i < 7; i++) {
        int innerSize = 2 * (i - 1);
        for (int j = 0; j < innerSize; j++) {
            T[i][j] = new SegmentTree(n);
        }
    }
    return T;
}

/**
 * Populates every SegmentTree with the initial values.
 * Mirrors the triple‑nested loop from the original code.
 */
private static void buildSegmentTrees(SegmentTree[][] T, long[] A) {
    int n = A.length;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < 7; j++) {
            int innerSize = 2 * (j - 1);
            for (int k = 0; k < innerSize; k++) {
                // T[j][k] is null for j < 2, which is fine because the loop is skipped.
                T[j][k].update(i, A[i] * getMult(j, k, i));
            }
        }
    }
}

/**
 * Executes the series of operations (updates or queries) read from the input.
 * The body of each operation has been moved to dedicated helper methods
 * to keep the control flow linear and readable.
 */
private static void processOperations(InputReader in, PrintWriter out,
                                      SegmentTree[][] T, int operationCount) {
    for (int op = 0; op < operationCount; op++) {
        int type = in.readInt();
        if (type == 1) {
            handleUpdate(in, T);
        } else {
            handleQuery(in, out, T);
        }
    }
}

/**
 * Handles an update operation (type == 1).
 * Updates every SegmentTree with the new value at position p.
 */
private static void handleUpdate(InputReader in, SegmentTree[][] T) {
    int p = in.readInt() - 1;          // zero‑based index
    long v = in.readLong();

    for (int j = 0; j < 7; j++) {
        int innerSize = 2 * (j - 1);
        for (int k = 0; k < innerSize; k++) {
            T[j][k].update(p, v * getMult(j, k, p));
        }
    }
}

/**
 * Handles a query operation (type != 1).
 * Computes the required shift and prints the result of the segment‑tree query.
 */
private static void handleQuery(InputReader in, PrintWriter out,
                                SegmentTree[][] T) {
    int l = in.readInt() - 1;          // zero‑based inclusive start
    int r = in.readInt() - 1;          // zero‑based inclusive end
    int z = in.readInt();

    int shift = l % (2 * (z - 1));
    long answer = T[z][shift].query(l, r);
    out.println(answer);
}

