long go(int last, int phase, int idx) {
            if (idx == n) return 0;
            long ans = 0;
            if (memo[last][phase][idx] != -1) return memo[last][phase][idx];
            switch (phase) {
                case 0: {
                    ans = Math.max(1 + go(a[idx], 1, idx + 1), go(last, 0, idx + 1));
                    break;
                }
                case 1: {
                    ans = go(last, 1, idx + 1);
                    if (last <= a[idx]) {
                        ans = Math.max(ans, 1 + go(a[idx], 1, idx + 1));
                    }
                    ans = Math.max(ans, go(last, 2, idx));
                    break;
                }
                case 2: {
                    ans = go(last, 2, idx + 1);
                    if (last >= a[idx]) {
                        ans = Math.max(ans, 1 + go(a[idx], 2, idx + 1));
                    }
                    ans = Math.max(ans, go(last, 3, idx));
                    break;
                }
                case 3: {
                    ans = go(last, 3, idx + 1);
                    if (last <= a[idx]) {
                        ans = Math.max(ans, 1 + go(a[idx], 3, idx + 1));
                    }
                    break;
                }
            }
            return memo[last][phase][idx] = ans;
        }

