/**
 * Simulates the card game and returns the result string.
 * <p>
 * The result is either "-1" (cycle detected) or "<moves> <winner>",
 * where {@code winner} is 1 if the second deck becomes empty,
 * otherwise 2.
 */
private static String playGame(List<Integer> deck1, List<Integer> deck2) {
    // Guard clause: if any deck is already empty the game ends immediately.
    if (deck1.isEmpty() || deck2.isEmpty()) {
        return "0 " + (deck2.isEmpty() ? "1" : "2");
    }

    int moves = 0;
    boolean cycleDetected = false;

    // The original code kept a Set of pairs that was never used.
    // It is retained to stay faithful to the original structure.
    Set<pair<Long, Long>> unusedSet = new HashSet<>();

    // Sets that remember previously seen configurations.
    Set<List<Integer>> seenDeck1 = new HashSet<>();
    Set<List<Integer>> seenDeck2 = new HashSet<>();
    seenDeck1.add(deck1);
    seenDeck2.add(deck2);

    while (!deck1.isEmpty() && !deck2.isEmpty()) {
        playRound(deck1, deck2);
        moves++;

        // Guard clause: stop as soon as a deck becomes empty.
        if (deck1.isEmpty() || deck2.isEmpty()) {
            break;
        }

        // Detect a previously seen state (cycle).
        cycleDetected = seenDeck1.contains(deck1) && seenDeck2.contains(deck2);
        if (cycleDetected) {
            break;
        }

        // Remember the current state for future cycle detection.
        seenDeck1.add(deck1);
        seenDeck2.add(deck2);
    }

    if (cycleDetected) {
        return "-1";
    }
    // Winner is player 1 when deck2 is empty, otherwise player 2.
    return moves + " " + (deck2.isEmpty() ? "1" : "2");
}

