}

/**
 * Executes Mo's algorithm: sorts the queries, moves the sliding window
 * and fills {@code ans[]} with the results.
 */
private static void solveQueries() {
    // no queries – nothing to do
    if (m == 0) {
        return;
    }

    Arrays.sort(q, 1, m + 1, new cmp());
    int left = 1;
    int right = 0;
    cnt[0] = 1;                 // initialise frequency of prefix xor 0
    nowAns = 0;                 // current answer for the active window

    for (int i = 1; i <= m; i++) {
        Query cur = q[i];

        left = moveLeft(left, cur.l);
        right = moveRight(right, cur.r);

        ans[cur.id] = nowAns;
    }
}

/**
 * Moves the left border of the window from {@code curL} to {@code targetL},
 * adding or removing elements as needed.
 *
 * @return the new left border (which equals {@code targetL})
 */
private static int moveLeft(int curL, int targetL) {
    while (curL < targetL) {
        remove(curL - 1);
        curL++;
    }
    while (curL > targetL) {
        curL--;
        add(curL - 1);
    }
    return curL;
}

/**
 * Moves the right border of the window from {@code curR} to {@code targetR},
 * adding or removing elements as needed.
 *
 * @return the new right border (which equals {@code targetR})
 */
private static int moveRight(int curR, int targetR) {
    while (curR < targetR) {
        add(++curR);
    }
    while (curR > targetR) {
        remove(curR--);
    }
    return curR;
}

