/**
 * Reads the input, builds prefix‑xor array and query objects,
 * then sorts the queries for Mo's algorithm.
 */
private static void init(Scanner cin) {
    n = cin.nextInt();
    m = cin.nextInt();
    k = cin.nextInt();
    block = (int) Math.sqrt(n);

    // build prefix XOR array (1‑based)
    arr[0] = 0;
    for (int i = 1; i <= n; i++) {
        int value = cin.nextInt();
        arr[i] = arr[i - 1] ^ value;
    }

    // read queries
    for (int i = 1; i <= m; i++) {
        int left = cin.nextInt();
        int right = cin.nextInt();
        q[i] = new Query(left, right, i);
    }

    // sort queries according to Mo's ordering
    Arrays.sort(q, 1, m + 1, new cmp());

    // initial frequency table for prefix XOR = 0
    cnt[0] = 1;
}

/**
 * Executes Mo's algorithm: moves the current window so that it matches
 * each query and records the answer.
 */
private static void processQueries() {
    int l = 1, r = 0;               // current window [l, r]
    for (int i = 1; i <= m; i++) {
        Query query = q[i];

        while (l < query.l) {
            remove(l - 1);
            l++;
        }
        while (l > query.l) {
            l--;
            add(l - 1);
        }
        while (r < query.r) {
            add(++r);
        }
        while (r > query.r) {
            remove(r--);
        }

        ans[query.id] = nowAns;
    }
}

