/**
 * Builds a prefix‑sum array where each element i contains the number of occurrences
 * of {@code target} in {@code s} from index 0 up to i (inclusive).
 */
private static int[] buildPrefix(String s, char target) {
    int[] prefix = new int[s.length()];
    prefix[0] = s.charAt(0) == target ? 1 : 0;
    for (int i = 1; i < s.length(); i++) {
        prefix[i] = prefix[i - 1] + (s.charAt(i) == target ? 1 : 0);
    }
    return prefix;
}

/**
 * Calculates the contribution of a single character position of {@code a}
 * to the final answer.
 *
 * @param aChar   the current character from string a
 * @param start   the current start index in b (inclusive)
 * @param end     the current end   index in b (inclusive)
 * @param sumZero prefix‑sum array for '0' characters in b
 * @param sumOne  prefix‑sum array for '1' characters in b
 * @return the integer contribution for this position
 */
private static int contributionForPosition(char aChar, int start, int end,
                                          int[] sumZero, int[] sumOne) {
    int sum = 0;

    // subtract the prefix part that lies before the sliding window
    if (start > 0) {
        sum -= (aChar == '1') ? sumZero[start - 1] : sumOne[start - 1];
    }

    // add the count inside the current window
    sum += (aChar == '1') ? sumZero[end] : sumOne[end];
    return sum;
}

