/**
 * Builds a map that stores, for each value pair (original, sorted),
 * the index where this pair occurs in the original array.
 */
private static TreeMap<Triple, Integer> buildIndexMap(int[] original, int[] sorted) {
    TreeMap<Triple, Integer> map = new TreeMap<>();
    for (int i = 0; i < original.length; i++) {
        Triple key = new Triple(original[i], sorted[i]);
        map.put(key, i);
    }
    return map;
}

/**
 * Returns {@code true} if the array {@code a} can be turned into {@code b}
 * by swapping at most one pair of elements; otherwise {@code false}.
 *
 * The method uses a guard‑clause style to early‑exit when more than one
 * required swap is detected or when a matching counterpart cannot be found.
 */
private static boolean canTransformWithAtMostOneSwap(int[] a, int[] b, TreeMap<Triple, Integer> map) {
    boolean[] swapped = new boolean[a.length];
    int swapCount = 0;

    for (int i = 0; i < a.length; i++) {
        // Skip positions that are already equal or already involved in a swap
        if (swapped[i] || a[i] == b[i]) {
            continue;
        }

        // Look for the counterpart (b[i], a[i]) in the map
        Integer counterpartIdx = map.get(new Triple(b[i], a[i]));
        if (counterpartIdx == null || swapped[counterpartIdx]) {
            // No matching element to swap with – transformation impossible
            return false;
        }

        swapped[counterpartIdx] = true; // mark the partner as used
        swapCount++;

        // More than one swap required → not allowed
        if (swapCount > 1) {
            return false;
        }
    }

    // If we reach here, either zero or one swap is sufficient
    return true;
}

