private static int count(int[] a, int current, boolean sport, boolean contest, Map<Node, Integer> memo) {
		if (current == a.length) {
			return 0;
		}
		Node key = new Node(current, sport, contest);
		if (memo.containsKey(key)) {
			return memo.get(key);
		}
		int res = 0;
		switch (a[current]) {
		case 0:
			res = count(a, current + 1, false, false, memo) + 1;
			break;
		case 1:
			res = contest ? count(a, current + 1, false, false, memo) + 1 : count(a, current + 1, false, true, memo);
			break;
		case 2:
			res = sport ? count(a, current + 1, false, false, memo) + 1 : count(a, current + 1, true, false, memo);			
			break;
		case 3:
			if (sport && !contest) {
				res = count(a, current + 1, false, true, memo);
			} 
			if (!sport && contest) {
				res = count(a, current + 1, true, false, memo);	
			}
			if (!sport && !contest) {
				res = Math.min(count(a, current + 1, false, true, memo), count(a, current + 1, true, false, memo));
			}			
			break;
		}
		memo.put(key, res);
		return res;
	}

