    if (c == 'k' || c == 'K' || c == '.') {
        return;
    }

    int value = getPieceValue(c);
    if (value == 0) {
        return; // safety net for any future unsupported characters
    }

    if (Character.isUpperCase(c)) {
        w += value; // white piece
    } else {
        b += value; // black piece
    }
}

