/*---------------------------------------------------------------*/
/* Helper structures and methods                                 */
/*---------------------------------------------------------------*/

private static class MaxInfo {
    double max = -Double.MAX_VALUE;
    String exp = "";
}

/**
 * Evaluates every candidate expression, updating {@code maxInfo}
 * with the greatest value and its textual representation.
 */
private static void evaluateAll(double x, double y, double z,
                                boolean usePower, MaxInfo maxInfo) {

    // 1) x^y^z  (log form or power form)
    updateMax(computeXPowerYPowerZ(x, y, z, usePower), "x^y^z", maxInfo);
    // 2) x^z^y
    updateMax(computeXPowerZPowerY(x, y, z, usePower), "x^z^y", maxInfo);
    // 3) (x^y)^z
    updateMax(computePowXYTimesZ(x, y, z, usePower), "(x^y)^z", maxInfo);
    // 4) y^x^z
    updateMax(computeYPowerXPowerZ(x, y, z, usePower), "y^x^z", maxInfo);
    // 5) y^z^x
    updateMax(computeYPowerZPowerX(x, y, z, usePower), "y^z^x", maxInfo);
    // 6) (y^x)^z
    updateMax(computePowYXTimesZ(x, y, z, usePower), "(y^x)^z", maxInfo);
    // 7) z^x^y
    updateMax(computeZPowerXPowerY(x, y, z, usePower), "z^x^y", maxInfo);
    // 8) z^y^x
    updateMax(computeZPowerYPowerX(x, y, z, usePower), "z^y^x", maxInfo);
    // 9) (z^x)^y
    updateMax(computePowZXTimesY(x, y, z, usePower), "(z^x)^y", maxInfo);
}

/**
 * Updates {@code maxInfo} if {@code value} exceeds the current maximum.
 */
private static void updateMax(double value, String expr, MaxInfo maxInfo) {
    if (value > maxInfo.max) {
        maxInfo.max = value;
        maxInfo.exp = expr;
    }
}

/*---------------------------------------------------------------*/
/* Individual expression calculators (log‑form ↔ power‑form)    */
/*---------------------------------------------------------------*/

private static double computeXPowerYPowerZ(double x, double y, double z,
                                           boolean usePower) {
    if (usePower) {
        return Math.pow(x, Math.pow(y, z));
    }
    return z * Math.log10(y) + Math.log10(Math.log10(x));
}

private static double computeXPowerZPowerY(double x, double y, double z,
                                           boolean usePower) {
    if (usePower) {
        return Math.pow(x, Math.pow(z, y));
    }
    return y * Math.log10(z) + Math.log10(Math.log10(x));
}

private static double computePowXYTimesZ(double x, double y, double z,
                                         boolean usePower) {
    if (usePower) {
        return Math.pow(x, y * z);
    }
    return Math.log10(y * z * Math.log10(x));
}

private static double computeYPowerXPowerZ(double x, double y, double z,
                                           boolean usePower) {
    if (usePower) {
        return Math.pow(y, Math.pow(x, z));
    }
    return z * Math.log10(x) + Math.log10(Math.log10(y));
}

private static double computeYPowerZPowerX(double x, double y, double z,
                                           boolean usePower) {
    if (usePower) {
        return Math.pow(y, Math.pow(z, x));
    }
    return x * Math.log10(z) + Math.log10(Math.log10(y));
}

private static double computePowYXTimesZ(double x, double y, double z,
                                         boolean usePower) {
    if (usePower) {
        return Math.pow(y, x * z);
    }
    return Math.log10(x * z * Math.log10(y));
}

private static double computeZPowerXPowerY(double x, double y, double z,
                                           boolean usePower) {
    if (usePower) {
        return Math.pow(z, Math.pow(x, y));
    }
    return y * Math.log10(x) + Math.log10(Math.log10(z));
}

private static double computeZPowerYPowerX(double x, double y, double z,
                                           boolean usePower) {
    if (usePower) {
        return Math.pow(z, Math.pow(y, x));
    }
    return x * Math.log10(y) + Math.log10(Math.log10(z));
}

private static double computePowZXTimesY(double x, double y, double z,
                                         boolean usePower) {
    if (usePower) {
        return Math.pow(z, x * y);
    }
    return Math.log10(x * y * Math.log10(z));
}

