public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner();
    PrintWriter pw = new PrintWriter(System.out);

    int n = sc.nextInt();
    initAdjacency(n);

    int m = sc.nextInt();
    k = sc.nextInt();

    EdgeData edgeData = readEdges(sc, m);
    TreeSet<Integer> orderedSet = createOrderedSet();

    initialiseVertexData(n);
    update(orderedSet, edgeData.edgeHashSet);

    int[] answer = computeAnswers(edgeData.edges, orderedSet, edgeData.edgeHashSet);

    for (int ans : answer) {
        pw.println(ans);
    }

