    pw.close();
}

/* -------------------------------------------------------------
   Helper structures and methods
   ------------------------------------------------------------- */
private static class EdgeData {
    final int[][] edges;           // original edge list (0‑based)
    final HashSet<Long> edgeHashSet; // hash set used by the algorithm

    EdgeData(int[][] edges, HashSet<Long> edgeHashSet) {
        this.edges = edges;
        this.edgeHashSet = edgeHashSet;
    }
}

/** creates adjacency list array for *n* vertices */
private static void initAdjacency(int n) {
    adj = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        adj[i] = new ArrayList<>();
    }
    in = new boolean[n];
    going = new int[n];
}

/** reads *m* edges, builds adjacency, and returns both the edge list
    and the hash set used later on */
private static EdgeData readEdges(Scanner sc, int m) {
    int[][] edges = new int[m][2];
    HashSet<Long> hashSet = new HashSet<>();

    for (int i = 0; i < m; i++) {
        int u = sc.nextInt() - 1;
        int v = sc.nextInt() - 1;
        edges[i][0] = u;
        edges[i][1] = v;

        adj[u].add(v);
        adj[v].add(u);

        hashSet.add(hash(u, v));
    }
    return new EdgeData(edges, hashSet);
}

/** creates the TreeSet used to keep vertices ordered by their current degree */
private static TreeSet<Integer> createOrderedSet() {
    return new TreeSet<>((i, j) -> {
        if (going[i] != going[j]) {
            return Integer.compare(going[i], going[j]);
        }
        return Integer.compare(i, j);
    });
}

/** fills the *in* array with true and sets the initial degree for each vertex */
private static void initialiseVertexData(int n) {
    Arrays.fill(in, true);
    for (int i = 0; i < n; i++) {
        going[i] = adj[i].size();
    }
}

/** main processing loop – walks the edge list backwards, records the size of the set
    after each removal, and updates the data structures accordingly */
private static int[] computeAnswers(int[][] edges, TreeSet<Integer> set,
                                    HashSet<Long> edgeHashSet) {
    int m = edges.length;
    int[] ans = new int[m];

    for (int q = m - 1; q >= 0; q--) {
        ans[q] = set.size();

        int u = edges[q][0];
        int v = edges[q][1];

        if (in[u] && in[v]) {
            // update vertex *u*
            set.remove(u);
            going[u]--;
            set.add(u);

            // update vertex *v*
            set.remove(v);
            going[v]--;
            set.add(v);

            // remove the processed edge from the hash set
            edgeHashSet.remove(hash(u, v));
        }

        // re‑evaluate vertices that may have become “good”
        update(set, edgeHashSet);
    }
    return ans;
}

