public static void main(String[] args) {
    FS in = new FS();

    // read problem input
    readInput(in);

    // initial result = sum of squares
    long result = initialSum(ar);

    // current split count for each element (starts at 1)
    int[] cur = initCur(N);

    // delta[i] = gain when increasing split count of ar[i] from cur[i] to cur[i]+1
    long[] delta = initDelta(ar, cur);

    // optional debug output
    if (debug) System.out.println(cost(5, 1) + " " + cost(5, 2));

    // priority queue ordered by smallest delta (most beneficial split first)
    PriorityQueue<Integer> pq = buildPriorityQueue(delta);
    for (int i = 0; i < N; i++) {
        pq.add(i);
    }

    if (debug) System.out.println("CURRES = " + result + " HAVE + " + N);

    // keep splitting until we have exactly K pieces
    result = increaseResultUntilK(result, cur, delta, pq, K);

    out.println(result);
    out.close();
}

/* ---------- helper methods ---------- */

private static void readInput(FS in) {
    N = in.nextInt();
    K = in.nextInt();
    ar = new long[N];
    for (int i = 0; i < N; i++) {
        ar[i] = in.nextInt();
    }
}

private static long initialSum(long[] arr) {
    long sum = 0;
    for (long v : arr) {
        sum += v * v;
    }
    return sum;
}

private static int[] initCur(int size) {
    int[] cur = new int[size];
    Arrays.fill(cur, 1);
    return cur;
}

private static long[] initDelta(long[] values, int[] cur) {
    long[] delta = new long[values.length];
    for (int i = 0; i < values.length; i++) {
        delta[i] = delta(values[i], cur[i]); // cur[i] is 1 here
    }
    return delta;
}

private static PriorityQueue<Integer> buildPriorityQueue(long[] delta) {
    return new PriorityQueue<>((a, b) -> Long.compare(delta[a], delta[b]));
}

/**
 * Repeatedly picks the element whose next split yields the smallest increase (delta)
 * and applies the split until the total number of pieces reaches {@code targetK}.
 */
private static long increaseResultUntilK(long result,
                                         int[] cur,
                                         long[] delta,
                                         PriorityQueue<Integer> pq,
                                         int targetK) {
    int have = N; // current number of pieces
    while (have < targetK) {
        int id = pq.poll();          // element with minimal delta
        result += delta[id];         // add its contribution

        if (debug) System.out.println(" id = " + id + " del = " + delta[id]);

        have++;
        cur[id]++;                   // increase split count for this element
        delta[id] = delta(ar[id], cur[id]); // recompute its delta
        pq.add(id);                  // push back with updated priority
    }
    return result;
}

