public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    PrintWriter out = new PrintWriter(System.out);

    // ----- read and initialise graph -----
    readInput(sc);

    // ----- compute shortest paths from each start vertex -----
    int[] start = new int[n];
    for (int i = 0; i < n; i++) {
        start[i] = sc.nextInt() - 1;
    }
    int[][] dist = computeAllDistances(start);

    // ----- binary search the minimum feasible time -----
    int k = sc.nextInt();
    int answer = findMinimumTime(k, dist);

    out.println(answer);
    out.close();
}

/** Reads V, E, n, m and builds the undirected weighted adjacency list. */
private static void readInput(Scanner sc) {
    V = sc.nextInt();                 // number of vertices
    int E = sc.nextInt();             // number of edges
    n = sc.nextInt();                 // number of start vertices
    m = V;                            // (kept for compatibility with original code)
    // adjacency list for the original graph
    adjList = new ArrayList[V];
    for (int i = 0; i < V; i++) {
        adjList[i] = new ArrayList<>();
    }
    // read edges
    while (E-- > 0) {
        int u = sc.nextInt() - 1;
        int v = sc.nextInt() - 1;
        int t = sc.nextInt();
        adjList[u].add(new Edge(v, t));
        adjList[v].add(new Edge(u, t));
    }
}

/** Runs Dijkstra from each start vertex and returns a matrix dist[i][j] */
private static int[][] computeAllDistances(int[] start) {
    int[][] dist = new int[n][V];
    for (int i = 0; i < n; i++) {
        dist[i] = dijkstra(start[i]);
    }
    return dist;
}

/** Binary‑searches the smallest time `mid` such that at least `k` matches exist. */
private static int findMinimumTime(int k, int[][] dist) {
    int answer = -1;
    int lo = 0;
    int hi = (int) 2e6;               // upper bound used in the original solution

    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        buildAdjacencyForMid(mid, dist);          // prepares adjList2 for this mid

        if (hopcroftKarp() >= k) {                // enough matches → try smaller time
            answer = mid;
            hi = mid - 1;
        } else {                                   // not enough → need larger time
            lo = mid + 1;
        }
    }
    return answer;
}

/** Constructs the bipartite graph `adjList2` for a given time limit `mid`. */
private static void buildAdjacencyForMid(int mid, int[][] dist) {
    // adjList2 is indexed from 1..n on the left side, and 1..V on the right side
    adjList2 = new ArrayList[n + 1];
    for (int i = 1; i <= n; i++) {
        adjList2[i] = new ArrayList<>();
        for (int j = 1; j <= V; j++) {
            if (dist[i - 1][j - 1] <= mid) {
                adjList2[i].add(j);
            }
        }
    }
}

