public long nextLong() {
    // Guard clause for empty input
    if (!hasNext()) {
        throw new NoSuchElementException();
    }

    int c = nextNonSpaceByte();

    boolean minus = false;
    if (c == '-') {
        minus = true;
        c = readByte();
    }

    long value = parseUnsignedLong(c);
    return minus ? -value : value;
}

/** Skips whitespace and returns the first non‑space character. */
private int nextNonSpaceByte() {
    int ch = readByte();
    while (isSpaceChar(ch)) {
        ch = readByte();
    }
    return ch;
}

/** Reads consecutive digits starting with the supplied character
 *  and stops when a space character is encountered.
 *  Throws {@link InputMismatchException} if a non‑digit is found. */
private long parseUnsignedLong(int startChar) {
    long result = 0;
    int c = startChar;

    do {
        if (c < '0' || c > '9') {
            throw new InputMismatchException();
        }
        result = result * 10 + (c - '0');
        c = readByte();
    } while (!isSpaceChar(c));

    return result;
}

