static void updateTree(long[] tree, boolean[] update, int left, int right, int l, int r, long val, int pos) {
        if(l<=left && r>=right) {
            tree[pos] = val;
            update[pos] = true;
            return;
        }
        if(l>right || r<left) return;
        if(update[pos]) {
            if(pos*2 < tree.length && tree[pos*2] != 0) {tree[pos*2] = tree[pos]; update[pos*2] = true;}
            if(pos*2+1<tree.length && tree[pos*2+1] != 0) {tree[pos*2+1] = tree[pos]; update[pos*2+1] = true;}
            update[pos] = false;
        }
        updateTree(tree, update, left, (left+right)/2, l, r, val, pos*2);
        updateTree(tree, update, (left+right)/2+1, right, l, r, val, pos*2+1);
        tree[pos] = Math.max(tree[pos*2], tree[pos*2+1]);
    }

