/* ------------ 1. Input & basic initialisation ----------------- */
private void readInputAndInitialiseStructures() throws Exception {
    n = in.nextInt();
    m = in.nextInt();
    buses = new Bus[m];

    set = new TreeSet<>();
    set.add(0);
    set.add(n);

    for (int i = 0; i < m; i++) {
        int s = in.nextInt();
        int t = in.nextInt();
        buses[i] = new Bus(s, t);
        set.add(s);
        set.add(t);
    }
}

/* ------------ 2. Build position → compressed index map --------- */
private void buildPositionIndexMap() {
    int idx = 0;
    posMap = new HashMap<>();
    for (int p : set) {
        posMap.put(p, idx++);
    }
    index = idx;                     // total number of distinct positions
}

/* ------------ 3. Replace original positions with compressed ones */
private void remapBusEndpoints() {
    for (Bus b : buses) {
        b.s = posMap.get(b.s);
        b.t = posMap.get(b.t);
    }
}

/* ------------ 4. Sort buses by their (compressed) destination */
private void sortBusesByDestination() {
    Arrays.sort(buses, Comparator.comparingInt(bus -> bus.t));
}

/* ------------ 5. DP core – kept small and readable ------------- */
private void computeDpAndPrintResult() {
    int[] dp  = new int[index];
    int[] sum = new int[index + 1];

    dp[0]  = 1;
    sum[1] = 1;                       // sum[i] = dp[0] + … + dp[i‑1]

    for (int i = 1; i < index; i++) {
        int j = locateFirstBusEndingAt(i);
        if (j >= 0) {
            // move to the first bus that ends at i
            while (j > 0 && buses[j - 1].t == i) {
                j--;
            }
            // process every bus that ends at i
            while (j < m && buses[j].t == i) {
                dp[i] = add(dp[i], sum[i] - sum[buses[j].s]);
                j++;
            }
        }
        sum[i + 1] = add(sum[i], dp[i]);
    }

    System.out.println(dp[index - 1]);
}

/* ------------ 6. Helper: binary‑search for first bus ending at i - */
private int locateFirstBusEndingAt(int dest) {
    // a temporary Bus is only used for its .t field in the comparator
    return Arrays.binarySearch(
            buses,
            new Bus(-1, dest),
            Comparator.comparingInt(b -> b.t)
    );
}

