public int upperFirstBound(ArrayList<Integer> a, Integer x) {
    // Guard clauses for trivial situations
    if (a == null || a.isEmpty()) {
        return 0;                     // empty list → insert at position 0
    }
    if (a.get(0) > x) {
        return 0;                     // first element already greater than x
    }
    if (a.get(a.size() - 1) <= x) {
        return a.size();              // all elements ≤ x → insert after last
    }

    // Delegated binary‑search logic
    return findUpperBound(a, x, 0, a.size() - 1);
}

/**
 * Binary‑search helper that returns the index of the first element
 * greater than {@code x}.  It assumes {@code left} and {@code right}
 * delimit a non‑empty sub‑list where the answer is guaranteed to exist.
 */
private int findUpperBound(ArrayList<Integer> a, int x, int left, int right) {
    while (left <= right) {
        int mid = (left + right) >>> 1;   // unsigned shift avoids overflow
        int midVal = a.get(mid);

        if (midVal == x) {
            // If the element right after {@code mid} is greater, that's the bound
            if (mid + 1 < a.size() && a.get(mid + 1) > x) {
                return mid + 1;
            }
            // Otherwise continue searching to the right
            left = mid + 1;
        } else if (midVal < x) {
            left = mid + 1;                // bound must be to the right
        } else { // midVal > x
            // If the predecessor is ≤ x, {@code mid} is the first greater element
            if (mid - 1 >= 0 && a.get(mid - 1) <= x) {
                return mid;
            }
            right = mid - 1;               // bound is further left
        }
    }
    // When the loop exits, {@code left} is the insertion point (upper bound)
    return left;
}

