/* core algorithm – builds the dp table and returns the final count */
private static int computeResult(int[] data) {
    final int INF = 987654321;
    int n = data.length;

    int[] dp = new int[n + 1];
    Arrays.fill(dp, INF);
    dp[0] = data[0];                     // initialise first element

    for (int i = 1; i < n; i++) {
        int pos = findInsertPosition(dp, data[i], n);
        if (pos <= n) {
            dp[pos] = Math.min(data[i], dp[pos]);
        }
    }

    return countValidEntries(dp, INF);
}

/* binary‑search style helper that finds the position where value fits */
private static int findInsertPosition(int[] dp, int value, int size) {
    int lo = 0;
    int hi = size;
    while (hi > lo + 1) {
        int mid = (hi + lo) / 2;
        if (dp[mid] > value) {
            hi = mid;
        } else {
            lo = mid;
        }
    }
    if (dp[lo] < value) {
        lo++;
    }
    return lo;
}

/* counts how many entries in dp are different from the sentinel INF.
   The result is always at least 1, matching the original logic. */
private static int countValidEntries(int[] dp, int sentinel) {
    int count = 1; // dp[0] is always valid
    for (int i = 1; i < dp.length; i++) {
        if (dp[i] != sentinel) {
            count++;
        }
    }
    return count;
}

