/**
 * Calculates the total according to the original nested‑if logic.
 *
 * @param bits character array representing the binary string (most significant
 *             bit at index 0)
 * @return the computed total
 */
private static long calculateTotal(char[] bits) {
    long total = 0;
    int carry = 0;

    for (int i = bits.length - 1; i >= 0; i--) {
        char bit = bits[i];

        if (carry == 0) {
            if (bit == '1') {
                // In the original code a carry is set only when there are
                // more bits to the left; otherwise nothing is added.
                if (i > 0) {
                    carry = 1;
                    total += 2;
                }
            } else { // bit == '0'
                total++;
            }
        } else { // carry == 1
            if (bit == '0') {
                // carry stays 1, add 2 (same as original branch)
                total += 2;
            } else { // bit == '1'
                // carry stays 1, add 1
                total++;
            }
        }
    }

    return total;
}

