    }
}

/**
 * Calculates the total according to the original algorithm.
 *
 * @param binary the input string composed of '0' and '1'
 * @return the computed total
 */
private static long calculateTotal(String binary) {
    if (binary == null || binary.isEmpty()) {
        return 0L;
    }

    char[] bits = binary.toCharArray();
    int carry = 0;
    long total = 0L;

    for (int i = bits.length - 1; i >= 0; i--) {
        total += evaluateBit(bits[i], i, carry);
        carry = nextCarry(bits[i], i, carry);
    }
    return total;
}

/**
 * Determines how much the current bit contributes to the total.
 *
 * @param bit   the current character ('0' or '1')
 * @param index the position of the bit in the array (0 = most‑significant)
 * @param carry the carry flag coming from less‑significant bits
 * @return the amount to add to the total for this bit
 */
private static long evaluateBit(char bit, int index, int carry) {
    if (carry == 0) {
        // no carry coming in
        if (bit == '0') {
            return 1L;              // original: tot++
        } else { // bit == '1'
            return (index > 0) ? 2L : 0L; // original: tot+=2 only if not the most‑significant bit
        }
    } else {
        // carry == 1
        return (bit == '0') ? 2L : 1L; // original: tot+=2 for '0', tot++ for '1'
    }
}

/**
 * Computes the carry flag for the next iteration.
 *
 * @param bit          the current character ('0' or '1')
 * @param index        the position of the bit in the array
 * @param currentCarry the carry flag before processing this bit
 * @return the carry flag to be used for the next (more‑significant) bit
 */
private static int nextCarry(char bit, int index, int currentCarry) {
    if (currentCarry == 0) {
        // carry only becomes 1 when we see a '1' that is not the most‑significant bit
        return (bit == '1' && index > 0) ? 1 : 0;
    }
    // once carry is 1 it stays 1 for the remaining bits (original logic never resets it)
    return 1;
}

