private static Bounds computeBounds(Reader sc, int n) throws IOException {
    int x0 = -(int) 1e5;   // maximum lower bound for x
    int x1 =  (int) 1e5;   // minimum upper bound for x
    int y0 = -(int) 1e5;   // maximum lower bound for y
    int y1 =  (int) 1e5;   // minimum upper bound for y

    while (n-- > 0) {
        int x = sc.nextInt();
        int y = sc.nextInt();
        int[] a = new int[4];
        for (int i = 0; i < 4; i++) {
            a[i] = sc.nextInt();
        }

        if (a[0] == 0) x0 = Math.max(x0, x);   // x must be ≥ x0
        if (a[1] == 0) y1 = Math.min(y1, y);   // y must be ≤ y1
        if (a[2] == 0) x1 = Math.min(x1, x);   // x must be ≤ x1
        if (a[3] == 0) y0 = Math.max(y0, y);   // y must be ≥ y0
    }

