/**
 * Creates an array containing ten fresh {@link StringBuilder} instances.
 */
private static StringBuilder[] initialiseBuilders() {
    StringBuilder[] arr = new StringBuilder[10];
    for (int i = 0; i < arr.length; i++) {
        arr[i] = new StringBuilder();
    }
    return arr;
}

/**
 * Appends the character that belongs to the given index to the corresponding
 * {@link StringBuilder} and increments the associated counter.
 */
private static void appendCharAndIncrement(int idx,
                                           StringBuilder[] builders,
                                           char[] chars,
                                           long[] counts) {
    builders[idx].append(chars[idx]);
    counts[idx]++;
}

/**
 * Returns the product of all counters. A product of zero is returned when any
 * counter is still zero – this matches the original behaviour where the loop
 * terminates only after every counter has been incremented at least once.
 */
private static long product(long[] counts) {
    long prod = 1;
    for (long c : counts) {
        prod *= c;
        // early exit if product becomes 0 (any counter still 0)
        if (prod == 0) {
            return 0;
        }
    }
    return prod;
}

