/* Helper methods that isolate distinct logical responsibilities               */
/* -------------------------------------------------------------------------- */

/**
 * Calculates the numeric part of the answer (the part before the
 * trailing zeroes). The algorithm follows the original implementation
 * step‑by‑step, but the code is now easier to follow.
 */
private BigInteger computeBaseResult(String s) {
    BigInteger x = BigInteger.ONE;
    boolean firstIsLetter = false;
    Set<Character> distinctLetters = new HashSet<>();

    // first character handling
    char first = s.charAt(0);
    if (first == '?') {
        x = x.multiply(BigInteger.valueOf(9));
    }
    if (isUppercaseLetter(first)) {
        distinctLetters.add(first);
        firstIsLetter = true;
    }

    // analyse the rest of the string (letters only, '?' are counted elsewhere)
    for (int i = 1; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '?') {
            continue;               // will be dealt with as trailing zeroes
        }
        if (isUppercaseLetter(c)) {
            distinctLetters.add(c);
        }
    }

    // multiply by decreasing digits 10,9,8,...
    int multiplier = 10;
    for (int i = 0; i < distinctLetters.size(); i++) {
        x = x.multiply(BigInteger.valueOf(multiplier--));
    }

    // adjust when the first character was a letter (cannot be zero)
    if (firstIsLetter) {
        x = x.divide(BigInteger.valueOf(10)).multiply(BigInteger.valueOf(9));
    }

    return x;
}

/**
 * Counts the number of '?' characters that appear after the first
 * character. Each such '?' corresponds to one trailing zero in the
 * final output.
 */
private int countTrailingZeroes(String s) {
    int zeroes = 0;
    for (int i = 1; i < s.length(); i++) {
        if (s.charAt(i) == '?') {
            zeroes++;
        }
    }
    return zeroes;
}

/**
 * Utility to recognise uppercase letters used in the problem statement.
 */
private boolean isUppercaseLetter(char c) {
    return c >= 'A' && c <= 'Z';
}

