private ArrayList<Integer>[] buildAdjacencyList(int n, FastScanner fs, int m) {
    @SuppressWarnings("unchecked")
    ArrayList<Integer>[] adj = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        adj[i] = new ArrayList<>();
    }
    for (int i = 0; i < m; i++) {
        int u = fs.nextInt() - 1;
        int v = fs.nextInt() - 1;
        adj[u].add(v);
    }
    return adj;
}

private int computeResult(ArrayList<Integer>[] adj, int n) {
    int res = 0;
    int[] cnt = new int[n];
    for (int i = 0; i < n; i++) {
        Arrays.fill(cnt, 0);
        // count how many length‑2 paths i → u → v reach each v (v != i)
        for (int u : adj[i]) {
            for (int v : adj[u]) {
                if (v != i) {
                    cnt[v]++;
                }
            }
        }
        // each pair of distinct length‑2 paths to the same v forms a "rhombus"
        for (int j = 0; j < n; j++) {
            if (cnt[j] > 1) {
                res += cnt[j] * (cnt[j] - 1) / 2;
            }
        }
    }
    return res;
}

