/**
 * Builds the initial distance matrix. The formula is identical to the
 * original implementation; the nested loops are isolated for readability.
 */
private void computeDistanceMatrix() {
    distance = new int[N][N];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (i == j) {
                distance[i][j] = 0;
            } else {
                distance[i][j] = D * (Math.abs(x[i] - x[j]) + Math.abs(y[i] - y[j])) - a[i];
            }
        }
    }
}

/**
 * Executes the Floyd‑Warshall algorithm to obtain all‑pairs shortest paths.
 * The triple‑nested loop is kept intact; it is now its own method.
 */
private void applyFloydWarshall() {
    for (int k = 0; k < N; k++) {
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                distance[i][j] = Math.min(distance[i][j], distance[i][k] + distance[k][j]);
            }
        }
    }
}

/**
 * Prints the required answer – distance from node 0 to node N‑1.
 */
private void printResult() {
    out.println(distance[0][N - 1]);
}

