/** places the required sentinel values at the two ends of the array */
private static void initialiseSentinels(int[] a) {
    a[0] = -(int) 2e9;          // very small value
    a[a.length - 1] = -a[0];    // very large value (opposite sign)
}

/** reads the sequence and initialises the left/right counters to 1 */
private static void readInputAndResetCounters(int[] a, int[] l, int[] r, int n) throws IOException {
    for (int i = 1; i <= n; i++) {
        a[i] = nextInt();
        l[i] = 1;
        r[i] = 1;
    }
    // the extra positions are never used for real data but must be 0 for the later logic
    l[0] = r[0] = l[n + 1] = r[n + 1] = 0;
}

/** fills l[i] with the length of the increasing prefix ending at i */
private static void computeLeftLengths(int[] a, int[] l, int n) {
    for (int i = 1; i <= n; i++) {
        if (a[i] > a[i - 1]) {
            l[i] = l[i - 1] + 1;
        }
    }
}

/** fills r[i] with the length of the increasing suffix starting at i */
private static void computeRightLengths(int[] a, int[] r, int n) {
    for (int i = n; i >= 1; i--) {
        if (a[i + 1] > a[i]) {
            r[i] = r[i + 1] + 1;
        }
    }
}

/** evaluates all possible ways of removing at most one element
 *  and returns the longest strictly‑increasing subsequence length */
private static int computeMaximumLength(int[] a, int[] l, int[] r, int n) {
    int max = 1;   // at least one element is always possible

    // case 1 – remove the element at position i (if it creates a longer sequence)
    for (int i = 1; i <= n; i++) {
        if (a[i] > a[i - 1] && a[i] < a[i + 1]) {
            max = Math.max(max, l[i - 1] + r[i + 1] + 1);
        } else if (a[i + 1] > a[i - 1] + 1) {
            max = Math.max(max, l[i - 1] + r[i + 1] + 1);
        }
    }

    // case 2 – extend an increasing prefix by one extra element
    for (int i = 2; i <= n; i++) {
        max = Math.max(max, l[i - 1] + 1);
    }

    // case 3 – extend an increasing suffix by one extra element
    for (int i = 1; i <= n - 1; i++) {
        max = Math.max(max, r[i + 1] + 1);
    }

    return max;
}

