/* ------------------------------------------------------------------ */
/* Helper methods                                                    */
/* ------------------------------------------------------------------ */

private static void fillArrays(Scanner sc, int n, int w, int h,
                               int[][] origin, int[][] end) {
    for (int i = 0; i < n; i++) {
        int g = sc.nextInt();
        int p = sc.nextInt();
        int t = sc.nextInt();
        if (g == 1) {
            origin[i] = new int[] { i, p, -t };
            end[i]    = new int[] { p - t, p, h };
        } else if (g == 2) {
            origin[i] = new int[] { i, -t, p };
            end[i]    = new int[] { p - t, w, p };
        }
    }
}

private static void sortOrigin(int[][] origin) {
    Arrays.sort(origin, originComparator());
}

private static void sortEnd(int[][] end) {
    Arrays.sort(end, endComparator());
}

private static Comparator<int[]> originComparator() {
    return (a, b) -> {
        int sumA = a[1] + a[2];
        int sumB = b[1] + b[2];
        if (sumA != sumB) {
            return Integer.compare(sumA, sumB);
        }
        int diffA = a[1] - a[2];
        int diffB = b[1] - b[2];
        return Integer.compare(diffA, diffB);
    };
}

private static Comparator<int[]> endComparator() {
    return (a, b) -> {
        if (a[0] != b[0]) {
            return Integer.compare(a[0], b[0]);
        }
        int diffA = a[1] - a[2];
        int diffB = b[1] - b[2];
        return Integer.compare(diffA, diffB);
    };
}

private static int[][] buildResult(int[][] origin, int[][] end) {
    int n = origin.length;
    int[][] re = new int[n][2];
    for (int i = 0; i < n; i++) {
        int index = origin[i][0];
        re[index] = new int[] { end[i][1], end[i][2] };
    }
    return re;
}

