public void solve() {
    // ----- read input -----
    String ip = sc.nextLine();
    String[] tok = ip.split("[ ]+");
    int n = lineToInt(tok[0]);

    final int N_MAX = 100000;
    String[][] name = new String[N_MAX][2];
    int[] pmt = new int[N_MAX];

    for (int i = 0; i < n; i++) {
        ip = sc.nextLine();
        tok = ip.split("[ ]+");
        name[i][0] = tok[0];
        name[i][1] = tok[1];
    }

    ip = sc.nextLine();
    tok = ip.split("[ ]+");
    for (int i = 0; i < n; i++) {
        pmt[i] = lineToInt(tok[i]) - 1;          // convert to 0‑based index
    }

    // ----- main algorithm -----
    if (n == 0) {
        out.print("YES");
        out.flush();
        return;
    }

    // initialise the first “hand”
    String[] currentHand = new String[] { name[pmt[0]][0], name[pmt[0]][1] };

    for (int i = 1; i < n; i++) {
        currentHand = updateHand(currentHand, name[pmt[i]]);
        if (currentHand == null) {               // guard clause – early exit on failure
            out.print("NO");
            out.flush();
            return;
        }
    }

    out.print("YES");
    out.flush();
}

/**
 * Updates the two‑hand values according to the original comparison logic.
 *
 * @param hand  a two‑element array containing the current hand strings
 * @param pair  a two‑element array containing the next name pair
 * @return a two‑element array with the updated hand, or {@code null}
 *         if both candidates are rejected (i.e. the original code would
 *         have printed “NO”).
 */
private String[] updateHand(String[] hand, String[] pair) {
    String hand1 = hand[0];
    String hand2 = hand[1];

    String lhand1 = null;
    String lhand2 = null;

    if (pair[0].compareTo(hand1) > 0 || pair[0].compareTo(hand2) > 0) {
        lhand1 = pair[0];
    }
    if (pair[1].compareTo(hand1) > 0 || pair[1].compareTo(hand2) > 0) {
        lhand2 = pair[1];
    }

    // both candidates discarded → signal failure
    if (lhand1 == null && lhand2 == null) {
        return null;
    }

    // ensure both slots are filled (mirrors the original else‑if chain)
    if (lhand1 != null && lhand2 == null) {
        lhand2 = lhand1;
    } else if (lhand1 == null && lhand2 != null) {
        lhand1 = lhand2;
    }

    return new String[] { lhand1, lhand2 };
}

