    while (remaining-- > 0) {
        int u = scan.nextInt() - 1;
        int v = scan.nextInt() - 1;
        dsu.union(u, v);
    }
}

private static List<int[]> buildAdditionalEdges(int n, DSU dsu1, DSU dsu2) {
    List<int[]> result = new ArrayList<>(n * n);
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (dsu1.find(i) == dsu1.find(j) || dsu2.find(i) == dsu2.find(j)) {
                continue;
            }
            result.add(new int[]{i, j});
            dsu1.union(i, j);
            dsu2.union(i, j);
        }
    }
    return result;
}

