/* initialise a disjoint‑set forest where each vertex is its own root */
private static int[] initParents(int n) {
    int[] parent = new int[n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }
    return parent;
}

/* read *edgeCount* edges from the input and merge the corresponding sets */
private static void addEdges(int[] parent, int edgeCount) {
    while (edgeCount-- > 0) {
        int u = scan.nextInt() - 1;
        int v = scan.nextInt() - 1;
        parent[find(parent, u)] = find(parent, v);
    }
}

/* generate the maximal set of edges that can be added without creating a cycle
   in either of the two graphs */
private static List<int[]> computeAdditionalEdges(int n, int[] parent1, int[] parent2) {
    List<int[]> result = new ArrayList<>(n * n);
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (find(parent1, i) == find(parent1, j) ||
                find(parent2, i) == find(parent2, j)) {
                continue;                                   // guard clause – skip incompatible pair
            }
            result.add(new int[]{i, j});
            // merge the components in both forests
            parent1[find(parent1, i)] = find(parent1, j);
            parent2[find(parent2, i)] = find(parent2, j);
        }
    }
    return result;
}

