private static void printResult(List<int[]> edges) {
    System.out.println(edges.size());
    for (int[] e : edges) {
        System.out.println(e[0] + 1 + " " + (e[1] + 1));
    }
}

/* standard find with path compression – assumed to exist elsewhere */
private static int find(int[] parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

