/* -------------------------------------------------------------
 * Helper: read all input and prepare sorted index arrays
 * ------------------------------------------------------------- */
private static ProblemData readProblemData(BufferedReader reader) throws IOException {
    StringTokenizer st = new StringTokenizer(reader.readLine());
    int n = Integer.parseInt(st.nextToken());
    int req = Integer.parseInt(st.nextToken());

    int[] left = new int[n];
    int[] right = new int[n];
    int[] cost = new int[n];

    for (int i = 0; i < n; i++) {
        st = new StringTokenizer(reader.readLine());
        left[i] = Integer.parseInt(st.nextToken());
        right[i] = Integer.parseInt(st.nextToken());
        cost[i] = Integer.parseInt(st.nextToken());
    }

    Integer[] byLeft = new Integer[n];
    Integer[] byRight = new Integer[n];
    for (int i = 0; i < n; i++) {
        byLeft[i] = i;
        byRight[i] = i;
    }

    Arrays.sort(byLeft, (a, b) -> Integer.compare(left[a], left[b]));
    Arrays.sort(byRight, (a, b) -> Integer.compare(right[a], right[b]));

    return new ProblemData(n, req, left, right, cost, byLeft, byRight);
}

/* -------------------------------------------------------------
 * Core algorithm: find the cheapest pair of intervals whose
 * combined length equals 'req'.
 * ------------------------------------------------------------- */
private static int computeMinimalCost(ProblemData d) {
    TreeMap<Integer, Integer> bestCostByDuration = new TreeMap<>();
    int nextRightIdx = 0;
    int bestTotal = Integer.MAX_VALUE;

    for (int idx : d.byLeft) {
        int currentStart = d.left[idx];

        // move all intervals that end before currentStart into the map
        while (nextRightIdx < d.n && d.right[d.byRight[nextRightIdx]] < currentStart) {
            int finishedIdx = d.byRight[nextRightIdx++];
            int duration = d.right[finishedIdx] - d.left[finishedIdx] + 1;
            int c = d.cost[finishedIdx];
            bestCostByDuration.merge(duration, c, Math::min);
        }

        int needed = d.req - (d.right[idx] - d.left[idx] + 1);
        Integer partnerCost = bestCostByDuration.get(needed);
        if (partnerCost != null) {
            int total = partnerCost + d.cost[idx];
            if (total < bestTotal) {
                bestTotal = total;
            }
        }
    }

    return (bestTotal == Integer.MAX_VALUE) ? -1 : bestTotal;
}

