/* extracts the reversal logic */
private void reverseArray(long[] arr) {
    int n = arr.length;
    for (int i = 0; i < n / 2; i++) {
        long tmp = arr[i];
        arr[i] = arr[n - i - 1];
        arr[n - i - 1] = tmp;
    }
}

/* computes Σ |arr[i] – arr[i‑1]| for i = 1 … n‑1 */
private long totalAbsoluteDifference(long[] arr) {
    long sum = 0;
    for (int i = 1; i < arr.length; i++) {
        sum += Math.abs(arr[i] - arr[i - 1]);
    }
    return sum;
}

/* evaluates the result for each possible removal and returns the minimum */
private long findMinimalResultAfterRemovingOne(long[] arr, long fullSum) {
    long best = Long.MAX_VALUE;
    int n = arr.length;

    for (int i = 0; i < n; i++) {
        long prev = (i == 0) ? arr[i] : arr[i - 1];
        long next = (i == n - 1) ? arr[i] : arr[i + 1];

        long candidate = fullSum
                - Math.abs(arr[i] - prev)
                - Math.abs(arr[i] - next);

        if (i != 0 && i != n - 1) {
            candidate += Math.abs(prev - next);
        }

        best = Math.min(best, candidate);
    }
    return best;
}

