/** Extracted: parses one input line and updates the points map. */
private void processActionLine(String[] tokens, String me, Map<String, Integer> points) {
    String first = tokens[0];
    String second = tokens[tokens.length - 2];
    second = second.substring(0, second.length() - 2); // strip trailing characters
    char action = tokens[1].charAt(0);

    // ensure both players are present in the map
    points.putIfAbsent(first, 0);
    points.putIfAbsent(second, 0);

    // guard clause – ignore lines that do not involve the current user
    if (!first.equals(me) && !second.equals(me)) {
        return;
    }

    int delta = pointsDeltaFor(action);
    addPoints(points, first, delta);
    addPoints(points, second, delta);
}

/** Returns the number of points to add for a given action character. */
private int pointsDeltaFor(char action) {
    switch (action) {
        case 'p': return 15;
        case 'c': return 10;
        case 'l': return 5;
        default:  return 0;   // unknown action – no points
    }
}

/** Adds delta points to the specified player in the map. */
private void addPoints(Map<String, Integer> points, String player, int delta) {
    points.put(player, points.get(player) + delta);
}

/** Builds a sorted list of Person objects, excluding the current user. */
private List<Person> buildSortedPeopleList(Map<String, Integer> points, String me) {
    List<Person> people = new ArrayList<>();
    for (Map.Entry<String, Integer> entry : points.entrySet()) {
        if (!entry.getKey().equals(me)) {
            people.add(new Person(entry.getKey(), entry.getValue()));
        }
    }
    Collections.sort(people);
    return people;
}

