}

/** Parses a raw line of input into its constituent parts. */
private static ActionInfo parseActionLine(String line) {
    String[] parts = line.split(" ");
    String first = parts[0];
    // the opponent name is the token before the last one ("... vs X)"), remove trailing "):"
    String second = parts[parts.length - 2];
    second = second.substring(0, second.length() - 2);
    char actionChar = parts[1].charAt(0);
    return new ActionInfo(first, second, actionChar);
}

