private static void applyAction(Map<String, Integer> points, ActionInfo info) {
    int delta = pointsDelta(info.actionChar);
    points.put(info.first, points.get(info.first) + delta);
    points.put(info.second, points.get(info.second) + delta);
}

/** Maps an action character to its point contribution. */
private static int pointsDelta(char action) {
    switch (action) {
        case 'p': return 15; // "p" – e.g., "play"
        case 'c': return 10; // "c" – e.g., "call"
        case 'l': return 5;  // "l" – e.g., "lose"
        default:  return 0;  // should never happen with valid input
    }
}

