/** Executes the same transformation logic that was inside the original main method. */
private static void applyTransform(long[] arr, long[] k, long mod) {
    int n = arr.length;
    int m = k.length;

    long[] psum = prefixSum(k);
    int steps = n - m + 1;
    int it = Math.min(m, steps);               // number of elements that are handled by the “first” and “last” loops

    // ----- first part (left side) -----
    for (int i = 0; i < it; i++) {
        arr[i] = modAdd(arr[i], psum[i], mod);
    }

    // ----- last part (right side) -----
    for (int i = 0; i < it; i++) {
        long suffix = psum[m - 1] - ((m - 1 - i - 1 < 0) ? 0 : psum[m - 1 - i - 1]);
        arr[n - i - 1] = modAdd(arr[n - i - 1], suffix, mod);
    }

    // ----- middle part (the remaining window) -----
    int id = m - 2;                                 // index inside psum for the sliding window
    for (int i = n - it - 1; i >= it; i--) {
        if (it == m) {                              // whole psum is always added
            arr[i] = modAdd(arr[i], psum[m - 1], mod);
        } else {
            arr[i] = modAdd(arr[i], psum[id] - psum[id - steps], mod);
            id--;
        }
    }
}

/** Returns the prefix‑sum array of the supplied values. */
private static long[] prefixSum(long[] values) {
    long[] psum = new long[values.length];
    psum[0] = values[0];
    for (int i = 1; i < values.length; i++) {
        psum[i] = psum[i - 1] + values[i];
    }
    return psum;
}

/** Helper that adds two numbers under the same modulus, mirroring the original “(a%mod + b%mod) % mod”. */
private static long modAdd(long a, long b, long mod) {
    return ((a % mod) + (b % mod)) % mod;
}

