    for (int i = 0; i < dst.length; i++) {
        dst[i] = in.nextLong();
    }
}

/**
 * Builds a prefix‑sum array of {@code values}.
 */
private static long[] computePrefixSums(long[] values) {
    long[] ps = new long[values.length];
    if (values.length == 0) {
        return ps;
    }
    ps[0] = values[0];
    for (int i = 1; i < values.length; i++) {
        ps[i] = ps[i - 1] + values[i];
    }
    return ps;
}

/**
 * Updates the first {@code it} elements of {@code arr} using the
 * corresponding prefix‑sum values.
 */
private static void applyFirstUpdates(long[] arr, long[] psum, int it, long mod) {
    for (int i = 0; i < it; i++) {
        arr[i] = ((arr[i] % mod) + (psum[i] % mod)) % mod;
    }
}

/**
 * Updates the last {@code it} elements of {@code arr}.
 */
private static void applyLastUpdates(long[] arr, long[] psum, int it, int n, long mod) {
    for (int i = 0; i < it; i++) {
        long leftSum = psum[m - 1] - ((m - 1 - i - 1 < 0) ? 0 : psum[m - 1 - i - 1]);
        arr[n - i - 1] = ((arr[n - 1 - i] % mod) + (leftSum % mod)) % mod;
    }
}

/**
 * Updates the middle segment of {@code arr} (those indices that are not
 * handled by the first or last segment).
 */
private static void applyMiddleUpdates(long[] arr, long[] psum, int it, int steps, int n, int m, long mod) {
    int id = m - 2;                // points to the last usable prefix index
    for (int i = n - it - 1; i >= it; i--) {
        if (it == m) {
            // whole prefix is applied
            arr[i] = ((arr[i] % mod) + (psum[m - 1] % mod)) % mod;
        } else {
            // use a sliding window of size {@code steps} over the prefix sums
            long windowSum = psum[id] - psum[id - steps];
            arr[i] = ((arr[i] % mod) + (windowSum % mod)) % mod;
            id--;
        }
    }
}

