/* Guarded construction of the answer matrix */
private static int[][] buildAnswers(char[] a, int n) {
    if (n <= 0) {
        return new int[26][1];               // only column 0 is required
    }

    int[][] ans = new int[26][n + 1];
    for (char c = 'a'; c <= 'z'; c++) {
        for (int cur = 1; cur <= n; cur++) {
            ans[c - 'a'][cur] = computeMaxSegment(c, cur, a, n);
        }
    }
    return ans;
}

/* Extracted computation of the maximum segment length for a given character and allowance */
private static int computeMaxSegment(char target, int allowedRemovals, char[] a, int n) {
    int max = 0;
    int i = 0, j = 0, rem = allowedRemovals;

    while (i < n && j < n) {
        if (a[i] != target && rem == 0) {
            // skip a block of the target character
            while (j < n && a[j] == target) {
                j++;
            }
            j++;                // move past the first non‑target after the block
            rem = 1;            // we have “spent” one removal to delete the block
        }

        if (a[i] != target) {
            rem--;              // consume a removal for a non‑target character
        }

        int currentLength = i - j + 1;
        if (currentLength > max) {
            max = currentLength;
        }
        i++;
    }
    return max;
}

/* Guard‑clause‑driven query processing */
private static void processQueries(Scanner sc, PrintWriter out, int[][] ans) {
    int q = sc.nextInt();
    while (q-- > 0) {
        int rem = sc.nextInt();
        char c = sc.next().charAt(0);   // reads the character token
        out.println(ans[c - 'a'][rem]);
    }
}

public static void main(String[] args) throws Exception {
    Scanner sc = new Scanner(System.in);
    PrintWriter out = new PrintWriter(System.out);
