    char[] a = sc.next().toCharArray();

    // Pre‑compute answers for every letter and every possible removal count.
    int[][] ans = precomputeAnswers(a);

    int q = sc.nextInt();
    while (q-- > 0) {
        int rem = sc.nextInt();
        char c = sc.nextChar();
        out.println(ans[c - 'a'][rem]);
    }
    out.flush();
    out.close();
}

/**
 * Builds the full answer table.
 *
 * @param a the input character array
 * @return a 2‑dimensional array where ans[letter][rem] is the maximum segment length
 *         after removing at most {@code rem} characters that are NOT {@code letter}.
 */
private static int[][] precomputeAnswers(char[] a) {
    int n = a.length;
    int[][] ans = new int[26][n + 1];
    for (char c = 'a'; c <= 'z'; c++) {
        for (int cur = 1; cur <= n; cur++) {
            ans[c - 'a'][cur] = computeMaxSegment(c, cur, a);
        }
    }
    return ans;
}

/**
 * Calculates the longest contiguous segment length for a specific character
 * when up to {@code maxRemovals} non‑matching characters may be removed.
 *
 * @param target       the character we are focusing on
 * @param maxRemovals  maximum number of characters not equal to {@code target}
 *                     that may be removed
 * @param arr          the source character array
 * @return the maximal segment length according to the original algorithm
 */
private static int computeMaxSegment(char target, int maxRemovals, char[] arr) {
    int n = arr.length;
    int max = 0;
    int i = 0, j = 0, rem = maxRemovals;

    while (i < n && j < n) {
        if (arr[i] != target && rem == 0) {
            while (j < n && arr[j] == target) {
                j++;
            }
            j++;               // skip the first non‑target after the block of targets
            rem = 1;           // we have "freed" one removal slot
        }
        if (arr[i] != target) {
            rem--;
        }
        int currentLen = i - j + 1;
        if (currentLen > max) {
            max = currentLen;
        }
        i++;
    }
    return max;
}

