/** Runs the K‑step simulation, stopping early if every value already reaches N. */
private static void simulate(int[] a, int maxSteps) {
    int n = a.length;
    for (int step = 0; step < maxSteps; step++) {
        // Guard clause: stop when all elements are ≥ n
        if (allValuesAtLeast(a, n)) {
            break;
        }

        int[] imos = new int[n + 1];            // automatically filled with 0
        applyImos(a, imos);
        prefixSum(imos);
        copyBack(a, imos);
    }
}

/** Returns true if every element in the array is ≥ limit. */
private static boolean allValuesAtLeast(int[] arr, int limit) {
    for (int value : arr) {
        if (value < limit) {
            return false;
        }
    }
    return true;
}

/** Fills the imos difference array according to the current values of a. */
private static void applyImos(int[] a, int[] imos) {
    int n = a.length;
    for (int i = 0; i < n; i++) {
        int lower = Math.max(0, i - a[i]);
        int upper = Math.min(n - 1, i + a[i]);

        imos[lower] += 1;
        imos[upper + 1] -= 1;   // safe because imos length is n+1
    }
}

/** Converts the difference array into the actual counts (prefix sum). */
private static void prefixSum(int[] imos) {
    for (int i = 0; i < imos.length - 1; i++) {
        imos[i + 1] += imos[i];
    }
}

/** Writes the computed counts back into the original array. */
private static void copyBack(int[] a, int[] imos) {
    for (int i = 0; i < a.length; i++) {
        a[i] = imos[i];
    }
}

