/**
 * Finds the longest sub‑array that can be turned into all 1's by flipping at most {@code k}
 * zeroes to ones. Returns a {@link Window} describing that segment; if no such segment exists
 * the window has {@code start = -1} and {@code end = -1}.
 */
private static Window findLongestZeroWindow(int[] a, int k) {
    int n = a.length;
    int left = 0, right = 0;
    int zeroCount = 0;

    int bestStart = -1, bestEnd = -1, bestLength = 0;

    while (left < n && right < n) {
        // expand window while we have room for more zeroes
        while (right < n && zeroCount < k) {
            if (a[right] == 0) {
                zeroCount++;
            }
            right++;
        }
