/**
 * Creates a value‑to‑index map for the permutation {@code a}.
 */
private Map<Integer, Integer> buildPositionMap(int[] a) {
    Map<Integer, Integer> map = new HashMap<>(a.length);
    for (int i = 0; i < a.length; i++) {
        map.put(a[i], i);
    }
    return map;
}

/**
 * Determines whether there exists a previously processed position {@code j}
 * (distance multiple of {@code step}) such that {@code a[j] > step}
 * and that position already holds a winning marker (ans[j] == 1).
 *
 * @param step the current number being examined (also the jump distance)
 * @param pos  the position of {@code step} in the original array
 * @param a    the original array
 * @param ans  the array that stores the partial results (1 = B, -1 = A)
 * @return {@code true} if a winning neighbour exists, {@code false} otherwise
 */
private boolean hasHigherWinnerNeighbor(int step, int pos, int[] a, int[] ans) {
    // check to the left
    for (int j = pos - step; j >= 0; j -= step) {
        if (a[j] > step && ans[j] == 1) {
            return true;
        }
    }
    // check to the right
    for (int j = pos + step; j < a.length; j += step) {
        if (a[j] > step && ans[j] == 1) {
            return true;
        }
    }
    return false;
}

