    long[] ansc = computeCumulative(col, m, n, p, k); // columns

    long max = Long.MIN_VALUE;
    for (int i = 0; i <= k; i++) {
        long current = ansr[i] + ansc[k - i] - p * (long) i * (long) (k - i);
        if (current > max) {
            max = current;
        }
    }
    System.out.println(max);
}

/**
 * Reads the matrix values and fills the row‑ and column‑sum arrays.
 */
private static void populateSums(Scanner br, int n, int m, long[] row, long[] col) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            long v = br.nextLong();
            row[i] += v;
            col[j] += v;
        }
    }
}

/**
 * Computes the cumulative best sums after performing up to {@code k} selections
 * on the provided {@code sums} array.
 *
 * @param sums          the original sums (row sums or column sums)
 * @param primaryCount  number of rows (if processing rows) or columns (if processing columns)
 * @param otherCount    the opposite dimension size (columns count when rows are processed, vice‑versa)
 * @param p             the penalty value
 * @param k             number of operations to simulate
 * @return an array where result[i] is the total gain after i selections
 */
private static long[] computeCumulative(long[] sums, int primaryCount, int otherCount, long p, int k) {
    // max‑heap based on current sum values
    Queue<Integer> pq = new PriorityQueue<>(new Comparator<Integer>() {
        @Override
        public int compare(Integer i1, Integer i2) {
            if (sums[i1] < sums[i2]) return 1;
            if (sums[i1] > sums[i2]) return -1;
            return i2 - i1;                // deterministic tie‑break
        }
    });

    for (int i = 0; i < primaryCount; i++) {
        pq.add(i);
    }

    long[] cumulative = new long[k + 1]; // cumulative[0] stays 0
    for (int i = 1; i <= k; i++) {
        int idx = pq.poll();
        long currentSum = sums[idx];
        cumulative[i] = cumulative[i - 1] + currentSum;
        // apply penalty for the next round
        sums[idx] -= otherCount * p;
        pq.add(idx);
    }
    return cumulative;
}

