    Scanner sc = new Scanner(System.in);
    PrintWriter out = new PrintWriter(System.out);

    int n = sc.nextInt();
    char[] a = sc.next().toCharArray();

    if (hasInvalidInitialConditions(n, a) || !enforceEnds(a)) {
        out.println(":(");
        out.flush();
        return;
    }

    int opensNeeded = calculateOpensNeeded(n, a);
    fillQuestionMarks(a, opensNeeded);

    if (isValidParenthesisSequence(a)) {
        out.print(a);
    } else {
