}

/** Guard clause for the three quick‑fail checks described in the original code. */
private static boolean hasInvalidInitialConditions(int n, char[] a) {
    return n % 2 == 1 || a[0] == ')' || a[n - 1] == '(';
}

/** Forces the first and last characters to be '(' and ')' respectively (as the original did). */
private static boolean enforceEnds(char[] a) {
    // The original code unconditionally overwrote the ends after the quick‑fail test,
    // so we can safely do the same here.
    a[0] = '(';
    a[a.length - 1] = ')';
    return true;
}

/**
 * Calculates how many '(' still have to be placed.
 * After fixing the ends, we subtract the '(' already present.
 */
private static int calculateOpensNeeded(int n, char[] a) {
    int open = n / 2;                     // total '(' required in a balanced string
    for (char c : a) {
        if (c == '(') {
            open--;
        }
    }
    return open;                          // may be zero or positive
}

/**
 * Replaces each '?' with '(' while we still need openings,
 * otherwise with ')'.  Mirrors the original loop that used the
 * post‑decrement trick (open-- > 0).
 */
private static void fillQuestionMarks(char[] a, int opensNeeded) {
    for (int i = 0; i < a.length; i++) {
        if (a[i] == '?') {
            if (opensNeeded > 0) {
                a[i] = '(';
                opensNeeded--;
            } else {
                a[i] = ')';
            }
        }
    }
}

/**
 * Validates the final parenthesis sequence.
 * The sequence must never become “balanced” (open == 0) before the last
 * character, and must end balanced.
 */
private static boolean isValidParenthesisSequence(char[] a) {
    int open = 0;
    for (int i = 0; i < a.length; i++) {
        if (a[i] == '(') {
            open++;
        } else { // ')'
            if ((open == 1 && i == a.length - 1) || open > 1) {
                open--;
            } else {
                return false; // early failure, mirrors original behaviour
            }
        }
    }
    return open == 0;
}

