    // Guard clause for empty input
    if (n <= 0) {
        pw.println(0);
        pw.flush();
        return;
    }

    Pair[] pairs = readPairs(scan, n);
    int result = countDominatedPairs(pairs);
    pw.println(result);
    pw.flush();
}

/**
 * Reads {@code n} pairs from the supplied scanner.
 */
private static Pair[] readPairs(MyScanner scan, int n) {
    Pair[] arr = new Pair[n];
    for (int i = 0; i < n; i++) {
        arr[i] = new Pair(scan.nextInt(), scan.nextInt());
    }
    Arrays.sort(arr);
    return arr;
}

/**
 * Counts how many pairs (a,b) are **dominated** by a previously seen pair:
 * a larger than the smallest 'a' seen so far AND
 * b smaller than the smallest 'b' seen so far.
 *
 * The logic mirrors the original implementation but is expressed in
 * clear, linear steps.
 */
private static int countDominatedPairs(Pair[] arr) {
    int minA = arr[0].a;
    int minB = arr[0].b;
    int count = 0;
    int i = 1;

    while (i < arr.length) {
        // Skip over entries that share the same 'a' as the previous one
        while (i < arr.length && arr[i].a == arr[i - 1].a) {
            i++;
            if (i < arr.length && arr[i].a > minA && arr[i].b < minB) {
                count++;
            }
        }

        if (i >= arr.length) {
            break;
        }

        // Update the current minima if the previous element improves them
        if (arr[i - 1].b > minB) {
            minA = arr[i - 1].a;
            minB = arr[i - 1].b;
        }

        // Count the current element if it is dominated
        if (arr[i].a > minA && arr[i].b < minB) {
            count++;
        }

        i++;
    }

    return count;
}

