/**
 * Attempts to select exactly {@code k} problems that satisfy the constraints.
 *
 * @param k          the desired number of problems
 * @param pairs      array of problems sorted by the required order
 * @param totalTime  total time available
 * @return a list of problem indices if a feasible selection exists; otherwise {@code null}
 */
private List<Integer> tryBuildSolution(int k, Pair[] pairs, int totalTime) {
    if (k == 0) {
        return new ArrayList<>();
    }

    int remainingTime = totalTime;
    List<Integer> selected = new ArrayList<>(k);

    for (Pair p : pairs) {
        if (p.a >= k && remainingTime >= p.t) {
            remainingTime -= p.t;
            selected.add(p.index);
            if (selected.size() == k) {
                break;
            }
        }
    }

    return selected.size() == k ? selected : null;
}

