        int k = low + (high - low) / 2;
        List<Integer> candidate = selectProblems(pairs, k, T);

        if (candidate.size() >= k) {               // feasible
            best = k;
            answer = candidate;
            low = k + 1;                           // try to solve more
        } else {
            high = k - 1;                          // solve fewer
        }
    }

    out.println(best);
    out.println(answer.size());
    for (int idx : answer) {
        out.print(idx + " ");
    }
    out.println();
}

/** Reads the input pairs and attaches the original 1‑based index. */
private Pair[] readPairs(InputReader in, int n) {
    Pair[] result = new Pair[n];
    for (int i = 0; i < n; i++) {
        int a = in.nextInt();
        int t = in.nextInt();
        result[i] = new Pair(a, t, i + 1);
    }
    return result;
}

/**
 * Tries to select {@code k} problems whose difficulty (a) is at least {@code k}
 * and whose total required time does not exceed {@code totalTime}.
 *
 * @return list of selected problem indices (may be smaller than {@code k})
 */
private List<Integer> selectProblems(Pair[] sortedPairs, int k, int totalTime) {
    int remaining = totalTime;
    List<Integer> selected = new ArrayList<>();

    for (Pair p : sortedPairs) {
        if (selected.size() == k) {
            break;
        }
        if (p.a >= k && remaining >= p.t) {
            remaining -= p.t;
            selected.add(p.index);
        }
    }
    return selected;
}

