/**
 * Allocates and clears all global arrays needed for the algorithm.
 */
private static void initializeDataStructures(int n) {
    g = new int[2 * n + 1];
    G = new ArrayList[2 * n + 1];
    for (int i = 0; i < 2 * n + 1; i++) {
        G[i] = new ArrayList<>();
    }
    size = new long[2 * n + 1];
    v = new boolean[2 * n + 1];
    stay = new int[2 * n + 1];
}

/**
 * Reads the n pairs (a,b) and builds the directed graph together
 * with the degree counters used later.
 */
private static void readEdges(Scanner in, int n, int[][] deg) {
    for (int i = 0; i < n; i++) {
        int a = in.nextInt();
        int b = in.nextInt();
        deg[0][b]++;          // indegree of b
        deg[1][a]++;          // outdegree of a
        g[a] = b;             // simple edge a -> b
        G[b].add(a);          // reverse adjacency list for dfs
    }
}

/**
 * Runs the first DFS (dfsi) on every vertex that has not been marked yet.
 * This populates the {@code stay} array.
 */
private static void computeStayFlags() {
    for (int i = 0; i < stay.length; i++) {
        if (stay[i] == 0) {
            dfsi(i);
        }
    }
}

/**
 * Computes the product of the results of the second DFS (dfsii)
 * for all vertices that satisfy the required conditions.
 */
private static long computeAnswer(int[][] deg) {
    long ans = 1L;
    v = new boolean[stay.length];          // reset visited array
    for (int i = 0; i < stay.length; i++) {
        if (stay[i] == 1 && deg[1][i] == 0) {   // stay && out‑degree == 0
            ans = (ans * dfsii(i)) % mod;
        }
    }
    return ans;
}

/**
 * Calculates 2^cnt modulo {@code mod}. The original code performed this
 * with a simple loop; the same logic is kept but extracted for clarity.
 */
private static long computeTwoPower(int cnt) {
    long two = 1L;
    for (int i = 0; i < cnt; i++) {
        two = (two * 2) % mod;
    }
    return two;
}

