/**
 * Moves the cursor according to the command.
 * Guard clause for the left‑most bound is applied here.
 */
private int moveCursor(char cmd, int cursor) {
    if (cmd == 'L') {
        cursor--;
        if (cursor < 0) {
            cursor = 0;
        }
    } else if (cmd == 'R') {
        cursor++;
    }
    return cursor;
}

/**
 * Updates the segment‑tree node at the current cursor position.
 * The value written depends on the command:
 *   '+'  →  1
 *   '-'  → -1
 *   any other character → 0
 */
private void applyCommand(char cmd, int cursor, FastSegmentTree<EEditor.S> st) {
    if (cmd == '+') {
        st.value.init(1);
    } else if (cmd == '-') {
        st.value.init(-1);
    } else {
        st.value.init(0);
    }
    st.update(cursor);
}

/**
 * Evaluates the segment‑tree after a query.
 * Returns -1 if the sequence is invalid (non‑zero sum or negative minimum),
 * otherwise returns the maximum prefix sum.
 */
private int evaluateCurrentState(FastSegmentTree<EEditor.S> st) {
    if (st.value.sum[0] != 0 || st.value.min[0] < 0) {
        return -1;
    }
    return st.value.max[0];
}

