/**
 * Moves the cursor according to the command.
 * Guard clause ensures the cursor never becomes negative.
 */
private int moveCursor(int cursor, char cmd) {
    switch (cmd) {
        case 'L':
            cursor--;
            if (cursor < 0) {
                cursor = 0;
            }
            break;
        case 'R':
            cursor++;
            break;
        default:
            // No cursor movement for other commands
            break;
    }
    return cursor;
}

/**
 * Updates the segment tree based on the current command.
 */
private void updateSegmentTree(FastSegmentTree<EEditor.S> st, int position, char cmd) {
    switch (cmd) {
        case '+':
            st.value.init(1);
            break;
        case '-':
            st.value.init(-1);
            break;
        default:
            // Any character that is not L, R, +, or - is treated as a reset (0)
            st.value.init(0);
            break;
    }
    st.update(position);
}

/**
 * Evaluates the current state of the segment tree and returns the answer
 * for this step.
 */
private int evaluateSegmentTree(FastSegmentTree<EEditor.S> st) {
    if (st.value.sum[0] != 0 || st.value.min[0] < 0) {
        return -1;
    }
    return st.value.max[0];
}

