/**
 * Counts how many of the lowest {@code bits} bits differ between two integers.
 *
 * @param mask the first integer (e.g., a value from the input array)
 * @param x    the second integer (the reference value)
 * @param bits how many least‑significant bits to compare
 * @return the number of positions where the bits differ
 */
private int bitDifferenceCount(int mask, int x, int bits) {
    int diff = 0;
    for (int j = 0; j < bits; j++) {
        // A difference exists when the j‑th bits are not equal.
        if (((mask >> j) & 1) != ((x >> j) & 1)) {
            diff++;
        }
    }
    return diff;
}

