/* ------------------------------------------------------------------ */
/* Segment tree implementation                                          */
/* ------------------------------------------------------------------ */
private static class SegmentTree {
    int size;          // the power‑of‑two size used internally
    int[] tree;        // binary‑indexed tree storing the increment counts

    SegmentTree(int n) {
        size = 1;
        while (size <= n) {
            size <<= 1;
        }
        tree = new int[2 * size];
    }

    /** Increment the counter at logical index i (0‑based). */
    void increment(int i) {
        for (i += size; i > 0; i >>= 1) {
            tree[i]++;
        }
    }

    /** Return the position of the k‑th zero (1‑based k). */
    int getZeroPos(int k) {
        return getZeroPos(k, 1, 0, size);
    }

    private int getZeroPos(int k, int node, int left, int right) {
        if (right - left == 1) {
            return left;
        }
        int mid = (left + right) >>> 1;
        int zerosInLeft = (mid - left) - tree[node << 1];
        if (zerosInLeft >= k) {
            return getZeroPos(k, node << 1, left, mid);
        } else {
            return getZeroPos(k - zerosInLeft, (node << 1) + 1, mid, right);
        }
    }
}

