public int lowerBound(ArrayList<Integer> a, int x) {
    // Guard clauses for trivial cases
    if (a.isEmpty() || a.get(0) >= x) {
        return -1;                     // nothing is smaller than x
    }
    int lastIdx = a.size() - 1;
    if (a.get(lastIdx) < x) {
        return lastIdx;                // everything is smaller than x
    }

    return searchLowerBound(a, x, 0, lastIdx);
}

/**
 * Binary‑searches the array for the index of the greatest element that is
 * strictly less than {@code x}. The pre‑conditions guarantee that such an
 * element exists and that not all elements are smaller than {@code x}.
 */
private int searchLowerBound(ArrayList<Integer> a, int x, int left, int right) {
    while (left <= right) {
        int mid = (left + right) >>> 1;   // avoids overflow
        int midVal = a.get(mid);

        if (midVal == x) {
            // x is present; answer is the element just before it (if any)
            return (mid > 0 && a.get(mid - 1) < x) ? mid - 1 : mid - 1;
        }

        if (midVal > x) {
            // All candidates are left of mid
            right = mid - 1;
        } else { // midVal < x
            // If the element after mid is >= x, mid is the lower bound
            if (mid + 1 < a.size() && a.get(mid + 1) >= x) {
                return mid;
            }
            // Otherwise continue searching to the right
            left = mid + 1;
        }
    }
    // The loop always returns inside for the pre‑conditions, but we keep
    // a fallback to satisfy the compiler.
    return -1;
}

