/* ------------ helper methods ----------------------------------- */

private Point[] readPoints(InputReader sc, int n) {
    Point[] p = new Point[n];
    for (int i = 0; i < n; ++i) {
        p[i] = new Point(sc.nextInt(), sc.nextInt(),
                         sc.nextInt(), sc.nextInt());
    }
    return p;
}

/**
 * Returns an int[2] containing the x and y of a feasible point,
 * or null if no point satisfies the constraints.
 */
private int[] findIntersection(Point[] p) {
    int n = p.length;

    // prefix (p*) arrays
    int[] pminx = new int[n];
    int[] pmaxx = new int[n];
    int[] pminy = new int[n];
    int[] pmaxy = new int[n];
    computePrefix(p, pminx, pmaxx, pminy, pmaxy);

    // suffix (s*) arrays
    int[] sminx = new int[n];
    int[] smaxx = new int[n];
    int[] sminy = new int[n];
    int[] smaxy = new int[n];
    computeSuffix(p, sminx, smaxx, sminy, smaxy);

    // 1) use suffix starting at index 1
    if (isValidRange(sminx[1], smaxx[1], sminy[1], smaxy[1])) {
        return new int[]{sminx[1], sminy[1]};
    }

    // 2) use prefix up to index n‑2
    if (isValidRange(pminx[n - 2], pmaxx[n - 2],
                     pminy[n - 2], pmaxy[n - 2])) {
        return new int[]{pminx[n - 2], pminy[n - 2]};
    }

    // 3) try removing each intermediate rectangle i (1 … n‑2)
    for (int i = 1; i <= n - 2; ++i) {
        int minX = Math.max(sminx[i + 1], pminx[i - 1]);
        int maxX = Math.min(smaxx[i + 1], pmaxx[i - 1]);
        int minY = Math.max(sminy[i + 1], pminy[i - 1]);
        int maxY = Math.min(smaxy[i + 1], pmaxy[i - 1]);

        if (isValidRange(minX, maxX, minY, maxY)) {
            return new int[]{minX, minY};
        }
    }

    // no intersection found
    return null;
}

private void computePrefix(Point[] p,
                           int[] minX, int[] maxX,
                           int[] minY, int[] maxY) {
    minX[0] = p[0].x1;
    maxX[0] = p[0].x2;
    minY[0] = p[0].y1;
    maxY[0] = p[0].y2;

    for (int i = 1; i < p.length; ++i) {
        minX[i] = Math.max(minX[i - 1], p[i].x1);
        maxX[i] = Math.min(maxX[i - 1], p[i].x2);
        minY[i] = Math.max(minY[i - 1], p[i].y1);
        maxY[i] = Math.min(maxY[i - 1], p[i].y2);
    }
}

private void computeSuffix(Point[] p,
                           int[] minX, int[] maxX,
                           int[] minY, int[] maxY) {
    int n = p.length;
    minX[n - 1] = p[n - 1].x1;
    maxX[n - 1] = p[n - 1].x2;
    minY[n - 1] = p[n - 1].y1;
    maxY[n - 1] = p[n - 1].y2;

    for (int i = n - 2; i >= 0; --i) {
        minX[i] = Math.max(minX[i + 1], p[i].x1);
        maxX[i] = Math.min(maxX[i + 1], p[i].x2);
        minY[i] = Math.max(minY[i + 1], p[i].y1);
        maxY[i] = Math.min(maxY[i + 1], p[i].y2);
    }
}

/** Helper to check whether the computed interval is non‑empty. */
private boolean isValidRange(int minX, int maxX, int minY, int maxY) {
    return minX <= maxX && minY <= maxY;
}

