/** Returns the lexicographically smaller of the two strings. */
private String minString(String a, String b) {
    return a.compareTo(b) < 0 ? a : b;
}

/**
 * Chooses the next string for the sequence.
 *
 * @param lastStr the string that must be surpassed
 * @param entry   the current entry containing two candidate strings
 * @return the smallest candidate that is greater than {@code lastStr},
 *         or {@code null} if neither candidate satisfies the condition
 */
private String chooseNextString(String lastStr, TEntry entry) {
    boolean s1Greater = entry.s1.compareTo(lastStr) > 0;
    boolean s2Greater = entry.s2.compareTo(lastStr) > 0;

    // guard clause – no candidate is greater than the previous string
    if (!s1Greater && !s2Greater) {
        return null;
    }

    // both candidates are greater – pick the smaller one
    if (s1Greater && s2Greater) {
        return entry.s1.compareTo(entry.s2) < 0 ? entry.s1 : entry.s2;
    }

    // exactly one candidate is greater – return it
    return s1Greater ? entry.s1 : entry.s2;
}

