private void initializeIO() {
    br = new BufferedReader(new InputStreamReader(System.in));
    pw = new PrintWriter(new OutputStreamWriter(System.out));
}

/** reads the n pairs (s1,s2) */
private TEntry[] readInputEntries(int count) throws IOException {
    TEntry[] arr = new TEntry[count];
    for (int i = 0; i < count; i++) {
        TEntry e = new TEntry();
        e.s1 = nextToken();
        e.s2 = nextToken();
        arr[i] = e;
    }
    return arr;
}

/** builds the “entries” array according to the permutation that follows */
private TEntry[] mapEntries(int count, TEntry[] source) throws IOException {
    TEntry[] result = new TEntry[count];
    for (int i = 0; i < count; i++) {
        int zn = nextInt() - 1;              // input is 1‑based
        result[i] = source[zn];
    }
    return result;
}

/** core algorithm – determines whether a strictly increasing lexicographic
 *  sequence can be formed */
private boolean isSequencePossible(TEntry[] entries) {
    if (entries == null || entries.length == 0) {
        return true;                     // matches original behaviour for empty input
    }

    // initialise with the smaller string of the first entry
    String lastStr = smallerString(entries[0]);

    for (int i = 1; i < entries.length; i++) {
        String next = pickNextString(entries[i], lastStr);
        if (next == null) {
            return false;                // guard clause – early exit when impossible
        }
        lastStr = next;
    }
    return true;
}

/** returns the lexicographically smaller of s1 and s2 */
private String smallerString(TEntry e) {
    return e.s2.compareTo(e.s1) < 0 ? e.s2 : e.s1;
}

/** chooses the smallest string in the entry that is still greater than lastStr;
 *  returns null if none exists */
private String pickNextString(TEntry entry, String lastStr) {
    // try s1 first
    if (entry.s1.compareTo(lastStr) > 0) {
        String candidate = entry.s1;
        // if s2 lies between lastStr and candidate, prefer s2
        if (entry.s2.compareTo(lastStr) > 0 && entry.s2.compareTo(candidate) < 0) {
            candidate = entry.s2;
        }
        return candidate;
    }
    // s1 not suitable, try s2
    if (entry.s2.compareTo(lastStr) > 0) {
        return entry.s2;
    }
    // neither string can extend the sequence
    return null;
}

