/**
 * Finds all pairs (i, j) such that b[j] lies in the interval [a[i] - x, a[i] + y].
 * The indices added to the result lists are 1‑based, preserving the original method's output.
 */
private void matchArrays(int[] a, int[] b, int x, int y,
                         List<Integer> u, List<Integer> v) {
    int i = 0;
    int j = 0;
    while (i < a.length && j < b.length) {
        if (a[i] - x <= b[j] && b[j] <= a[i] + y) {
            // match found – store 1‑based positions
            u.add(i + 1);
            v.add(j + 1);
            i++;
            j++;
        } else if (b[j] > a[i] + y) {
            // b[j] is too large for current a[i]; move to next a[i]
            i++;
        } else {
            // b[j] is too small for current a[i]; move to next b[j]
            j++;
        }
    }
}

