private static List<int[]> collectMatches(int[] a, int[] b, int x, int y) {
    List<int[]> result = new ArrayList<>();
    int i = 0, j = 0;
    while (i < a.length && j < b.length) {
        // Guard clause for a matching pair
        if (a[i] - x <= b[j] && b[j] <= a[i] + y) {
            result.add(new int[]{i + 1, j + 1}); // store 1‑based indices
            i++;
            j++;
            continue;
        }
        // Guard clause: b[j] is too large, move forward in a
        if (b[j] > a[i] + y) {
            i++;
            continue;
        }
        // Guard clause: b[j] is too small, move forward in b
        j++;
    }
    return result;
}

