public void solve(int testNumber, InputReader in, PrintWriter out) {
    long x1 = in.ni(), y1 = in.ni(), x2 = in.ni(), y2 = in.ni();
    long n = in.ni();
    char[] moves = in.next().toCharArray();

    final long INF = (long) 2e18;
    long low = 0, high = INF;
    int iterations = 100;                       // enough for convergence

    while (iterations-- > 0) {
        long mid = (low + high) / 2;
        if (canReachInSteps(mid, x1, y1, x2, y2, n, moves)) {
            high = mid;
        } else {
            low = mid;
        }
    }

    if (high == INF) {
        out.println(-1);
    } else {
        out.println(high);
    }
}

/**
 * Returns true if the target point (x2, y2) can be reached from (x1, y1)
 * within the given number of steps {@code steps}.
 *
 * The {@code steps} are distributed as evenly as possible among the
 * {@code n} moves described by {@code moves}.  Each character in {@code moves}
 * denotes a direction: U (up), D (down), L (left), R (right).
 */
private boolean canReachInSteps(long steps, long x1, long y1,
                                long x2, long y2, long n, char[] moves) {
    long nx = x1;
    long ny = y1;

    for (int i = 0; i < n; i++) {
        long op = steps / n + (i < steps % n ? 1 : 0);
        switch (moves[i]) {
            case 'U' -> ny += op;
            case 'D' -> ny -= op;
            case 'L' -> nx -= op;
            default  -> nx += op; // 'R'
        }
    }

    long manhattan = Math.abs(nx - x2) + Math.abs(ny - y2);
    return manhattan <= steps;
}

