/**
 * Returns true if any element a[i] has the same parity as its index i.
 * This replicates the original check that caused an early “-1” output.
 */
private static boolean hasParityConflict(int[] a) {
    for (int i = 0; i < a.length; i++) {
        if (a[i] % 2 == i % 2) {
            return true;
        }
    }
    return false;
}

/**
 * Executes the series of swaps that were previously in the main method.
 * The method also records each swap position into the shared {@code answers} list.
 */
private static void performSwaps(int[] a, int n) {
    for (int biggerVal = n, smallerVal = n - 1, gotoPos = n - 1;
         biggerVal > 1;
         biggerVal -= 2, smallerVal -= 2, gotoPos -= 2) {

        swap(indof(biggerVal, a), a);
        swap(indof(smallerVal, a) - 1, a);
        swap(indof(smallerVal, a) + 1, a);
        swap(2, a);
        swap(gotoPos, a);
    }
}

/**
