 * Throws the same NullPointerException the original code used if the check fails.
 */
private static void verifyIdentityPermutation(int[] a) {
    for (int i = 0; i < a.length; i++) {
        if (a[i] != i + 1) {
            throw null;               // preserve original behaviour
        }
    }
