private static long candidateNeg2Pos3(List<Long> negAsc, List<Long> posDesc) {
    if (negAsc.size() < 2 || posDesc.size() < 3) return Long.MIN_VALUE;
    long a = negAsc.get(0);
    long b = negAsc.get(1);
    long p1 = posDesc.get(0);
    long p2 = posDesc.get(1);
    long p3 = posDesc.get(2);
