private static long candidateNeg4Pos1(List<Long> negAsc, List<Long> posDesc) {
    if (negAsc.size() < 4 || posDesc.isEmpty()) return Long.MIN_VALUE;
    long a = negAsc.get(0);
    long b = negAsc.get(1);
    long c = negAsc.get(2);
    long d = negAsc.get(3);
