/**
 * Returns the maximum product obtainable by selecting exactly five numbers
 * from the supplied positive and negative lists.
 * <p>
 * The method respects the original algorithm:
 * <ul>
 *   <li>use the three largest positives with the two most‑negative values,
 *   <li>use the largest positive with the four most‑negative values,
 *   <li>use the five largest positives,
 *   <li>if those do not give a non‑negative result, try the remaining
 *       combinations that involve the smallest positives and the
 *       negatives closest to zero.
 * </ul>
 *
 * @param pos  list of positive numbers (may be empty)
 * @param neg  list of negative numbers (may be empty)
 * @param zeroExists true if at least one zero was read
 * @return the best product (zero if it exists and no positive product can be formed)
 */
private long maxProductOfFive(List<Long> pos, List<Long> neg, boolean zeroExists) {
    // start with 0 when a zero is present, otherwise the smallest possible value
    long best = zeroExists ? 0L : Long.MIN_VALUE;

    // prepare the four orderings needed by the different cases
    List<Long> posDesc = new ArrayList<>(pos);
    posDesc.sort(Collections.reverseOrder());          // largest → smallest

    List<Long> posAsc = new ArrayList<>(pos);
    posAsc.sort(Long::compare);                        // smallest → largest

    List<Long> negAsc = new ArrayList<>(neg);
    negAsc.sort(Long::compare);                        // most negative → closest to zero

    List<Long> negDesc = new ArrayList<>(neg);
    negDesc.sort(Collections.reverseOrder());          // closest to zero (largest) → most negative

    // ----- first phase (original ordering) -----
    best = Math.max(best, productCase1(posDesc, negAsc));
    best = Math.max(best, productCase2(posDesc, negAsc));
    best = Math.max(best, productCase3(posDesc));

    // ----- second phase (re‑ordered lists) -----
    best = Math.max(best, productCase4(posAsc, negDesc));
    best = Math.max(best, productCase5(posAsc, negDesc));
    best = Math.max(best, productCase6(negDesc));

    return best;
}

/* case 1: 2 most negative + 3 largest positives */
private long productCase1(List<Long> posDesc, List<Long> negAsc) {
    if (negAsc.size() >= 2 && posDesc.size() >= 3) {
        return mul(negAsc.get(0), negAsc.get(1), posDesc.get(0), posDesc.get(1), posDesc.get(2));
    }
    return Long.MIN_VALUE;
}

/* case 2: 4 most negative + 1 largest positive */
private long productCase2(List<Long> posDesc, List<Long> negAsc) {
    if (negAsc.size() >= 4 && posDesc.size() >= 1) {
        return mul(negAsc.get(0), negAsc.get(1), negAsc.get(2), negAsc.get(3), posDesc.get(0));
    }
    return Long.MIN_VALUE;
}

/* case 3: five largest positives */
private long productCase3(List<Long> posDesc) {
    if (posDesc.size() >= 5) {
        return mul(posDesc.get(0), posDesc.get(1), posDesc.get(2), posDesc.get(3), posDesc.get(4));
    }
    return Long.MIN_VALUE;
}

/* case 4: 1 negative (closest to zero) + 4 smallest positives */
private long productCase4(List<Long> posAsc, List<Long> negDesc) {
    if (negDesc.size() >= 1 && posAsc.size() >= 4) {
        return mul(negDesc.get(0), posAsc.get(0), posAsc.get(1), posAsc.get(2), posAsc.get(3));
    }
    return Long.MIN_VALUE;
}

/* case 5: 3 negatives (closest to zero) + 2 smallest positives */
private long productCase5(List<Long> posAsc, List<Long> negDesc) {
    if (negDesc.size() >= 3 && posAsc.size() >= 2) {
        return mul(negDesc.get(0), negDesc.get(1), negDesc.get(2), posAsc.get(0), posAsc.get(1));
    }
    return Long.MIN_VALUE;
}

/* case 6: five negatives (closest to zero) */
private long productCase6(List<Long> negDesc) {
    if (negDesc.size() >= 5) {
        return mul(negDesc.get(0), negDesc.get(1), negDesc.get(2), negDesc.get(3), negDesc.get(4));
    }
    return Long.MIN_VALUE;
}

/* helper that multiplies exactly five long values */
private long mul(long a, long b, long c, long d, long e) {
    return a * b * c * d * e;
}

