/** Reads {@code n} integers from the scanner and returns them as an array. */
private static int[] readArray(int n) {
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = in.nextInt();
    }
    return arr;
}

/** Builds a prefix‑sum array where {@code even[i]} holds the number of even
 *  elements in {@code a[0..i]} (inclusive). */
private static int[] computeEvenPrefix(int[] a) {
    int[] even = new int[a.length];
    for (int i = 0; i < a.length; i++) {
        even[i] = (a[i] % 2 == 0 ? 1 : 0) + (i > 0 ? even[i - 1] : 0);
    }
    return even;
}

/** Core DP algorithm extracted from the original {@code main}.
 *  The method keeps the exact behaviour while reducing nesting and clarifying
 *  the distinct logical steps. */
private static long[][] computeDP(int budget, int[] a, int[] evenPrefix) {
    int n = a.length;
    long[][] dp = new long[budget + 1][n + 1];

    for (int i = 1; i <= budget; i++) {
        for (int j = 2; j < n; j++) {
            // propagate the best value seen so far
            dp[i][j] = Math.max(dp[i][j], Math.max(dp[i - 1][j], dp[i][j - 1]));

            if (!isEvenIndex(j)) {
                continue;                         // guard: only even indices can form a pair
            }
            if (!hasSufficientEvenCount(j, evenPrefix)) {
                continue;                         // guard: the prefix must contain exactly j/2 evens
            }

            int diff = Math.abs(a[j] - a[j - 1]);
            if (i >= diff) {                     // guard: enough budget to pay the cost
                dp[i][j] = Math.max(dp[i][j], 1 + dp[i - diff][j - 1]);
            }
        }
    }
    return dp;
}

/** Returns {@code true} if {@code j} is an even index (i.e. {@code j % 2 == 0}). */
private static boolean isEvenIndex(int j) {
    return j % 2 == 0;
}

/** Checks whether the number of even elements up to {@code j‑1} equals {@code j/2}. */
private static boolean hasSufficientEvenCount(int j, int[] evenPrefix) {
    // {@code evenPrefix[j‑1]} is the count of evens in a[0..j‑1]
    return evenPrefix[j - 1] == j / 2;
}

