/** No direct move from x to y and neither edge (1 or n) can be used as an intermediate step. */
private boolean cannotReachDirectly(long x, long y, long n, long d) {
    return Math.abs(x - y) % d != 0 &&
           (y - 1) % d != 0 &&
           (n - y) % d != 0;
}

/** x can reach y directly in steps of size d. */
private boolean directReachable(long x, long y, long d) {
    return Math.abs(x - y) % d == 0;
}

/** y can be reached from the left edge (position 1) using steps of size d. */
private boolean leftEndReachable(long y, long d) {
    return (y - 1) % d == 0;
}

/** y can be reached from the right edge (position n) using steps of size d. */
private boolean rightEndReachable(long y, long n, long d) {
    return (n - y) % d == 0;
}

