/** Returns true if a segment that should be off in the target digit is currently on,
 *  which makes the transformation impossible. */
private static boolean isInvalidSegment(char targetSegment, char currentSegment) {
    return targetSegment == '0' && currentSegment == '1';
}

/** Returns true if a segment that should be on in the target digit is currently off,
 *  meaning we need to turn it on (cost increases). */
private static boolean isSegmentToTurnOn(char targetSegment, char currentSegment) {
    return targetSegment == '1' && currentSegment == '0';
}

/** Returns true if the transition cost p can be used without exceeding the total limit k. */
private static boolean canReachWithCost(int p, int remaining, int maxK) {
    return p != -1 && remaining + p <= maxK;
}

/** Returns true if a digit can be chosen at position i given the remaining budget
 *  and the DP table. */
private static boolean canSelectDigit(int digitCost, int remainingK, int index, boolean[][] dp) {
    return digitCost != -1 && digitCost <= remainingK && dp[index + 1][remainingK - digitCost];
}

