                    cost[i][digit] = -1;
                    break;
                }
                if (requiresTurnOn(DIGITS[digit][pos], x[pos])) {
                    cost[i][digit]++;
                }
            }
        }
    }

    boolean[][] dp = new boolean[n + 1][k + 1];
    dp[n][0] = true;
    for (int idx = n; idx > 0; idx--) {
        for (int remaining = 0; remaining <= k; remaining++) {
            if (dp[idx][remaining]) {
                for (int digit = 0; digit < 10; digit++) {
                    int p = cost[idx - 1][digit];
                    if (p != -1 && remaining + p <= k) {
                        dp[idx - 1][remaining + p] = true;
                    }
                }
            }
        }
    }

    if (!dp[0][k]) {
        out.println(-1);
        return;
    }

    for (int i = 0; i < n; i++) {
        int chosenDigit = -1;
        for (int d = 9; d >= 0; d--) {
            if (canSelectDigit(cost, i, d, k, dp)) {
                k -= cost[i][d];
                chosenDigit = d;
                break;
            }
        }
        out.print(chosenDigit);
    }
}

/** Returns true if a segment that should be '0' is currently '1' – such a transition is impossible. */
private static boolean isTurnOffImpossible(char needed, char current) {
    return needed == '0' && current == '1';
}

/** Returns true if a segment that should be '1' is currently '0' – this requires turning the segment on. */
private static boolean requiresTurnOn(char needed, char current) {
    return needed == '1' && current == '0';
}

/** Determines whether a digit can be chosen at position `pos` given the remaining budget `kRemaining`. */
private static boolean canSelectDigit(int[][] cost, int pos, int digit, int kRemaining, boolean[][] dp) {
    int c = cost[pos][digit];
    return c != -1 && c <= kRemaining && dp[pos + 1][kRemaining - c];
}

