/**
 * Returns true if the cell (i, j) lies on the border of the matrix.
 */
private static boolean isBorderCell(int i, int j, int n, int m) {
    return i == 0 || j == 0 || i == n - 1 || j == m - 1;
}

/**
 * Checks whether accessing the three cells directly above (i, j) would go
 * out of the matrix bounds.
 */
private static boolean isAboveRowOutOfBounds(int i, int j, int m) {
    return (i - 1) < 0 || (j - 1) < 0 || (j + 1) >= m;
}

/**
 * Returns true if the three cells directly above (i, j) all contain the same
 * character as the current cell.
 */
private static boolean areThreeAboveEqual(char[][] a, int i, int j, char current) {
    return current == a[i - 1][j - 1]
            && current == a[i - 1][j]
            && current == a[i - 1][j + 1];
}

/**
 * Determines whether the character at position (i, j) is equal to the character
 * located 2 * num rows above in the same column, and that the index is valid.
 */
private static boolean hasSameCharAtUpper(int i, int j, long num, char[][] a) {
    int upperRow = i - (int) (2L * num);
    return upperRow >= 0 && a[upperRow][j] == a[i][j];
}

