/**
 * Checks whether a left/right horizontal move from (originRow, originCol) to (row, col)
 * stays within the allowed distance {@code k} and lands on a walkable cell.
 */
private static boolean isValidHorizontalStep(int row, int col, int originCol, int k, char[][] map) {
    return col >= originCol - k && map[row][col] == '.';
}

/**
 * Checks whether a rightward horizontal move from (originRow, originCol) to (row, col)
 * stays within the allowed distance {@code k} and lands on a walkable cell.
 */
private static boolean isValidHorizontalStepRight(int row, int col, int originCol, int k, char[][] map) {
    return col <= originCol + k && map[row][col] == '.';
}

/**
 * Checks whether an upward vertical move from (originRow, originCol) to (row, col)
 * stays within the allowed distance {@code k} and lands on a walkable cell.
 */
private static boolean isValidVerticalStep(int row, int col, int originRow, int k, char[][] map) {
    return row >= originRow - k && map[row][col] == '.';
}

/**
 * Checks whether a downward vertical move from (originRow, originCol) to (row, col)
 * stays within the allowed distance {@code k} and lands on a walkable cell.
 */
private static boolean isValidVerticalStepDown(int row, int col, int originRow, int k, char[][] map) {
    return row <= originRow + k && map[row][col] == '.';
}

