/**
 * Returns true if the given string {@code s} matches {@code p} either
 * directly or in reversed order.
 */
private boolean matchesPattern(String p, String s) {
    return (p.charAt(0) == s.charAt(0) && p.charAt(1) == s.charAt(1))
        || (p.charAt(0) == s.charAt(1) && p.charAt(1) == s.charAt(0));
}

/**
 * Returns true if a pattern {@code p} can be built by taking one character
 * from {@code s1} and the other from {@code s2} (order matters).
 */
private boolean canFormPatternFromTwo(String p, String s1, String s2) {
    return (s1.charAt(0) == p.charAt(1) && s2.charAt(1) == p.charAt(0))
        || (s1.charAt(1) == p.charAt(0) && s2.charAt(0) == p.charAt(1));
