/** Returns true if the square (i, j) is on the same rank/file as the rook
 *  or occupied by the knight – i.e. it cannot be used as a candidate square. */
private boolean isInvalidPosition(int i, int j, IntIntPair rook, IntIntPair knight) {
    return i == rook.first || j == rook.second || new IntIntPair(i, j).equals(knight);
