/**
 * Returns true if the cell (i,j) is either on the same row or column as the rook,
 * or coincides with the knight's current position.
 */
private boolean isForbiddenCell(int i, int j, IntIntPair rook, IntIntPair knight) {
    return i == rook.first || j == rook.second || new IntIntPair(i, j).equals(knight);
}

/**
 * Checks whether the cell (i,j) is safe:
 * - it is not reachable by the knight in one move,
 * - the rook cannot capture it in one move.
 */
private boolean isSafePosition(int i, int j, IntIntPair rook, IntIntPair knight,
                               int[] dX, int[] dY) {
    // not reachable by the knight
    for (int k = 0; k < 8; k++) {
        if (new IntIntPair(i, j)
                .equals(new IntIntPair(knight.first + dX[k], knight.second + dY[k]))) {
            return false;
        }
    }
    // not capturable by the rook in one move
    for (int k = 0; k < 8; k++) {
        if (new IntIntPair(i + dX[k], j + dY[k]).equals(rook)) {
            return false;
        }
    }
    return true;
}

