/**
 * Tries to parse a date that starts at position {@code i} in {@code input}.
 * Returns a {@link Date} object if the substring represents a valid date
 * (format DD-MM-YYYY, day/month limits, year between 2013 and 2015);
 * otherwise returns {@code null}.
 */
private Date tryParseDate(char[] input, int i, int[] days) {
    // DD
    if (!Character.isDigit(input[i]) || !Character.isDigit(input[i + 1])) {
        return null;
    }
    int day = Character.getNumericValue(input[i]) * 10 + Character.getNumericValue(input[i + 1]);

    // '-'
    if (input[i + 2] != '-') {
        return null;
    }

    // MM
    if (!Character.isDigit(input[i + 3]) || !Character.isDigit(input[i + 4])) {
        return null;
    }
    int month = Character.getNumericValue(input[i + 3]) * 10 + Character.getNumericValue(input[i + 4]);
    if (month <= 0 || month > 12) {
        return null;
    }
    if (day <= 0 || day > days[month - 1]) {
        return null;
    }

    // '-'
    if (input[i + 5] != '-') {
        return null;
    }

    // YYYY
    if (!Character.isDigit(input[i + 6]) || !Character.isDigit(input[i + 7])
            || !Character.isDigit(input[i + 8]) || !Character.isDigit(input[i + 9])) {
        return null;
    }
    int year = Character.getNumericValue(input[i + 6]) * 1000
            + Character.getNumericValue(input[i + 7]) * 100
            + Character.getNumericValue(input[i + 8]) * 10
            + Character.getNumericValue(input[i + 9]);
    if (year < 2013 || year > 2015) {
        return null;
    }

    return new Date(day, month, year);
}

