private boolean hashesMatch(int l1, int l2, int l3) {
    return hashMatchesMod(pref1, pow1, mod1, l1, l2, l3) &&
           hashMatchesMod(pref2, pow2, mod2, l1, l2, l3);
}

/** Compute the rolling‑hash condition for a single modulo. */
private boolean hashMatchesMod(long[] pref, long[] pow, long mod,
                               int l1, int l2, int l3) {
    long v1 = pref[l1];

    long tmp = pref[l1] * pow[l2] % mod;
    long v2 = pref[l1 + l2] - tmp;
    if (v2 < 0) {
        v2 += mod;
    }

    tmp = pref[l1 + l2] * pow[l3] % mod;
    long v3 = pref[n] - tmp;
    if (v3 < 0) {
        v3 += mod;
    }

    return (v1 + v2) % mod == v3;
}

