private CUncleBogdanAndCountryHappiness.pair dfs(int[] people, int[] happiness, int curr, HashMap<Integer, ArrayList<Integer>> tree, int par, int[] peopleInSubtree) {
            ArrayList<Integer> children = tree.getOrDefault(curr, new ArrayList<>());
            int peopleInCurr = peopleInSubtree[curr];
            if ((peopleInCurr + happiness[curr]) % 2 != 0) {
                return new CUncleBogdanAndCountryHappiness.pair(0, 0, false);
            }

            int happy = (peopleInCurr + happiness[curr]) / 2;
            int unhappy = peopleInCurr - happy;

            if (happy < 0 || unhappy < 0 || (peopleInCurr + happiness[curr]) % 2 != 0) {
                return new CUncleBogdanAndCountryHappiness.pair(0, 0, false);
            }

            int happyBelow = 0;
            int unHappyBelow = 0;
            for (Integer child : children) {
                if (par != child) {
                    CUncleBogdanAndCountryHappiness.pair p = dfs(people, happiness, child, tree, curr, peopleInSubtree);
                    if (p.happy > happy || !p.okBelow) {
                        return new CUncleBogdanAndCountryHappiness.pair(0, 0, false);
                    }

                    happyBelow += p.happy;
                    unHappyBelow += p.unhappy;
                }
            }

            if (happy < happyBelow) {
                return new CUncleBogdanAndCountryHappiness.pair(0, 0, false);
            }

            return new CUncleBogdanAndCountryHappiness.pair(happy, unhappy, true);
        }

