private static boolean canAdvance(char[][] field, int row, int col, int dRow) {
    int newRow = row + dRow;
    return newRow >= 0 && newRow < ROWS
            && field[newRow][col + 1] == EMPTY
            && field[newRow][col + 2] == EMPTY
            && field[newRow][col + 3] == EMPTY;
}

