public static int restaurant(int a, int b, int c) {
    int ans = 0;

    // consume one from each positive pile
    if (isPositive(a)) { a--; ans++; }
    if (isPositive(b)) { b--; ans++; }
    if (isPositive(c)) { c--; ans++; }

    int highest = Math.max(a, Math.max(b, c));

    // handle the case where a is the (or one of the) highest pile(s)
    if (isHighest(a, highest)) {
        if (bothPositive(a, b)) { a--; b--; ans++; }
        if (bothPositive(a, c)) { a--; c--; ans++; }
        if (bothPositive(c, b)) { c--; b--; ans++; }
    }

    // handle the case where b is the (or one of the) highest pile(s)
    if (isHighest(b, highest)) {
        if (bothPositive(c, b)) { c--; b--; ans++; }
        if (bothPositive(a, b)) { a--; b--; ans++; }
        if (bothPositive(c, a)) { c--; a--; ans++; }
    }

    // handle the case where c is the (or one of the) highest pile(s)
    if (isHighest(c, highest)) {
        if (bothPositive(c, b)) { c--; b--; ans++; }
        if (bothPositive(a, c)) { a--; c--; ans++; }
        if (bothPositive(a, b)) { a--; b--; ans++; }
    }

    // finally, if all three piles still have items, consume one from each
    if (allPositive(a, b, c)) {
        a--; b--; c--; ans++;
    }

    return ans;
}

