/**
 * Determines whether the current segment of consecutive 'a's should be
 * terminated and added to the answer list.
 *
 * @param curAAmount   number of consecutive 'a' characters seen so far
 * @param currentChar  the character at the current index
 * @param index        current loop index
 * @param totalLength  total length of the filtered char array
 * @return true if we have reached the end of a segment, false otherwise
 */
private boolean shouldFlushSegment(int curAAmount, char currentChar, int index, int totalLength) {
    // Flush when we have at least one 'a' followed by a 'b',
    // or when we are at the last character of the array.
    return (curAAmount != 0 && currentChar == 'b') || index == totalLength - 1;
}

