/**
 * Determines whether the element at the given index can be decreased.
 *
 * The rules are:
 *   • there is at least one decrement left (remainingK > 0)
 *   • the index is odd (i % 2 == 1)
 *   • both neighbours are at least two smaller than the current value
 *
 * @param i          the current index in the array
 * @param values     the array of integers
 * @param remainingK how many decrements are still allowed
 * @return true if the element should be decreased, false otherwise
 */
private boolean shouldDecrease(int i, int[] values, int remainingK) {
    return remainingK > 0
            && i % 2 == 1
            && values[i - 1] < values[i] - 1
            && values[i + 1] < values[i] - 1;
}

