/**
 * Converts a string composed of characters '0' and '1' into an int array where
 * '0' becomes 0 and any other character becomes 1.
 */
private static int[] toBinaryArray(String s) {
    int[] arr = new int[s.length()];
    for (int i = 0; i < s.length(); i++) {
        arr[i] = (s.charAt(i) == '0') ? 0 : 1;
    }
    return arr;
}

/**
 * Counts how many entries in the array are equal to 0.
 */
private static int countZeros(int[] arr) {
    int count = 0;
    for (int value : arr) {
        if (value == 0) {
            count++;
        }
    }
    return count;
}

/**
 * Returns the amount to add according to the original complex conditional:
 *   if (b <= c * w) add b else add c * w
 */
private static int calculateAddition(int b, int c, int w) {
    return (b <= c * w) ? b : c * w;
}

