private static class Counter {
    int odd;
    int ones;
    int zeros;
}

/** Updates the aggregated counts for a single string. */
private void updateAggregates(String s, Counter counter) {
    // Count strings with odd length
    counter.odd += (s.length() & 1);

    // Count '1' and '0' characters
    for (int i = 0; i < s.length(); i++) {
        if (s.charAt(i) == '1') {
            counter.ones++;
        } else {
            counter.zeros++;
        }
    }
}

/** Determines the answer for a test case based on the gathered statistics. */
private int computeResult(int n, int odd, int ones, int zeros) {
    // Guard clause – the "else" case is the default return value
    if ((ones % 2) + (zeros % 2) > odd) {
        return n - 1;
    }
    return n;
}

