/**
 * Computes, for a given column, the maximal number of 1's that can be obtained
 * by selecting a window of up to K consecutive rows that start at a row
 * containing a 1, and the number of already‑selected 1's (the "replace" count)
 * that correspond to the best window.
 *
 * @return an int array where
 *         result[0] = best score (maximal sum in a K‑window),
 *         result[1] = number of preceding 1's (replace count) for that best score.
 */
private static int[] computeColumnScoreAndReplace(int[][] a, int col, int K) {
    int score = 0;          // best window sum found so far
    int replaceCount = 0;   // replace count associated with the best window
    int cur = 0;            // number of 1's seen up to the current row
    int n = a.length;

    for (int i = 0; i < n; ++i) {
        // guard clause: ignore rows where the current column is not 1
        if (a[i][col] != 1) {
            continue;
        }

        int tot = sumWindow(a, col, i, K);
        if (tot > score) {
            score = tot;
            replaceCount = cur;
        }
        cur++;
    }
    return new int[]{score, replaceCount};
}

/**
 * Returns the sum of values in column {@code col} from row {@code start}
 * up to {@code start + K - 1}, without exceeding the matrix height.
 */
private static int sumWindow(int[][] a, int col, int start, int K) {
    int total = 0;
    int limit = Math.min(start + K, a.length);
    for (int j = start; j < limit; ++j) {
        total += a[j][col];
    }
    return total;
}

