    }
}

/** Holds the running counters used while scanning the string. */
private static class State {
    long dCnt = 0L;   // number of 'D' seen in the current window
    long mCnt = 0L;   // number of 'M' seen in the current window
    long dmCnt = 0L;  // number of "DM" pairs in the current window
}

/** Updates the counters when a character leaves the sliding window. */
private static void removeChar(char ch, State s) {
    switch (ch) {
        case 'D':
            s.dCnt--;
            s.dmCnt -= s.mCnt;   // all pairs that started with this 'D' are removed
            break;
        case 'M':
            s.mCnt--;
            break;
        // 'C' does not affect counters when it leaves the window
        default:
            break;
    }
}

/** Processes the current character, updates counters and returns the contribution
 *  to the answer (only non‑zero for 'C'). */
private static long handleCurrentChar(char ch, State s) {
    switch (ch) {
        case 'D':
            s.dCnt++;
            return 0L;
        case 'M':
            s.mCnt++;
            s.dmCnt += s.dCnt;   // each existing 'D' forms a "DM" pair with this 'M'
            return 0L;
        case 'C':
            return s.dmCnt;      // each "DM" before this 'C' contributes one subsequence
        default:
            return 0L;
    }
}

