/**
 * Tries to partition the suffix of {@code nums} that starts at {@code startIdx}
 * into windows whose sums equal {@code target}.
 *
 * @param nums   input array
 * @param target required sum for each window
 * @param startIdx index (1‑based) where the suffix begins
 * @return the final count if every window matches {@code target},
 *         otherwise {@code null}
 */
private static Integer findCountForTarget(int[] nums, int target, int startIdx) {
    int count = startIdx - 1;          // elements already accounted for in the prefix
    int i = startIdx;                  // start scanning from the first element after the prefix

    while (i < nums.length) {
        int windowSum = 0;
        // build the next window until its sum reaches (or exceeds) the target
        while (i < nums.length && windowSum < target) {
            windowSum += nums[i];
            count++;
            i++;
        }
        // guard‑clause: the window sum must be exactly the target
        if (windowSum != target) {
            return null;
        }
        // undo the extra increment performed when the window finished
        count--;
    }
    return count;
}

