/**
 * Tries to partition the array starting after {@code startIndex} into
 * consecutive windows whose sum equals {@code target}.
 *
 * @param nums   the input array
 * @param startIndex the index where the first window ends (exclusive)
 * @param target the required sum for every window
 * @return the count value defined by the original algorithm, or {@code null}
 *         if the partitioning cannot be achieved.
 */
private static Integer tryBuildWithTarget(int[] nums, int startIndex, int target) {
    int count = startIndex - 1;      // mirrors the original 'pre-1' initialization
    int i = startIndex;              // start scanning from the element after the prefix

    while (i < nums.length) {
        int windowSum = 0;

        // accumulate until we reach or exceed the target
        while (i < nums.length && windowSum < target) {
            windowSum += nums[i];
            count++;
            i++;
        }

        // if the accumulated sum does not match the target, this prefix fails
        if (windowSum != target) {
            return null;
        }

        // undo the last increment that belongs to the next window's start
        count--;
    }
    return count;
}

