        ds.u(sc.nextInt() - 1, sc.nextInt() - 1);
    }

    Map<Integer, List<int[]>> components = buildComponentMap(n, wa, wb, ds);
    int[][] dp = computeKnapsack(components, w);
    out.println(dp[components.size()][w]);
}

/**
 * Builds a map from component root → list of items belonging to that component.
 * The first element of each list stores the aggregated weight/value of the whole component.
 */
private static Map<Integer, List<int[]>> buildComponentMap(int n, int[] wa, int[] wb, DS ds) {
    Map<Integer, List<int[]>> map = new HashMap<>();
    for (int i = 0; i < n; i++) {
        int root = ds.r(i);
        List<int[]> list = map.computeIfAbsent(root, k -> {
            List<int[]> l = new ArrayList<>();
            l.add(new int[2]);               // aggregate placeholder (weight, value)
            return l;
        });

        int[] aggregate = list.get(0);
        aggregate[0] += wa[i];
        aggregate[1] += wb[i];
        list.add(new int[] { wa[i], wb[i] });
    }
    return map;
}

/**
 * Runs the knapsack DP across all components.
 */
private static int[][] computeKnapsack(Map<Integer, List<int[]>> components, int capacity) {
    int compCount = components.size();
    int[][] dp = new int[compCount + 1][capacity + 1];
    int cur = 0;

    for (List<int[]> component : components.values()) {
        cur++;

        // start from the previous component's results
        dp[cur] = Arrays.copyOf(dp[cur - 1], capacity + 1);

        // try every item (including the aggregated one) of the current component
        for (int[] item : component) {
            updateDpRow(dp, cur, capacity, item);
        }

        // ensure dp[cur][w] is non‑decreasing with respect to w
        propagateBest(dp[cur], capacity);
    }
    return dp;
}

/**
 * Updates a single DP row with the given item.
 */
private static void updateDpRow(int[][] dp, int row, int capacity, int[] item) {
    int weight = item[0];
    int value  = item[1];

    for (int curW = 0; curW <= capacity; curW++) {
        int nextW = curW + weight;
        if (nextW > capacity) {
            break;
        }
        int candidate = dp[row - 1][curW] + value;
        if (candidate > dp[row][nextW]) {
            dp[row][nextW] = candidate;
        }
    }
}

/**
 * Makes the DP row monotonic: dp[w] = max(dp[w], dp[w‑1]).
 */
private static void propagateBest(int[] row, int capacity) {
    for (int i = 1; i <= capacity; i++) {
        if (row[i - 1] > row[i]) {
            row[i] = row[i - 1];
        }
    }
}

