/**
 * Checks whether every character of the substring [x, x+l-1] can be mapped to a
 * distinct character of the substring [y, y+l-1] with matching 31‑ and 61‑hashes.
 */
private boolean areSubstringsTransformable(int x, int y, int l,
                                           CharHash hash31, CharHash hash61,
                                           boolean[] used) {
    for (char c = 'a'; c <= 'z'; c++) {
        int xHash31 = hash31.hash(x, x + l - 1, c);
        int xHash61 = hash61.hash(x, x + l - 1, c);

        if (!findAndMarkMatch(y, l, xHash31, xHash61, used, hash31, hash61)) {
            return false;               // guard clause – fail fast
        }
    }
    return true;
}

/**
 * Tries to find a character {@code d} (not yet used) in the substring
 * [y, y+l-1] whose 31‑ and 61‑hashes equal the supplied values.
 * If such a character exists it is marked as used.
 */
private boolean findAndMarkMatch(int y, int l,
                                 int targetHash31, int targetHash61,
                                 boolean[] used,
                                 CharHash hash31, CharHash hash61) {
    for (char d = 'a'; d <= 'z' + 1; d++) {
        int idx = d - 'a';
        if (idx < 0 || idx >= used.length) {
            continue;                   // safety – keep original behaviour
        }
        if (used[idx]) {
            continue;
        }
        int yHash31 = hash31.hash(y, y + l - 1, d);
        int yHash61 = hash61.hash(y, y + l - 1, d);
        if (targetHash31 == yHash31 && targetHash61 == yHash61) {
            used[idx] = true;
            return true;
        }
    }
    return false;
}

