/* Initialise the DP matrix with Long.MAX_VALUE. */
private long[][] initialiseDpMatrix(int n) {
    long[][] dp = new long[n + 1][n + 1];
    for (int i = 0; i <= n; i++) {
        Arrays.fill(dp[i], Long.MAX_VALUE);
    }
    return dp;
}

/* Populate the DP matrix – the core O(n³) logic. */
private void fillDp(long[][] dp, int n) {
    for (int len = 2; len < n - 1; len++) {
        for (int i = 0; i < n; i++) {
            int end = (i + len) % n;
            for (int mid = 1; mid < len; mid++) {
                int m = (i + mid) % n;
                long cur = computeCurrentCost(i, end, m, i, mid, len, dp);
                dp[i][len] = Math.min(dp[i][len], cur);
            }
        }
    }
}

/* Compute the cost for a particular (i, len, mid) combination,
   applying the same guard‑clause logic that existed in the original code. */
private long computeCurrentCost(int i, int end, int m,
                                 int startIdx, int mid, int len,
                                 long[][] dp) {
    long cost = (i + 1L) * (end + 1L) * (m + 1L);

    // Add the left sub‑problem only if it actually exists
    if (mid > 1) {
        cost += dp[startIdx][mid];
    }

    // Add the right sub‑problem only if it actually exists
    if (len - mid > 1) {
        cost += dp[m][len - mid];
    }
    return cost;
}

/* Compute the final answer from the filled DP matrix. */
private long computeBest(long[][] dp, int n) {
    long best = dp[1][n - 2] + 2L * n;

    for (int len = 2; len < n - 1; len++) {
        long candidate = dp[0][len] + dp[len][n - len];
        best = Math.min(best, candidate);
    }
    return best;
}

