    dp[0][0] = 1;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < (1 << 17); j++) {
            processTransitions(i, j, dp, retMask, MASK, MOD);
        }
    }

    long answer = pow10Mod(n, MOD);
    answer = subtractAllDpValues(dp[n], answer, MOD);
    System.out.println(answer);
}

/**
 * Constructs the mask that must appear in the final state.
 */
private static int buildRetMask(int[] x) {
    int mask = 0;
    for (int v : x) {
        mask <<= 1;          // add a mandatory '1' separator
        mask |= 1;
        mask <<= v - 1;      // shift by the length of the block
    }
    return mask;
}

/**
 * Performs the inner DP transitions for a given (i, j) pair.
 * The guard‑clause style ``continue`` removes one level of nesting.
 */
private static void processTransitions(int i, int j, long[][] dp,
                                       int retMask, int mask, int mod) {
    // base state after appending a single ‘1’
    int base = ((j << 1) | 1) & mask;

    for (int k = 1; k <= 10; k++) {
        int to = (base << (k - 1)) & mask;

        // guard clause: skip states that already contain the required pattern
        if ((to & retMask) == retMask) {
            continue;
        }

        dp[i + 1][to] = (dp[i + 1][to] + dp[i][j]) % mod;
    }
}

/**
 * Computes 10ⁿ mod MOD.
 */
private static long pow10Mod(int n, int mod) {
    long result = 1;
    for (int i = 0; i < n; i++) {
        result = (result * 10) % mod;
    }
    return result;
}

/**
 * Subtracts the sum of all DP values from the current answer,
 * keeping the result within the modular range.
 */
private static long subtractAllDpValues(long[] dpRow, long current,
                                       int mod) {
    long sum = current;
    for (long value : dpRow) {
        sum = (sum + mod - value) % mod;
    }
    return sum;
}

