/**
 * Returns {@code true} if the subsequence s[l..r] brings the point back
 * to the origin (net displacement (0,0)).
 */
private boolean isZeroDisplacement(String s, int l, int r) {
    int dx = 0;
    int dy = 0;

    for (int i = l; i <= r; i++) {
        switch (s.charAt(i)) {
            case 'U': dy++; break;
            case 'D': dy--; break;
            case 'L': dx++; break;
            case 'R': dx--; break;
        }
    }

    return dx == 0 && dy == 0;
}

