private static long computePairDifferenceSkipping(int[] sorted, int skipIdx1, int skipIdx2) {
    long sum = 0;
    Integer previous = null;               // holds the first element of a pair
    for (int idx = 0; idx < sorted.length; idx++) {
        if (idx == skipIdx1 || idx == skipIdx2) {
            continue;                      // skip the two removed elements
        }
        if (previous == null) {
            previous = sorted[idx];        // start a new pair
        } else {
            sum += sorted[idx] - previous; // complete the pair
            previous = null;               // ready for next pair
        }
    }
    return sum;
}

