/**
 * Performs the binary search for a given n.
 * Returns the matching m, or -1 if no m satisfies the equation.
 */
private int findMForN(int n, int target) {
    int low = 1;
    int high = n;

    while (low <= high) {
        int mid = (low + high) >>> 1;
        int value = sqr(n) - sqr(n / mid);

        if (value < target) {
            low = mid + 1;
        } else if (value > target) {
            high = mid - 1;
        } else {
            return mid;            // found a matching m
        }
    }
    return -1;                     // no matching m for this n
}

