/**
 * Decreases the values starting from index {@code start} by {@code amount}.
 * It walks through the DSU structure (via {@code root}) and uses the
 * ``left`` array to consume the remaining amount.  The method updates the
 * {@code left} and {@code par} arrays exactly as the original logic.
 */
private void applyDecrement(int start, int amount, int[] left, int[] par, int n) {
    int remaining = amount;
    for (int j = root(start, par); j < n; j = root(j, par)) {
        if (left[j] > remaining) {
            left[j] -= remaining;
            break;
        }
        remaining -= left[j];
        left[j] = 0;
        par[j] = j + 1;          // link to the next element in the DSU
    }
}

