/**
 * Decreases the values starting from position {@code p} by {@code x},
 * skipping already exhausted positions using the disjoint‑set {@code par} array.
 *
 * @param p   zero‑based start index
 * @param x   amount to decrease
 * @param left remaining values for each position
 * @param par union‑find parent array
 */
private void handleDecrease(int p, int x, int[] left, int[] par) {
    int j = root(p, par);
    while (j < left.length) {
        if (left[j] > x) {
            left[j] -= x;
            break;
        }
        x -= left[j];
        left[j] = 0;
        par[j] = j + 1;          // skip this exhausted element
        j = root(j, par);
    }
}

