/** Returns true if the rectangle defined by its corners
 *  (top‑left) = (top,left) and (bottom‑right) = (bottom,right)
 *  contains at least k marked cells.
 */
private static boolean hasAtLeastK(int[][] grid,
                                   int top, int left,
                                   int bottom, int right,
                                   int k) {
    int sum = 0;
    for (int i = top; i <= bottom; i++) {
        for (int j = left; j <= right; j++) {
            sum += grid[i][j];
            if (sum >= k) {
