        for (int birds = 1; birds <= N; birds++) {
            int limit = Math.min(c[nest - 1], birds);
            for (int x = 0; x <= limit; x++) {
                if (tryUpdate(nest, birds, x, W, B, X, cost, dp)) {
                    ans = birds;                 // keep the latest reachable bird count
                }
            }
        }
