/**
 * Attempts to update the DP table for the given state.
 *
 * @return true if the DP entry was updated, false otherwise
 */
private static boolean tryUpdate(int nest, int birds, int x,
                                 long W, long B, long X,
                                 int[] cost, long[][] dp) {
    long previous = dp[nest - 1][birds - x];
    if (previous == -1) {
        return false;                           // guard: unreachable previous state
    }

    long newM = Math.min(W + (birds - x) * B, previous + X)
                - (long) cost[nest - 1] * x;
    if (newM < 0) {
        return false;                           // guard: not enough resource after cost
    }

    long max = W + birds * B;
    dp[nest][birds] = Math.max(dp[nest][birds], Math.min(newM, max));
    return true;
}

