public static void main(String[] args) {
    Scanner in = new Scanner(System.in);
    int n = in.nextInt();

    List<Seg> segs = buildSegments(n);
    Collections.sort(segs);

    AtomicInteger count = new AtomicInteger(0);

    while (!segs.isEmpty()) {
        Seg biggest = segs.get(segs.size() - 1);

        // Try to merge the biggest segment with any smaller one.
        // If a merge happened (regardless of whether it increased the count),
        // restart the loop to process the new set of segments.
        if (attemptMerge(biggest, segs, n, count)) {
            continue;
        }

        // No merge possible → discard the biggest segment.
        segs.remove(segs.size() - 1);
        count.incrementAndGet();
    }

    System.out.println(count.get());
}

/**
 * Creates all possible segments for a given length {@code n}.
 * Each segment is represented by its length, start index and end index.
 */
private static List<Seg> buildSegments(int n) {
    List<Seg> result = new ArrayList<>();
    for (int s = 0; s < n; s++) {
        for (int e = n; e > s; e--) {
            result.add(new Seg(e - s, s, e));
        }
    }
    return result;
}

/**
 * Attempts to merge {@code big} with any other segment in {@code segs}.
 * If a merge is performed the corresponding old segments are removed,
 * the new one is inserted (or counted if its length reaches {@code n}),
 * and {@code true} is returned to indicate that the outer loop should
 * continue processing the updated list.
 *
 * @return {@code true} if a merge occurred, {@code false} otherwise.
 */
private static boolean attemptMerge(Seg big, List<Seg> segs, int n, AtomicInteger count) {
    // iterate from the second‑last element downwards
    for (int i = segs.size() - 2; i >= 0; i--) {
        Seg candidate = segs.get(i);
        if (areNonOverlapping(candidate, big)) {
            Seg merged = merge(candidate, big);

            // remove the two original segments
            segs.remove(segs.size() - 1); // remove big (last element)
            segs.remove(i);               // remove candidate

            // either put the merged segment back or count it directly
            if (merged.len < n) {
                segs.add(merged);
            } else {
                count.incrementAndGet();
            }

            return true; // a merge happened
        }
    }
    return false; // no suitable candidate found
}

/**
 * Two segments are non‑overlapping when one ends before the other starts.
 */
private static boolean areNonOverlapping(Seg a, Seg b) {
    return (a.s >= b.e) || (b.s >= a.e);
}

/**
 * Returns a new segment that spans both {@code a} and {@code b}.
 */
private static Seg merge(Seg a, Seg b) {
    int start = Math.min(a.s, b.s);
    int end   = Math.max(a.e, b.e);
    return new Seg(end - start, start, end);
}

