/**
 * Constructs the word obtained by merging two words of length {@code k}
 * according to the rule used in the original solution:
 * <ul>
 *   <li>If the characters at a position are equal, keep that character.</li>
 *   <li>Otherwise use the third character from the set {'S','E','T'}.</li>
 * </ul>
 *
 * @param first  the first word
 * @param second the second word
 * @param k      the common length of the words
 * @return the merged word
 */
private static String buildCombinedWord(String first, String second, int k) {
    StringBuilder sb = new StringBuilder(k);
    for (int t = 0; t < k; t++) {
        char a = first.charAt(t);
        char b = second.charAt(t);
        sb.append(a == b ? a : (char) ('S' + 'E' + 'T' - a - b));
    }
    return sb.toString();
}

