public static void main(String[] args) throws IOException {
    PrintStream out = new PrintStream(System.out);
    Reader sc = new Reader();

    int n = sc.i();
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = sc.i();
    }

    // Guard clause for trivial cases
    if (n <= 2) {
        out.println(0);
        return;
    }

    int initialDiff = arr[1] - arr[0];
    int min = Integer.MAX_VALUE;

    for (int step = initialDiff - 2; step <= initialDiff + 2; step++) {
        for (int offset = -1; offset <= 1; offset++) {
            Integer cost = computeAdjustmentCost(arr, step, offset);
            if (cost != null) {
                min = Math.min(min, cost);
            }
        }
    }

    out.println(min == Integer.MAX_VALUE ? -1 : min);
}

/**
 * Calculates the total number of unit adjustments required to transform the
 * original sequence into an arithmetic progression with the given {@code step}
 * and an optional change {@code offset} applied to the first element.
 *
 * @param arr    the original array (must have length ≥ 2)
 * @param step   the candidate common difference of the target progression
 * @param offset the value added to {@code arr[0]} (can be -1, 0, or 1)
 * @return the total adjustment cost if the transformation is possible;
 *         otherwise {@code null}
 */
private static Integer computeAdjustmentCost(int[] arr, int step, int offset) {
    // Cost contributed by changing the first element
    int cost = Math.abs(offset);
    int expected = arr[0] + offset;

    for (int i = 1; i < arr.length; i++) {
        expected += step;
        int diff = Math.abs(arr[i] - expected);
        if (diff > 1) {
            // Guard clause – transformation impossible for this combination
            return null;
        }
        cost += diff;
    }
    return cost;
}

