/**
 * Populates the three‑dimensional DP table.
 * Guard clauses are used to flatten the inner conditional logic.
 */
private static void fillDP(int n, int k) {
    dp[0][0][0] = true;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j <= k; j++) {
            for (int l = 0; l <= k; l++) {
                int tmp1 = j - coins[i];
                int tmp2 = l - coins[i];

                // If the current coin cannot be taken for the first sum, skip that branch.
                if (tmp1 < 0) {
                    dp[i + 1][j][l] |= dp[i][j][l];
                    continue;
                }

                // Take the coin for the first sum.
                dp[i + 1][j][l] |= dp[i][tmp1][l];

                // If the coin can also be taken for the second sum, apply that transition.
                if (tmp2 >= 0) {
                    dp[i + 1][j][l] |= dp[i][tmp1][tmp2];
                }

                // Always propagate the “do nothing” state.
                dp[i + 1][j][l] |= dp[i][j][l];
            }
        }
    }
