/**
 * Counts how many consecutive pairs (a[j], a[j+1]) in the given array
 * contain at least one element equal to 1.
 *
 * @param a an array of even length (2 * m)
 * @return the number of pairs where a[j] == 1 || a[j+1] == 1
 */
private static int countPairsWithOne(int[] a) {
    int count = 0;
    // Guard clause: empty or null array yields 0
    if (a == null || a.length == 0) {
        return 0;
    }
    for (int j = 0; j < a.length; j += 2) {
        if (a[j] == 1 || a[j + 1] == 1) {
            count++;
        }
    }
    return count;
}

