    in[m][0] = c0;
    in[m][1] = n;
    in[m][2] = d0;

    int[][] dp = new int[n + 1][m + 1];
    int[] best = new int[n + 1];

    for (int i = 1; i <= n; i++) {
        int[] currentState = dp[i - 1];   // best state for i‑1
        int currentScore = best[i - 1];   // best score for i‑1

        for (int j = 0; j <= m; j++) {
            // guard‑clause style: skip impossible options early
            if (in[j][0] > i) {
                continue;
            }
            int[] prevState = dp[i - in[j][0]];
            int prevScore = best[i - in[j][0]];

            if (prevState[j] >= in[j][1]) {
                continue;
            }

            int candidateScore = prevScore + in[j][2];
            if (candidateScore <= currentScore) {
                continue;
            }

            // we have found a better solution for i using option j
            currentState = prevState.clone();
            currentState[j]++;          // consume one more of option j
            currentScore = candidateScore;
        }

        dp[i] = currentState;
        best[i] = currentScore;
    }

    System.out.println(best[n]);
}

