/**
 * Returns the number of prime factors (with multiplicity) of {@code value}.
 * Behaviour is identical to the original nested loops but the logic is now
 * encapsulated in a single, well‑named method.
 */
private static int countPrimeFactors(long value) {
    int factorCount = 0;
    long m = value;

    for (long j = 2; j * j <= m; j++) {
        if (m % j == 0) {
            while (m % j == 0) {
                m /= j;
                factorCount++;
            }
        }
    }

    // if a prime > sqrt(original value) remains, count it as a factor
    if (m > 1) {
        factorCount++;
    }

    return factorCount;
}

