/**
 * Applies the {@code queryIdx}-th query to a single value of array {@code b}.
 * Returns the updated value while preserving the original semantics.
 */
private static int applyQueryToElement(int value, int queryIdx) {
    // Guard clause: if the value is outside the query interval, leave it unchanged.
    if (value < min[queryIdx] || value > max[queryIdx]) {
        return value;
    }

    if (t[queryIdx] == 1) {
        // Decrement with wrap‑around at the lower bound.
        return (value == min[queryIdx]) ? max[queryIdx] : value - 1;
    }

    // t[queryIdx] != 1 → the “reverse” operation.
    return max[queryIdx] - value + min[queryIdx];
}

