void solve() throws Exception {
    int n = sc.nextInt();
    int[] a = new int[n];
    for (int i = 0; i < n; i++) {
        a[i] = sc.nextInt();
    }

    int[] ans = new int[MAXN + 1];

    for (int i = 0; i < n; i++) {
        List<Integer> divisors = getPrimeDivisors(a[i]);

        // If the number has no prime divisor (possible only for 1), skip processing.
        if (divisors.isEmpty()) {
            continue;
        }

        int best = calculateBest(divisors, ans);
        updateAnswers(divisors, ans, best);
    }

    int res = 1;
    for (int j = 2; j <= MAXN; j++) {
        res = max(res, ans[j]);
    }
    out.println(res);
