/**
 * Returns a list containing the distinct prime divisors of {@code num}.
 * The original number is not modified.
 */
private List<Integer> getPrimeDivisors(int num) {
    List<Integer> divisors = new ArrayList<>();
    int value = num;                       // work on a copy to keep the original unchanged
    for (int d = 2; d * d <= value; d++) {
        if (value % d != 0) {
            continue;                     // guard‑clause: not a divisor, try next candidate
        }
        divisors.add(d);
        while (value % d == 0) {
            value /= d;                    // strip all occurrences of the current prime
        }
    }
    if (value > 1) {
        divisors.add(value);                // remaining value is a prime divisor
    }
    return divisors;
}

/**
 * Computes the length of the longest valid subsequence that can be extended
 * by the current number, based on its prime divisors.
 */
private int calculateBest(List<Integer> divisors, int[] ans) {
    int best = 0;
    for (int d : divisors) {
        best = max(best, ans[d] + 1);
    }
    return best;
}

/**
 * Updates the {@code ans} array for each prime divisor with the newly
 * calculated {@code best} value.
 */
private void updateAnswers(List<Integer> divisors, int[] ans, int best) {
    for (int d : divisors) {
        ans[d] = max(ans[d], best);
    }
}

