/* Extracted method that contains the three‑level nested search.
   It returns the minimum additional cost needed to make the hero
   survive longer than the monster. */
private static int findBestAdditionalCost(
        int hpy, int aty, int dey, int hpm, int atm, int dem,
        int chp, int cat, int cde) {

    int addCost = Integer.MAX_VALUE;

    for (int h = 0; h < 10001; h++) {
        for (int a = 0; a < 101; a++) {
            for (int d = 0; d < 100; d++) {
                int dmgToMonster = Math.max(atm - dey - d, 0);
                int dmgToHero   = Math.max(aty + a - dem, 0);

                /* Guard clause – if the current (h,a,d) combination is
                   already sufficient we can evaluate its cost
                   and stop increasing d (break the innermost loop). */
                if (dmgToMonster <= 0 ||
                        Math.ceil((double) (hpy + h) / (double) dmgToMonster)
                                > Math.ceil((double) hpm / (double) dmgToHero)) {

                    int actCost = a * cat + h * chp + d * cde;
                    if (actCost < addCost) {
                        addCost = actCost;
                    }
                    break; // stop increasing d for this (h,a) pair
                }
                // otherwise keep increasing d
            }
        }
    }
    return addCost;
}

