/**
 * Returns {@code true} if the fraction with denominator {@code q} has a finite
 * representation in base {@code b}, otherwise {@code false}.
 *
 * The method follows the same logic as the original loop but is extracted
 * to keep the main algorithm flat. It also guards against pathological
 * inputs by limiting the number of iterations.
 */
private boolean hasFiniteExpansion(long q, long b) {
    int iterations = 0;
    while (q != 1) {
        long cofactor = gcd(q, b);
        if (cofactor == 1) {
            return false;
        }
        while (q % cofactor == 0) {
            q /= cofactor;
        }
        if (++iterations >= 1_000_000) {
            throw new ArrayIndexOutOfBoundsException("Infinite loop");
        }
    }
    return true;
}

