/**
 * Determines whether the fraction p/q (reduced) terminates in base {@code b}.
 * Returns {@code true} for a finite representation, {@code false} otherwise.
 */
private boolean isFinite(long p, long q, long b) {
    // Guard clause – if numerator is zero the value is 0, which is always finite.
    if (p == 0) {
        return true;
    }

    // Reduce the fraction.
    long gcd = gcd(p, q);
    p /= gcd;
    q /= gcd;

    int iterations = 0;
    while (q != 1) {
        long cofactor = gcd(q, b);
        if (cofactor == 1) {
            return false;               // No common factor → infinite representation.
        }

        // Remove all occurrences of the common factor from the denominator.
        while (q % cofactor == 0) {
            q /= cofactor;
        }

        // Safety against pathological inputs.
        if (++iterations >= 1_000_000) {
            throw new ArrayIndexOutOfBoundsException("INfinite loop");
        }
    }

    return true;                        // Denominator fully reduced → finite.
}

/**
 * Euclidean algorithm for greatest common divisor.
 */
private long gcd(long a, long b) {
    while (b != 0) {
        long tmp = a % b;
        a = b;
        b = tmp;
    }
    return Math.abs(a);
}

