    int[][] perms = {
        {0, 1, 2},
        {0, 2, 1},
        {1, 0, 2},
        {1, 2, 0},
        {2, 0, 1},
        {2, 1, 0}
    };

    for (int[] p : perms) {
        if ((bits[p[0]] & 0b001) != 0 &&
            (bits[p[1]] & 0b010) != 0 &&
            (bits[p[2]] & 0b100) != 0) {
