        Vertex[] vs = undirectedGraph;
        for(Vertex v:vs)v.used=false;
        List<Vertex[]> lists = new ArrayList<Vertex[]>();
        for(Vertex v:vs)if(!v.used){
            List<Vertex> list = new ArrayList<Vertex>();
            Queue<Vertex> que = new LinkedList<Vertex>();
            que.offer(v);
            v.used = true;
            while(!que.isEmpty()){
                Vertex cur = que.poll();
                list.add(cur);
                for(Vertex nxt : cur){
                    if(!nxt.used){
                        que.offer(nxt);
                        nxt.used=true;
                    }
                }
