/**
 * Returns true if there exists a pair (i, j) that satisfies the original
 * nested conditions for the given {@code mid} value.
 */
private static boolean canAchieve(int[] h, int[] a, int[] d, int mid) {
    for (int i = 0; i < 300; i++) {
        for (int j = 0; j < 300; j++) {
            // Guard clause: skip combinations that cannot possibly work
            if (i + a[0] <= d[1]) {
                continue;
            }
            int hp = calculateHp(h, a, d, i, j);
            if (hp * h[2] + i * a[2] + j * d[2] <= mid) {
                return true; // early exit – condition satisfied
            }
        }
    }
    return false;
}

/**
 * Computes the {@code hp} value used in the original algorithm.
 * The denominator is guaranteed to be positive because {@code canAchieve}
 * filters out the cases where {@code i + a[0] <= d[1]}.
 */
private static int calculateHp(int[] h, int[] a, int[] d, int i, int j) {
    int numerator = h[1] + a[0] + i - d[1] - 1;
    int denominator = a[0] + i - d[1];
    int term = (a[1] - (d[0] + j)) * (numerator / denominator);
    return Math.max(0, term + 1 - h[0]);
}

