/**
 * Processes all sub‑arrays that start at index {@code start}.
 * For each distinct GCD value {@code g} found, it adds the number of
 * sub‑arrays beginning at {@code start} whose GCD equals {@code g}
 * to {@code resultMap}.
 */
private static void accumulateForStart(int start, int n, SparseTable s, Map<Integer, Long> resultMap) {
    int idx = start;
    while (true) {
        int g = s.query(start, idx);
        int nextIdx = findFirstSmaller(start, idx, n, s, g);
        // number of sub‑arrays with GCD = g that start at 'start' and end before 'nextIdx'
        long add = (long) (nextIdx - idx);
        resultMap.put(g, resultMap.getOrDefault(g, 0L) + add);

        idx = nextIdx;
        if (nextIdx == n) {
            break;
        }
    }
}

/**
 * Binary‑searches for the smallest index {@code mid} in (idx, n‑1]
 * such that {@code s.query(start, mid)} is strictly smaller than {@code target}.
 * Returns {@code n} if no such index exists.
 */
private static int findFirstSmaller(int start, int idx, int n, SparseTable s, int target) {
    int lo = idx + 1;
    int hi = n - 1;
    int ans = n;

    while (lo <= hi) {
        int mid = (lo + hi) >>> 1; // unsigned right shift for floor division by 2
        if (s.query(start, mid) < target) {
            ans = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return ans;
}

