/**
 * Fills containers starting at {@code start} with {@code amount} units.
 * Containers that become full are removed from {@code available}.
 *
 * @param start     index of the first container to try (zero‑based)
 * @param amount    total units to distribute
 * @param cap       array of capacities
 * @param fill      array of currently filled amounts (will be mutated)
 * @param available TreeSet keeping indices of containers that are not yet full
 */
private static void fillCapacity(int start, int amount,
                                 int[] cap, int[] fill,
                                 TreeSet<Integer> available) {
    int pos = available.ceiling(start);
    int remaining = amount;

    while (remaining > 0 && pos != Integer.MAX_VALUE) {
        int delta = Math.min(cap[pos] - fill[pos], remaining);
        fill[pos] += delta;
        remaining -= delta;

        if (fill[pos] == cap[pos]) {
            available.remove(pos);
        }
        pos = available.ceiling(pos);
    }
}

