/**
 * Returns {@code true} if the subsequence {@code s[start..end]} brings the
 * cursor back to the original position (net vertical and horizontal displacement are zero).
 */
private boolean isZeroDisplacement(char[] s, int start, int end) {
    int r = 0; // vertical displacement
    int c = 0; // horizontal displacement

    for (int k = start; k <= end; k++) {
        char ch = s[k];
        if (ch == 'U') {
            ++r;
        } else if (ch == 'D') {
            --r;
        } else if (ch == 'R') {
            ++c;
        } else if (ch == 'L') {
            --c;
        }
    }

    return r == 0 && c == 0;
}

