public void solve(int testNumber, ScanReader in, PrintWriter out) {
    int b = in.scanInt();
    int d = in.scanInt();
    char[] ar = in.scanString().toCharArray();
    char[] br = in.scanString().toCharArray();

    // Guard against empty pattern – the original algorithm assumes br.length > 0
    if (br.length == 0) {
        out.println(0);
        return;
    }

    int[] dp = new int[br.length];
    int[] dpPos = new int[br.length];
    computeDpAndPos(ar, br, dp, dpPos);

    long total = simulateSteps(b, dp, dpPos);
    out.println(total / d);
}

/** Fills the dp and dpPos arrays.
 *  dp[j]   – how many times the whole pattern br is found when scanning ar
 *            starting from position j in br.
 *  dpPos[j] – the position in br where the scan ends after processing ar.
 */
private void computeDpAndPos(char[] ar, char[] br, int[] dp, int[] dpPos) {
    for (int j = 0; j < br.length; j++) {
        int matches = 0;
        int curPos = j;

        for (char c : ar) {
            if (c == br[curPos]) {
                curPos = (curPos + 1) % br.length;
                if (curPos == 0) {
                    matches++;
                }
            }
        }

        dp[j] = matches;
        dpPos[j] = curPos;
    }
}

/** Simulates the process for ‘steps’ iterations, accumulating the
 *  number of complete pattern matches.
 */
private long simulateSteps(int steps, int[] dp, int[] dpPos) {
    long sum = 0L;
    int curB = 0;

    for (int i = 0; i < steps; i++) {
        sum += dp[curB];
        curB = dpPos[curB];
    }

    return sum;
}

