    stack.add(n + 1);                     // sentinel
    StringBuilder sb = new StringBuilder();

    int smallest = 1;
    int[] nextIdx = {0};                  // mutable holder for the current array index

    while (!stack.isEmpty()) {
        while (stack.peek() > smallest) {
            if (!pushNextOrDecrement(stack, arr, k, nextIdx, sb)) {
                System.out.println(-1);
                return;
            }
        }
        stack.pop();
        smallest++;
    }

    System.out.println(sb);
    pw.flush();
    pw.close();
}

/**
 * Pushes the next user‑provided value onto the stack if any remain,
 * otherwise pushes {@code stack.peek() - 1}.  The method appends the
 * pushed value to {@code sb}.  If the next value violates the invariant
 * {@code value <= stack.peek()}, the method returns {@code false}
 * signalling an error.
 *
 * @return {@code true} if the push succeeded, {@code false} on error.
 */
private static boolean pushNextOrDecrement(Stack<Integer> stack,
                                           int[] arr,
                                           int k,
                                           int[] nextIdx,
                                           StringBuilder sb) {
    if (nextIdx[0] < k) {                     // there are still input numbers
        int x = arr[nextIdx[0]++];
        if (x > stack.peek()) {               // invariant broken → impossible sequence
            return false;
        }
        stack.push(x);
        sb.append(x).append(' ');
    } else {                                  // no more input numbers, use decreasing sequence
        int value = stack.peek() - 1;
        stack.push(value);
        sb.append(value).append(' ');
    }
    return true;
}

