/** Returns true if s1 should come after s2 in lexicographic order. */
private static boolean isOutOfOrder(String s1, String s2) {
    return s1.compareTo(s2) > 0;
}

/**
 * Finds the first column index (0‑based) where s1 has a larger character
 * than s2. Returns –1 if no such column exists (should not happen in the
 * current algorithm because the caller already knows the pair is out of order).
 */
private static int findBadColumn(String s1, String s2, int maxLen) {
    for (int j = 0; j < maxLen; j++) {
        if (s1.charAt(j) > s2.charAt(j)) {
            return j;
        }
    }
    return -1;
}

/**
 * Removes the character at the given column index from every string in the array.
 */
private static void removeColumn(String[] array, int colIdx) {
    for (int k = 0; k < array.length; k++) {
        String str = array[k];
        array[k] = str.substring(0, colIdx) + str.substring(colIdx + 1);
    }
}

