        // guard: stop processing this pair if it is already in order
        if (!isOutOfOrder(a[i], a[i + 1])) {
            continue;
        }

        count++;                                   // original count++
        removeFirstProblematicColumn(a, m, i);     // performs the column deletion
        i = -1;                                    // restart scan from the beginning
    }

