}

/**
 * Returns true when {@code left} should come after {@code right}
 * according to the original lexicographical comparison.
 */
private static boolean isOutOfOrder(String left, String right) {
    return left.compareTo(right) > 0;
}

/**
 * Finds the first column (position {@code j}) where the two rows differ
 * and where the character in the upper row is greater than the one
 * below it. That column is removed from every row.
 *
 * This method reproduces the nested loops that were originally
 * inside {@code main}, but isolates the responsibility into a well‑named
 * helper, flattening the overall control flow.
 *
 * @param rows the array of strings representing the table
 * @param m    the original number of columns (used as the upper bound for {@code j})
 * @param row  the index of the upper row that is out of order
 */
private static void removeFirstProblematicColumn(String[] rows, int m, int row) {
    for (int j = 0; j < m; j++) {
        if (rows[row].charAt(j) > rows[row + 1].charAt(j)) {
            for (int k = 0; k < rows.length; k++) {
                rows[k] = rows[k].substring(0, j) + rows[k].substring(j + 1);
            }
            break; // column removed – exit early
        }
    }
}

