    int t1 = in.nextInt() - 1;
    int l1 = in.nextInt();
    int s2 = in.nextInt() - 1;
    int t2 = in.nextInt() - 1;
    int l2 = in.nextInt();

    int[][] dist = computeAllPairsShortestPaths(adj, n);

    // guard clause – impossible to satisfy the length limits
    if (dist[s1][t1] > l1 || dist[s2][t2] > l2) {
        System.out.println(-1);
        return;
    }

    int best = dist[s1][t1] + dist[s2][t2];

    for (int a = 0; a < n; a++) {
        for (int b = 0; b < n; b++) {
            best = tryImproveResult(best, a, b, dist,
                                    s1, t1, l1,
                                    s2, t2, l2);
        }
    }

