}

/* ---------- helper methods (extracted to flatten main) ---------- */

private static List<Integer>[] buildAdjacencyList(int n) {
    @SuppressWarnings("unchecked")
    List<Integer>[] adj = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        adj[i] = new ArrayList<>();
    }
    return adj;
}

private static void readEdges(FastScanner in, int m, List<Integer>[] adj) {
    for (int i = 0; i < m; i++) {
        int a = in.nextInt() - 1;
        int b = in.nextInt() - 1;
        adj[a].add(b);
        adj[b].add(a);
    }
}

/* runs BFS from every vertex – O(n·(n+m)) */
private static int[][] computeAllPairsShortestPaths(List<Integer>[] adj, int n) {
    int[][] dist = new int[n][];
    for (int v = 0; v < n; v++) {
        dist[v] = bfs(adj, v);
    }
    return dist;
}

/* standard BFS returning distances from src */
private static int[] bfs(List<Integer>[] adj, int src) {
    int n = adj.length;
    int[] d = new int[n];
    Arrays.fill(d, Integer.MAX_VALUE);
    Deque<Integer> q = new ArrayDeque<>();
    d[src] = 0;
    q.add(src);
    while (!q.isEmpty()) {
        int cur = q.poll();
        int nd = d[cur] + 1;
        for (int nb : adj[cur]) {
            if (d[nb] == Integer.MAX_VALUE) {
                d[nb] = nd;
                q.add(nb);
            }
        }
    }
    return d;
}

/* evaluates the two possible joint paths (a‑b shared) and updates the best result */
private static int tryImproveResult(int currentBest,
                                    int a, int b,
                                    int[][] dist,
                                    int s1, int t1, int l1,
                                    int s2, int t2, int l2) {

    // first ordering: both routes use a→b in the same direction
    if (dist[s1][a] + dist[a][b] + dist[b][t1] <= l1 &&
        dist[s2][a] + dist[a][b] + dist[b][t2] <= l2) {

        int candidate = dist[s1][a] + dist[s2][a] + dist[a][b]
                      + dist[b][t1] + dist[b][t2];
        currentBest = Math.min(currentBest, candidate);
    }

    // second ordering: second route uses the edge in reverse (b→a)
    if (dist[s1][a] + dist[a][b] + dist[b][t1] <= l1 &&
        dist[s2][b] + dist[b][a] + dist[a][t2] <= l2) {

        int candidate = dist[s1][a] + dist[s2][b] + dist[a][b]
                      + dist[b][t1] + dist[a][t2];
        currentBest = Math.min(currentBest, candidate);
    }

    return currentBest;
}

