/**
 * Returns the new position of {@code position} after applying a single query.
 * If {@code position} is outside the interval defined by {@code query},
 * it is returned unchanged.
 */
private static int applyQuery(int position, NoD query) {
    // Guard clause: outside the interval → no transformation
    if (position < query.b || position > query.c) {
        return position;
    }

    // Query type 1: reverse the interval
    if (query.a == 1) {
        return (position == query.b) ? query.c : position - 1;
    }

    // Query type 2: rotate the interval left by one (implemented as mirror)
    int size = query.c - query.b + 1;
    int relPos = position - query.b + 1; // 1‑based index inside the interval
    relPos = size - relPos + 1;           // mirrored position
    return query.b + relPos - 1;
}

