/**
 * Applies a single query to the current position.
 * If the position is outside the query interval, it is returned unchanged.
 * Otherwise the transformation defined by the query is performed.
 *
 * @param pos current position
 * @param q   query description
 * @return new position after applying the query
 */
private static int applyQuery(int pos, NoD q) {
    // Guard: position not affected by this query
    if (pos < q.b || pos > q.c) {
        return pos;
    }

    // Query type 1: shift left or jump to the right bound
    if (q.a == 1) {
        return (pos == q.b) ? q.c : pos - 1;
    }

    // Query type 2: reverse within the interval
    int size = q.c - q.b + 1;
    int relPos = pos - q.b + 1;          // 1‑based position inside the interval
    relPos = size - relPos + 1;          // mirrored position
    return q.b + relPos - 1;
}

