        char last = '0';
        for (int index = offset; index < T.length(); index += K) {
            char now = T.charAt(index);

            // Guard clause: reset if the same as previous and skip scoring
            if (last == now) {
                last = '0';
                continue;
            }

            // Add points for the current character
            score += pointsFor(now, P, R, S);
            last = now;
