/**
 * Slides a window of length {@code k} over {@code str} and stores the pair of
 * rolling hashes for each distinct substring into {@code hs1} and {@code hs2}.
 *
 * @return the number of distinct substrings of length {@code k}
 */
private static int collectDistinctSubHashes(String str, int n, int k,
                                            HashSet<Long> hs1, HashSet<Long> hs2) {
    long hash1 = 0;
    long hash2 = 0;
    long pow1 = power(BASE, k - 1, MOD1);
    long pow2 = power(BASE, k - 1, MOD2);
    int count = 0;

    for (int i = 0; i < n; i++) {
        hash1 = (hash1 * BASE) % MOD1;
        hash2 = (hash2 * BASE) % MOD2;
        hash1 = (hash1 + (str.charAt(i) - '0')) % MOD1;
        hash2 = (hash2 + (str.charAt(i) - '0')) % MOD2;

        // window not yet full
        if (i < k - 1) {
            continue;
        }

        boolean added = hs1.add(hash1);
        added |= hs2.add(hash2);
        if (added) {
            count++;
        }

        // remove the leftmost digit if it was a '1'
        if (str.charAt(i - k + 1) == '1') {
            hash1 = ((hash1 - pow1) % MOD1 + MOD1) % MOD1;
            hash2 = ((hash2 - pow2) % MOD2 + MOD2) % MOD2;
        }
    }
    return count;
}

/**
