 * in the previously collected hash sets.
 *
 * @return the numeric value of that missing binary string
 */
private static long findMissingPattern(HashSet<Long> hs1, HashSet<Long> hs2, int k) {
    long hash1 = 0;
    long hash2 = 0;

    // start from the pattern consisting of k ones (value = 2^k‑1)
    for (int i = 0; i < k; i++) {
        hash1 = (hash1 * BASE) % MOD1;
        hash2 = (hash2 * BASE) % MOD2;
        hash1 = (hash1 + 1) % MOD1;
        hash2 = (hash2 + 1) % MOD2;
    }

    long value = 0;
    while (hs1.contains(hash1) && hs2.contains(hash2)) {
        hash1 = ((hash1 - 1) % MOD1 + MOD1) % MOD1;
        hash2 = ((hash2 - 1) % MOD2 + MOD2) % MOD2;
        value++;
    }
    return value;
}

