/**
 * Checks whether the segment of length {@code j} starting at {@code start}
 * repeats consecutively (i.e. {@code chars[start .. start+j-1]} equals
 * {@code chars[start+j .. start+2*j-1]}), or runs out of bounds, which is
 * treated as a successful match in the original algorithm.
 *
 * @return {@code true} if the segment satisfies the condition, {@code false}
 *         otherwise.
 */
private boolean segmentMatches(char[] chars, int start, int j, int n) {
    // Guard clause: if the second copy would start beyond the array, it’s a match.
    if (start + j >= n) {
        return true;
    }
    for (int t = start; t < start + j; t++) {
        if (t + j >= n) {
            return true;                 // reached the end of the array
        }
        if (chars[t] != chars[t + j]) {
            return false;                // mismatch found
        }
        // When we reach the last comparison without a mismatch we succeed.
        if (t == start + j - 1) {
            return true;
        }
    }
    return false; // should never reach here
}

