        int needed = power - value;
        if (needed <= 0) {
            continue;                     // guard clause: ignore non‑positive needed values
        }
        Integer occurrences = frequency.get(needed);
        if (occurrences != null) {
            count += occurrences;
        }
    }
    return count;
}

