 */
private static int findBestScrollIndex(List<Scroll> scrolls, int cur, int max) {
    int bestIdx = -1;
    int bestDec = Integer.MIN_VALUE;
    double threshold = (cur * 1.0 / max) * 100.0;

    for (int i = 0; i < scrolls.size(); i++) {
        Scroll s = scrolls.get(i);
        if (s.percent >= threshold && s.dec > bestDec) {
            bestDec = s.dec;
            bestIdx = i;
        }
    }
    return bestIdx;
}

