public boolean nextPermutation(String[] permutateString) {
    // Guard clause for null or trivially small arrays
    if (permutateString == null || permutateString.length < 2) {
        return false;
    }

    int L = permutateString.length;

    for (int i = L - 1; i >= 1; i--) {
        // Look for the first position where the order can be increased
        if (permutateString[i].compareTo(permutateString[i - 1]) <= 0) {
            continue; // guard: not a pivot, keep scanning left
        }

        // Reverse the suffix after the pivot to obtain the smallest lexicographic order
        reverse(permutateString, i, L);

        // Swap the pivot with the next greater element in the reversed suffix
        if (swapWithNextGreater(permutateString, i - 1, i)) {
            return true;
        }
    }

    // No higher permutation exists
    return false;
}

/**
 * Finds the first element in {@code arr} (starting at {@code startIdx})
 * that is greater than {@code arr[pivotIdx]}, swaps them, and returns {@code true}.
 * Returns {@code false} if no such element exists.
 */
private boolean swapWithNextGreater(String[] arr, int pivotIdx, int startIdx) {
    for (int j = startIdx; j < arr.length; j++) {
        if (arr[pivotIdx].compareTo(arr[j]) < 0) {
            swap(arr, pivotIdx, j);
            return true;
        }
    }
    return false;
}

