    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    int n = Integer.parseInt(br.readLine());

    for (int i = 0; i < n; i++) {
        Tree tree = new Tree();
        Deque<Node> stack = new ArrayDeque<>();
        StringBuilder numBuilder = new StringBuilder();

        String line = br.readLine();
        for (char c : line.toCharArray()) {
            if (c == '[') {
                handleOpenBracket(stack);
            } else if (c == ']') {
                handleCloseBracket(stack, numBuilder, tree);
            } else {
                numBuilder.append(c);
            }
        }
        System.out.println(tree.solve());
    }
}

private static void handleOpenBracket(Deque<Node> stack) {
    Node node = new Node();
    if (!stack.isEmpty()) {
        node.parent = stack.peek();
        stack.peek().children.add(node);
    }
    stack.push(node);
}

private static void handleCloseBracket(Deque<Node> stack, StringBuilder numBuilder, Tree tree) {
    // Flush any accumulated number into the current node
    if (numBuilder.length() > 0) {
        stack.peek().nums.add(Integer.parseInt(numBuilder.toString()));
        numBuilder.setLength(0);
    }

    // Pop the node; if the stack becomes empty, this node is the tree root
    Node completedNode = stack.pop();
    if (stack.isEmpty()) {
        tree.root = completedNode;
    }
}

