public static void main(String[] args) throws Exception {
    Scanner sc = new Scanner(System.in);
    String number = sc.next();

    // initialise the binary representation
    char[] input = number.toCharArray();
    int length = input.length;
    int steps = 0;

    // repeat until we reach the binary value “1”
    while (!(length == 1 && input[0] == '1')) {
        // even number → simply drop the trailing 0
        if (input[length - 1] == '0') {
            length--;
            steps++;
            continue;
        }

        // odd number → add 1 (binary increment)
        input = incrementBinary(input, length);
        // if the array grew, the logical length grows as well
        if (input.length > length) {
            length = input.length;
        }
        steps++;
    }

    System.out.println(steps);
    sc.close();
}

/**
 * Adds 1 to the binary number stored in {@code bits}.
 *
 * @param bits   the current binary digits (most‑significant at index 0)
 * @param length the logical length of the number (ignoring any trailing garbage)
 * @return a possibly new array containing the incremented value
 */
private static char[] incrementBinary(char[] bits, int length) {
    int i = length - 1;

    // flip trailing 1s to 0s
    while (i >= 0 && bits[i] == '1') {
        bits[i] = '0';
        i--;
    }

    // if we found a 0, turn it to 1 and we are done
    if (i >= 0) {
        bits[i] = '1';
        return bits;
    }

    // overflow case: 111…111 + 1 → 1 followed by zeros
    char[] extended = new char[length + 1];
    extended[0] = '1';
    for (int j = 1; j < extended.length; j++) {
        extended[j] = '0';
    }
    return extended;
}

