/**
 * Builds an array where each index k contains the number of subsets
 * whose Wu‑value is ≤ k for the supplied query mask.
 *
 * @param mask the query mask
 * @param subsetCounts counts of each subset (the S array)
 * @param n number of bits/elements
 * @return a cumulative frequency array of size 1201
 */
private static int[] computeCumulativeWuValues(int mask, int[] subsetCounts, int n) {
    int[] values = new int[1201];

    int limit = 1 << n;
    for (int subset = 0; subset < limit; subset++) {
        if (subsetCounts[subset] == 0) {
            continue; // guard clause – skip empty subsets
        }
        int wu = getWuValue(mask, subset);
        values[wu] += subsetCounts[subset];
    }

    // transform to a prefix‑sum (cumulative) array
    for (int i = 1; i < values.length; i++) {
        values[i] += values[i - 1];
    }
    return values;
}

