 * and returns the 1‑based position (i+1). If no such index exists,
 * returns -1.
 */
private int findAndIncreaseFirstIncreasingPair(int[] a) {
    for (int i = 0; i < a.length - 1; i++) {
        if (a[i] < a[i + 1]) {
            a[i] += 1;
            return i + 1; // 1‑based index as required by the original logic
