static int dijkstra(Map<Integer, List<int[]>> all_edges, int start, int end, int max_node_number) {
    int[] distance = new int[max_node_number + 1];
    Arrays.fill(distance, -1);
    PriorityQueue<int[]> p_que = new PriorityQueue<>(
            (a, b) -> ((distance[a[0]] + a[2]) - (distance[b[0]] + b[2])));
    distance[start] = 0;

    // seed queue with outgoing edges of the start node
    List<int[]> startEdges = all_edges.get(start);
    if (startEdges != null) {
        p_que.addAll(startEdges);
    }

    while (distance[end] < 0) {
        int[] edge = p_que.poll();
        if (edge == null) {
            // no more reachable nodes – loop will exit on next check
            break;
        }

        // guard: skip already visited destination nodes
        if (distance[edge[1]] >= 0) {
            continue;
        }

        relaxEdge(edge, distance);
        enqueueAdjacentEdges(edge[1], all_edges, distance, p_que);
    }
    return distance[end];
}

/** Updates the distance for the destination node of the given edge. */
private static void relaxEdge(int[] edge, int[] distance) {
    int from = edge[0];
    int to = edge[1];
    int weight = edge[2];
    distance[to] = distance[from] + weight;
}

/** Enqueues all outgoing edges of `node` whose target has not been visited yet. */
private static void enqueueAdjacentEdges(int node,
                                         Map<Integer, List<int[]>> all_edges,
                                         int[] distance,
                                         PriorityQueue<int[]> queue) {
    List<int[]> outgoing = all_edges.get(node);
    if (outgoing == null) {
        return;
    }
    for (int[] e : outgoing) {
        if (distance[e[1]] < 0) {
            queue.add(e);
        }
    }
}

