/**
 * Computes the "yay" and "whoops" scores while mutating the frequency
 * tables to reflect the letters that have been accounted for.
 *
 * @param freq_t frequency table for the original text (row 0 = lower, row 1 = upper)
 * @param freq_n frequency table for the new text (row 0 = lower, row 1 = upper)
 * @return an int array where index 0 is <yay> and index 1 is <whoops>
 */
private static int[] computeScores(int[][] freq_t, int[][] freq_n) {
    int yay = 0;
    int whoops = 0;

    for (int i = 0; i < 26; i++) {
        // match lower‑case letters from text to lower‑case letters from news
        if (freq_t[0][i] > 0) {
            int dif = freq_n[0][i] - freq_t[0][i];
            if (dif < 0) {
                freq_t[0][i] -= freq_n[0][i];
                yay += freq_n[0][i];
                freq_n[0][i] = 0;
            } else {
                yay += freq_t[0][i];
                freq_n[0][i] -= freq_t[0][i];
                freq_t[0][i] = 0;
            }
        }

        // match upper‑case letters from text to upper‑case letters from news
        if (freq_t[1][i] > 0) {
            int dif = freq_n[1][i] - freq_t[1][i];
            if (dif < 0) {
                freq_t[1][i] -= freq_n[1][i];
                yay += freq_n[1][i];
                freq_n[1][i] = 0;
            } else {
                yay += freq_t[1][i];
                freq_n[1][i] -= freq_t[1][i];
                freq_t[1][i] = 0;
            }
        }

        // match remaining lower‑case letters from text to upper‑case letters from news (whoops)
        if (freq_t[0][i] > 0) {
            int dif = freq_n[1][i] - freq_t[0][i];
            if (dif < 0) {
                freq_t[0][i] -= freq_n[1][i];
                whoops += freq_n[1][i];
                freq_n[1][i] = 0;
            } else {
                whoops += freq_t[0][i];
                freq_n[1][i] -= freq_t[0][i];
                freq_t[0][i] = 0;
            }
        }

        // match remaining upper‑case letters from text to lower‑case letters from news (whoops)
        if (freq_t[1][i] > 0) {
            int dif = freq_n[0][i] - freq_t[1][i];
            if (dif < 0) {
                freq_t[1][i] -= freq_n[0][i];
                whoops += freq_n[0][i];
                freq_n[0][i] = 0;
            } else {
                whoops += freq_t[1][i];
                freq_n[0][i] -= freq_t[1][i];
                freq_t[1][i] = 0;
            }
        }
    }

    return new int[] { yay, whoops };
}

