@SuppressWarnings("unchecked")
    void solve() throws IOException {
        final int n = nextInt();
        final int[] a = new int[n];
        for(int i = 0; i < n; i++) {
            a[i] = nextInt();
        }
        class Utils {
            int[] a;
            int[] extrema;

            public Utils(int[] a) {
                this.a = a;
                extrema = new int[a.length];
                for(int i = 1; i < a.length - 1; i++) {
                    if(Integer.signum(a[i] - a[i - 1]) * Integer.signum(a[i] - a[i + 1]) > 0) {
                        extrema[i] = i;
                    } else {
                        extrema[i] = extrema[i - 1];
                    }
                }
                extrema[a.length - 1] = extrema[a.length - 2];
            }

            long foo(int i) {
                if(i == 0) {
                    return 0;
                }
                int j = extrema[i];
                if(j == i) {
                    j = extrema[j - 1];
                }
                if(j == 0) {
                    return Math.abs(a[0] - a[i]);
                }
                return Math.max(Math.abs(a[i] - a[j]) + foo(j - 1), Math.abs(a[i] - a[j + 1]) + foo(j));
            }
        }
        class CachedUtils extends Utils {
            long[] cache;
            boolean[] hit;

            public CachedUtils(int[] a) {
                super(a);
                cache = new long[a.length];
                hit = new boolean[a.length];
            }

            @Override
            long foo(int i) {
                if(!hit[i]) {
                    hit[i] = true;
                    cache[i] = super.foo(i);
                }
                return cache[i];
            }
        }

        int i = 0;
        long answer = 0;
        for(int j = 0; j < n - 1; j++) {
            if(a[j + 1] == a[j]) {
                if(j - i + 1 > 1) {
                    int[] b = new int[j - i + 1];
                    System.arraycopy(a, i, b, 0, j - i + 1);
                    answer += new CachedUtils(b).foo(j - i);
                }
                i = j + 1;
            }
        }
        if(n - 1 - i + 1 > 1) {
            int[] b = new int[n - 1 - i + 1];
            System.arraycopy(a, i, b, 0, n - 1 - i + 1);
            answer += new CachedUtils(b).foo(n - 1 - i);
        }
        writer.println(answer);
    }

