        for (int i = 0; i < n; i++) a[i] = in.nextInt();

        if (n == 1) {
            out.println(0);
            return;
        }

        int[] l1 = new int[n], r1 = new int[n];
        Stack<Integer> stack = new Stack<>();
        for (int i = 0; i < n; i++) {
            while (!stack.isEmpty() && a[stack.peek()] <= a[i]) stack.pop();
            l1[i] = stack.isEmpty() ? 0 : stack.peek() + 1;
        }
        stack.clear();
        for (int i = n - 1; i >= 0; i--) {
            while (!stack.isEmpty() && a[stack.peek()] <= a[i]) stack.pop();
            r1[i] = stack.isEmpty() ? n - 1 : stack.peek() - 1;
        }

        int[] l2 = new int[n];
        int[] lmax = new int[30];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < 30; j++) {
                if ((a[i] & (1 << j)) == 0) {
                    l2[i] = Math.max(l2[i], lmax[j]);
                } else {
                    lmax[j] = i + 1;
                }
            }
        }
        int[] r2 = new int[n];
        Arrays.fill(r2, n - 1);
        int[] rmin = new int[30];
        Arrays.fill(rmin, n - 1);
        for (int i = n - 1; i >= 0; i--) {
            for (int j = 0; j < 30; j++) {
                if ((a[i] & (1 << j)) == 0) {
                    r2[i] = Math.min(r2[i], rmin[j]);
                } else {
                    rmin[j] = i - 1;
                }
            }
        }

        Queue<Integer> qu = new PriorityQueue<>((i, j) -> -Integer.compare(a[i], a[j]));
        for (int i = 0; i < n; i++) qu.offer(i);
        Map<Long, List<Integer>> ranges = new HashMap<>();
        while (!qu.isEmpty()) {
            int x = qu.poll();
            int l = Math.max(l1[x], l2[x]);
            int r = Math.min(r1[x], r2[x]);

            if (r > l) {
                long code = encode(l, r);
                if (!ranges.containsKey(code)) ranges.put(code, new ArrayList<>());
                ranges.get(code).add(x);
            }
        }

        long ans = choose2(n);
        for (long code : ranges.keySet()) {
            int[] t = decode(code);
            int l = t[0], r = t[1];
            long tot = choose2(r - l + 1);
            List<Integer> list = ranges.get(code);
            Collections.sort(list);
            if (list.get(0) != l) tot -= choose2(list.get(0) - l);
            for (int i = 0; i < list.size() - 1; i++) {
                tot -= choose2(list.get(i + 1) - list.get(i) - 1);
            }
            if (list.get(list.size() - 1) != r) tot -= choose2(r - list.get(list.size() - 1));
            ans -= tot;
        }
        out.println(ans);
    }

