/**
 * For each cell (i,j) where B[i][j] is false, the whole i‑th row and
 * j‑th column of A are set to false.
 */
private static void eliminateRowsAndCols(boolean[][] B, boolean[][] A) {
    int m = B.length;
    int n = B[0].length;
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (!B[i][j]) {
                // clear row i
                for (int k = 0; k < n; ++k) {
                    A[i][k] = false;
                }
                // clear column j
                for (int k = 0; k < m; ++k) {
                    A[k][j] = false;
                }
            }
        }
    }
}

/**
 * For each true cell in A, set the entire row and column in C to true.
 */
private static void propagateAtoC(boolean[][] A, boolean[][] C) {
    int m = A.length;
    int n = A[0].length;
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (A[i][j]) {
                // set row i in C
                for (int k = 0; k < n; ++k) {
                    C[i][k] = true;
                }
                // set column j in C
                for (int k = 0; k < m; ++k) {
                    C[k][j] = true;
                }
            }
        }
    }
}

/**
