 */
private static boolean matches(boolean[][] X, boolean[][] Y) {
    int m = X.length;
    int n = X[0].length;
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            if (X[i][j] != Y[i][j]) {
                return false;
            }
        }
    }
    return true;
}

