/**
 * Handles a single test case. The implementation mirrors the original logic,
 * but is isolated in its own method to improve readability and maintainability.
 */
private static void processCase(int n, long k, long x, String s, StringBuilder fout) {
    boolean hasA = false;
    ArrayList<Long> sequence = new ArrayList<>();
    char prev = 'a';

    // Build the sequence of repetition counts for consecutive '*' groups
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '*') {
            if (prev == 'a') {
                sequence.add(k);
            } else {
                int last = sequence.size() - 1;
                sequence.set(last, sequence.get(last) + k);
            }
        }
        prev = c;
        if (c == 'a') {
            hasA = true;
        }
    }
    if (!hasA) {
        x++;                     // adjust x when the string contains no 'a'
    }

    // Determine how many 'b's each '*' group should expand to
    ArrayList<Long> ans = new ArrayList<>(sequence.size());
    for (int i = 0; i < sequence.size(); i++) {
        ans.add(0L);
    }

    long mult = 1;
    int index = 0;
    outer:
    for (int i = sequence.size() - 1; i >= 0; i--) {
        long count = 1;
        while (count <= sequence.get(i) + 1) {
            if (mult * count > x) {
                index = i;
                break outer;
            }
            count++;
        }
        mult *= sequence.get(i) + 1;
    }

    for (int i = index; i < sequence.size(); i++) {
        ans.set(i, x / mult);
        x %= mult;
        if (i != sequence.size() - 1) {
            mult /= sequence.get(i + 1) + 1;
        }
    }

    // Build the final string using the computed repetitions
    int counter = 0;
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '*') {
            while (i < s.length() && s.charAt(i) == '*') {
                i++;
            }
            i--; // step back to the last '*' processed
            long repeat = ans.get(counter);
            for (long j = 0; j < repeat; j++) {
                fout.append('b');
            }
            counter++;
        } else {
            fout.append('a');
        }
    }
    fout.append('\n');
}

