		Reader.init(System.in);
		PrintWriter out=new PrintWriter(System.out);
		int n=Reader.nextInt(),m=Reader.nextInt();
		char[][] grid=new char[n][m];
		for(int i=0;i<n;i++) grid[i]=Reader.next().toCharArray();
		int[][] height=new int[n][m];
		int[][] length=new int[n][m],length2=new int[n][m];
		int[][] lastindex=new int[n][m];
		for(int i=0;i<n;i++) Arrays.fill(lastindex[i], -1);
		long ans=0;
		for(int i=0;i<n;i++) {
			for(int j=0;j<m;j++) {
				if(i==0) {
					height[i][j]=1;

					if(j==0) {
						length[i][j]=1;
						length2[i][j]=1;
					}

					else {
						if(grid[i][j]==grid[i][j-1] && height[i][j]==height[i][j-1]) {
							length[i][j]=length[i][j-1]+1;
						}
						else {
							length[i][j]=1;
						}
						if(grid[i][j]==grid[i][j-1]) {
							length2[i][j]=length2[i][j-1]+1;
						}
						else length2[i][j]=1;
					}
				}


				else {

					if(grid[i][j]==grid[i-1][j]) {

						height[i][j]=height[i-1][j]+1;
						lastindex[i][j]=lastindex[i-1][j];
						if(j==0) {
							length[i][j]=1;
							length2[i][j]=1;
						}
						else {
							if(grid[i][j]==grid[i][j-1] && height[i][j]==height[i][j-1]) {
								length[i][j]=length[i][j-1]+1;
								length[i][j]=Math.min(length[i][j], length[i-1][j]);
							}
							else {
								length[i][j]=1;
							}
							if(grid[i][j]==grid[i][j-1]) {
								length2[i][j]=length2[i][j-1]+1;
							}
							else length2[i][j]=1;
						}

					}

					else {
						height[i][j]=1;
						lastindex[i][j]=i-1;
						if(j==0) {
							length[i][j]=1;
							length2[i][j]=1;
						}
						else {
							if(grid[i][j]==grid[i][j-1] && height[i][j]==height[i][j-1]) {
								length[i][j]=length[i][j-1]+1;
							}
							else {
								length[i][j]=1;
							}
							if(grid[i][j]==grid[i][j-1]) {
								length2[i][j]=length2[i][j-1]+1;
							}
							else length2[i][j]=1;
						}

					}
				}
				int a=lastindex[i][j];
				if(a!=-1) {
					int b=lastindex[a][j];
					if(b!=-1 && height[i][j]==height[a][j]) {
						if(height[b][j]>=height[i][j]) {
							int ll=Math.min(length[i][j], length[a][j]);
							for(int k=b;k>b-height[i][j];k--) {
								ll=Math.min(length2[k][j], ll);
							}
							ans+=ll;
						}
					}
				}

			}
		}
		out.println(ans);
		out.flush();

	}

