static class ProcessResult {
    final boolean error;
    final int count;
    final List<Integer> cutPoints;

    ProcessResult(boolean error, int count, List<Integer> cutPoints) {
        this.error = error;
        this.count = count;
        this.cutPoints = cutPoints;
    }
}

/**
 * Extracted the core logic that analyses the integer array.
 * Returns a {@link ProcessResult} containing whether an error was detected,
 * the number of valid segments found and the indices (inclusive) where
 * each segment ends.
 */
private static ProcessResult analyzeArray(int[] arr) {
    Map<Integer, Integer> map = new HashMap<>();
    int count = 0;
    List<Integer> cutPoints = new ArrayList<>();

    int positiveSeen = 0;   // corresponds to variable 'one' in original code
    int paired = 0;         // corresponds to variable 'two'
    int previousCut = -1;   // corresponds to variable 'pre'

    boolean error = false;

    for (int i = 0; i < arr.length; i++) {
        int value = arr[i];

        if (value > 0) {
            // first occurrence of a positive number
            if (!map.containsKey(value)) {
                map.put(value, 1);
                positiveSeen++;
            } else {
                // duplicate positive number -> invalid
                error = true;
                break;
            }
        } else {
            int key = -value; // look for the matching positive number
            if (map.containsKey(key)) {
                if (map.get(key) > 0) {
                    // first time we meet the matching negative
                    map.put(key, 0);
                    paired++;
                    positiveSeen--;

                    // check whether we have closed a segment
                    if (i - previousCut == 2 * paired) {
                        previousCut = i;
                        count++;
                        cutPoints.add(i);
                        // reset state for the next segment
                        positiveSeen = 0;
                        paired = 0;
                        map = new HashMap<>();
                    }
                } else {
                    // negative seen twice -> invalid
                    error = true;
                    break;
                }
            } else {
                // no matching positive -> invalid
                error = true;
                break;
            }
        }
    }

    // After the loop, any remaining positive numbers make the input invalid
    if (!error) {
        for (Map.Entry<Integer, Integer> entry : map.entrySet()) {
            if (entry.getKey() > 0) {
                error = true;
                break;
            }
        }
    }

    return new ProcessResult(error, count, cutPoints);
}

