/**
 * Attempts to build the required answer for a given length {@code i}.
 * If a valid answer can be constructed it is printed to {@code pw}
 * and the method returns {@code true}; otherwise it returns {@code false}
 * without producing output.
 *
 * @param i    the current length being examined
 * @param cnta the mutable digit‑frequency array (already adjusted for {@code i})
 * @param b    the second input number as a character array
 * @param pw   the PrintWriter used for output
 * @return {@code true} if an answer was printed, {@code false} otherwise
 */
private static boolean tryConstructAnswer(int i, int[] cnta, char[] b, PrintWriter pw) {
    int first = 0;
    for (int j = 1; j < 10; j++) {
        if (cnta[j] > 0) {
            first = j;
            break;
        }
    }
    // condition that allows us to construct an answer
    if (first > 0 || b[0] != '0' || i == 1) {
        if (first > 0) {
            // ----- build answer that starts with a non‑zero digit -----
            cnta[first]--;
            int[] ans = new int[i];
            int size = 0;
            ans[size++] = first;

            // determine whether the block b must be placed before or after the
            // remaining digits of the same leading value
            boolean bigger = false;
            for (int j = 1; j < b.length; j++) {
                if (b[j] != b[0]) {
                    if (b[j] > b[0])
                        bigger = true;
                    break;
                }
            }

            for (int d = 0; d < 10; d++) {
                if (d == b[0] - '0' && !bigger) {
                    for (int k = 0; k < b.length; k++) {
                        ans[size++] = b[k] - '0';
                    }
                }
                for (int c = 0; c < cnta[d]; c++) {
                    ans[size++] = d;
                }
                if (d == b[0] - '0' && bigger) {
                    for (int k = 0; k < b.length; k++) {
                        ans[size++] = b[k] - '0';
                    }
                }
            }

            // ----- possibly replace with the version that puts b at the front -----
            if (b[0] > '0') {
                int[] ans2 = new int[i];
                int sz2 = 0;
                for (int k = 0; k < b.length; k++) {
                    ans2[sz2++] = b[k] - '0';
                }
                cnta[first]++; // restore the first digit for the alternative construction
                for (int d = 0; d < 10; d++) {
                    for (int c = 0; c < cnta[d]; c++) {
                        ans2[sz2++] = d;
                    }
                }
                // compare lexicographically
                int cmp = 0;
                for (int k = 0; k < i; k++) {
