                        break;
                    } else if (ans[k] < ans2[k]) {
                        cmp = -1;
                        break;
                    }
                }
                if (cmp == 1) {
                    ans = ans2.clone();
                }
                cnta[first]--; // re‑apply the decrement for the chosen answer
            }

            // print the chosen answer
            for (int k = 0; k < i; k++) {
