				int fs = udiag[i-1] ^ ddiag[i-1];
				long[] ndp = new long[2];
				if(fi == 2){
					for(int j = 0;j < 2;j++){
						ndp[j^fs] += dp[j];
					}
				}else if(fi == 1){
					ndp[0] = (dp[0] + dp[1]) % mod;
					ndp[1] = (dp[0] + dp[1]) % mod;
				}else{
					ndp[0] = (dp[0] + dp[1])*2L % mod;
					ndp[1] = (dp[0] + dp[1])*2L % mod;
				}
				dp = ndp;
			}
			long[] ndp = new long[2];
			if(diag[i] == 0){
				ndp[0] = dp[0];
			}else if(diag[i] == 1){
				ndp[1] = dp[1];
			}else{
				ndp[0] = dp[0];
				ndp[1] = dp[1];
			}
			dp = ndp;
		}

		out.println((dp[0]+dp[1])%mod * pow(2, free, mod) % mod);
	}

