/**
 * Performs the Dijkstra‑like exploration of the grid.
 *
 * @return the number of cells popped from the priority queue (i.e. visited)
 */
private static int exploreGrid(int n, int m, int startR, int startC,
                               long[][] x, long[][] y,
                               boolean[][] visit, int[][] lost,
                               String[] grid) {
    PriorityQueue<Node> heap = new PriorityQueue<>();
    heap.add(new Node(startR, startC, 0));

    visit[startR][startC] = true;
    lost[startR][startC] = 0;

    int[] dr = {1, 0, -1, 0};
    int[] dc = {0, 1, 0, -1};

    int visitedCount = 0;

    while (!heap.isEmpty()) {
        Node cur = heap.remove();
        int cr = cur.x;
        int cc = cur.y;

        if (cur.l > lost[cr][cc])
            continue;

        visitedCount++;

        for (int dir = 0; dir < 4; dir++) {
            int nr = cr + dr[dir];
            int nc = cc + dc[dir];

            if (nr < 0 || nr >= n || nc < 0 || nc >= m)
                continue;
            if (grid[nr].charAt(nc) == '*')
                continue;

            // vertical move (no resource consumption)
            if (dc[dir] == 0) {
                x[nr][nc] = x[cr][cc];
                y[nr][nc] = y[cr][cc];

                if (cur.l < lost[nr][nc]) {
                    heap.add(new Node(nr, nc, cur.l));
                    lost[nr][nc] = cur.l;
                }
            }
            // left move consumes x‑resource
            else if (dc[dir] == -1 && x[cr][cc] > 0) {
                x[nr][nc] = x[cr][cc] - 1;
                y[nr][nc] = y[cr][cc];

                if (cur.l + 1 < lost[nr][nc]) {
                    heap.add(new Node(nr, nc, cur.l + 1));
                    lost[nr][nc] = cur.l + 1;
                }
            }
            // right move consumes y‑resource
            else if (dc[dir] == 1 && y[cr][cc] > 0) {
                x[nr][nc] = x[cr][cc];
                y[nr][nc] = y[cr][cc] - 1;

                if (cur.l + 1 < lost[nr][nc]) {
                    heap.add(new Node(nr, nc, cur.l + 1));
                    lost[nr][nc] = cur.l + 1;
                }
            }
        }
    }
    return visitedCount;
}

