/**
 * Evaluates a specific set size {@code t} and returns a {@link Pair}
 * describing a valid solution, or {@code null} if the configuration is
 * invalid according to the original algorithm.
 */
private Pair evaluateT(int t, int[] play, int win, int lose,
                       int[] accWin, int[] accLose) {
    int cur = 0;
    int winscore = 0;
    int losescore = 0;
    int lastV = 0;
    boolean bad = false;

    while (cur < play.length) {
        int left = cur;
        int right = cur + t + t - 1;
        int bw = accWin[left];
        int bl = accLose[left];

        while (left <= play.length && left < right) {
            int m = (left + right) / 2;
            if (accWin[m] - bw >= t || accLose[m] - bl >= t) {
                right = m;
            } else {
                left = m + 1;
            }
        }

        if (accWin[left] - bw == t) {
            winscore++;
            lastV = win;
        } else if (accLose[left] - bl == t) {
            losescore++;
            lastV = lose;
        } else {
            bad = true;
            break;
        }
        cur = left;
    }

    if (!bad && winscore > losescore && lastV == win) {
        Pair p = new Pair();
        p.s = winscore;
        p.t = t;
        return p;
    }
    return null;
}

