/**
 * Performs a bubble‑sort on the {@code primary} array while moving the
 * corresponding elements of {@code secondary} in lock‑step. The algorithm
 * mirrors the original nested loops used in the program.
 *
 * @param primary   array that determines the ordering
 * @param secondary array that is reordered together with {@code primary}
 * @param length    number of elements to sort
 */
private static void bubbleSortByPrimary(int[] primary, int[] secondary, int length) {
    for (int j = 0; j < length; j++) {
        for (int i = 0; i < length - 1; i++) {
            if (primary[i] > primary[i + 1]) {
                int temp = primary[i];
                primary[i] = primary[i + 1];
                primary[i + 1] = temp;

                temp = secondary[i];
                secondary[i] = secondary[i + 1];
                secondary[i + 1] = temp;
            }
        }
    }
}

