 * cut position (1‑based) and replaces it with the two resulting sub‑pieces.
 *
 * The algorithm follows the original logic: it walks around the perimeter of
 * the rectangle, determines on which edge the cut falls, creates the two new
 * {@link Piece} objects in the correct order, adds them to the list and finally
 * removes the original piece.
 *
 * @param pieces    mutable list containing the current set of pieces
 * @param targetIdx index of the piece to be cut
 * @param rawPos    cut position on the perimeter (1‑based as read from input)
 */
private static void cutPiece(LinkedList<Piece> pieces, int targetIdx, int rawPos) {
    // keep a copy of the original position for possible future use
    int pos = rawPos;

    Piece temp = pieces.get(targetIdx);
    int circ = temp.h * 2 + temp.w * 2;

    // normalise position to the range [0, circ)
    pos = pos % circ;
    if (pos < 0) pos += circ;

    int px = 0, py = 0;

    if (pos <= temp.w) {                         // top edge
        px = pos;

        if (px * 2 > temp.w) {
            pieces.add(new Piece(temp.x + px, temp.y, temp.w - px, temp.h));
            pieces.add(new Piece(temp.x, temp.y, px, temp.h));
        } else {
            pieces.add(new Piece(temp.x, temp.y, px, temp.h));
            pieces.add(new Piece(temp.x + px, temp.y, temp.w - px, temp.h));
        }
    } else {
        px = temp.w;
        pos -= temp.w;

        if (pos <= temp.h) {                     // right edge
            py = pos;

            if (py * 2 > temp.h) {
                pieces.add(new Piece(temp.x, temp.y + py, temp.w, temp.h - py));
                pieces.add(new Piece(temp.x, temp.y, temp.w, py));
            } else {
                pieces.add(new Piece(temp.x, temp.y, temp.w, py));
                pieces.add(new Piece(temp.x, temp.y + py, temp.w, temp.h - py));
            }
        } else {
            py = temp.h;
            pos -= temp.h;

            if (pos <= temp.w) {                 // bottom edge
                px -= pos;

                if (px * 2 > temp.w) {
                    pieces.add(new Piece(temp.x + px, temp.y, temp.w - px, temp.h));
                    pieces.add(new Piece(temp.x, temp.y, px, temp.h));
                } else {
                    pieces.add(new Piece(temp.x, temp.y, px, temp.h));
                    pieces.add(new Piece(temp.x + px, temp.y, temp.w - px, temp.h));
                }
            } else {                             // left edge
                pos -= temp.w;
                px = 0;
                py = temp.h - pos;

                if (py * 2 > temp.h) {
                    pieces.add(new Piece(temp.x, temp.y + py, temp.w, temp.h - py));
                    pieces.add(new Piece(temp.x, temp.y, temp.w, py));
                } else {
                    pieces.add(new Piece(temp.x, temp.y, temp.w, py));
                    pieces.add(new Piece(temp.x, temp.y + py, temp.w, temp.h - py));
                }
            }
        }
    }

    // remove the original piece after its children have been added
    pieces.remove(targetIdx);
}

