 *
 * @param board a 3‑element array, each element being a string of length 3
 * @return a boolean array where index 0 indicates a win for player 1 ('X')
 *         and index 1 indicates a win for player 2 ('0')
 */
private boolean[] computeWins(String[] board) {
    boolean win1 = false, win2 = false;

    // rows
    for (int row = 0; row < 3; ++row) {
        if (board[row].charAt(0) == board[row].charAt(1) &&
            board[row].charAt(1) == board[row].charAt(2)) {
            if (board[row].charAt(0) == 'X')
                win1 = true;
            if (board[row].charAt(0) == '0')
