    for (int col = 0; col < 3; ++col) {
        if (board[0].charAt(col) == board[1].charAt(col) &&
            board[1].charAt(col) == board[2].charAt(col)) {
            if (board[0].charAt(col) == 'X')
                win1 = true;
            if (board[0].charAt(col) == '0')
                win2 = true;
        }
    }

    // main diagonal
    if (board[0].charAt(0) == board[1].charAt(1) &&
        board[1].charAt(1) == board[2].charAt(2)) {
        if (board[0].charAt(0) == 'X')
            win1 = true;
        if (board[0].charAt(0) == '0')
            win2 = true;
    }

    // anti‑diagonal
    if (board[0].charAt(2) == board[1].charAt(1) &&
        board[1].charAt(1) == board[2].charAt(0)) {
        if (board[0].charAt(2) == 'X')
            win1 = true;
        if (board[0].charAt(2) == '0')
            win2 = true;
    }

    return new boolean[] { win1, win2 };
}

