 * @param board a 3‑element array representing the tic‑tac‑toe board
 * @return an int array where index 0 is the count of X's (first player)
 *         and index 1 is the count of 0's (second player)
 */
private int[] countMarks(String[] board) {
    int p1 = 0, p2 = 0;
    for (String row : board) {
        for (int j = 0; j < 3; ++j) {
            char c = row.charAt(j);
            if (c == 'X')
