    int[][] right = new int[n][m];
    for (int i = n - 1; i >= 0; i--) {
        for (int j = m - 1; j >= 0; j--) {
            if (grid[i][j]) {
                bottom[i][j] = (i == n - 1) ? 1 : bottom[i + 1][j] + 1;
                right[i][j] = (j == m - 1) ? 1 : right[i][j + 1] + 1;
            }
        }
    }

    int[][] stars = new int[n][m];
    int count = 0;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int length = Math.min(Math.min(top[i][j], bottom[i][j]), Math.min(left[i][j], right[i][j]));
            if (length > 1) {
                stars[i][j] = length - 1;
                count++;
            }
        }
    }

    eraseCoveredCells(stars, grid, n, m);

    boolean cant = false;
    for (int i = 0; i < n && !cant; i++) {
        for (int j = 0; j < m && !cant; j++) {
            if (grid[i][j]) {
                cant = true;
            }
        }
    }

    if (cant) {
        out.println(-1);
    } else {
        out.println(count);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (stars[i][j] != 0) {
                    out.println((i + 1) + " " + (j + 1) + " " + stars[i][j]);
                }
            }
        }
    }

    out.flush();
}

/**
 * Removes cells that are covered by any star.
 *
 * The original implementation performed four passes:
 *   1. left‑to‑right scan per row,
 *   2. right‑to‑left scan per row,
 *   3. top‑to‑bottom scan per column,
 *   4. bottom‑to‑top scan per column.
 *
 * Each pass uses a counter {@code x} that represents the remaining
 * radius of the most recent star encountered in that direction.
 * If {@code x > 0}, the current cell is cleared.
 *
 * This method encapsulates that logic, keeping {@code main} focused on
 * I/O and high‑level algorithm steps.
 */
private static void eraseCoveredCells(int[][] stars, boolean[][] grid, int n, int m) {
    // Horizontal passes
    for (int i = 0; i < n; i++) {
        int x = 0;
        // left → right
        for (int j = 0; j < m; j++) {
            if (x != 0) {
                x--;
                grid[i][j] = false;
            }
            if (stars[i][j] != 0) {
                x = Math.max(x, stars[i][j]);
                grid[i][j] = false;
            }
        }
        x = 0;
        // right → left
        for (int j = m - 1; j >= 0; j--) {
            if (x != 0) {
                x--;
                grid[i][j] = false;
            }
            if (stars[i][j] != 0) {
                x = Math.max(x, stars[i][j]);
                grid[i][j] = false;
            }
        }
    }

    // Vertical passes
    for (int j = 0; j < m; j++) {
        int x = 0;
        // top → bottom
        for (int i = 0; i < n; i++) {
            if (x != 0) {
                x--;
                grid[i][j] = false;
            }
            if (stars[i][j] != 0) {
                x = Math.max(x, stars[i][j]);
                grid[i][j] = false;
            }
        }
        x = 0;
        // bottom → top
        for (int i = n - 1; i >= 0; i--) {
            if (x != 0) {
                x--;
                grid[i][j] = false;
            }
            if (stars[i][j] != 0) {
                x = Math.max(x, stars[i][j]);
                grid[i][j] = false;
            }
        }
    }
