/**
 * Determines the minimal number of operations required according to the
 * problem's rules. The returned value is 1, 2, 3 or 4.
 */
private static int computeMinimumOperations(char[][] map, int n, int m) {
    // 1‑move possibility: any whole border (top row, bottom row, left column,
    // right column) already contains only 'A'.
    if (isAnyFullBorder(map, n, m)) {
        return 1;
    }

    // 2‑move possibility:
    //   a) any corner cell is 'A'
    //   b) any complete row is free of 'P'
    //   c) any complete column is free of 'P'
    if (isAnyCornerA(map, n, m) || isAnyFullRow(map, n, m) || isAnyFullColumn(map, n, m)) {
        return 2;
    }

    // 3‑move possibility: any cell on the border is 'A'
    if (isAnyBorderCellA(map, n, m)) {
        return 3;
    }

    // Otherwise we need 4 moves.
    return 4;
}

/** Returns true if at least one of the four borders contains only 'A'. */
private static boolean isAnyFullBorder(char[][] map, int n, int m) {
    // left column
    boolean leftAllA = true;
    for (int i = 0; i < n; i++) {
        if (map[i][0] == 'P') {
            leftAllA = false;
            break;
        }
    }
    if (leftAllA) return true;

    // top row
    boolean topAllA = true;
    for (int j = 0; j < m; j++) {
        if (map[0][j] == 'P') {
            topAllA = false;
            break;
        }
    }
    if (topAllA) return true;

    // bottom row
    boolean bottomAllA = true;
    for (int j = 0; j < m; j++) {
        if (map[n - 1][j] == 'P') {
            bottomAllA = false;
            break;
        }
    }
    if (bottomAllA) return true;

    // right column
    boolean rightAllA = true;
    for (int i = 0; i < n; i++) {
        if (map[i][m - 1] == 'P') {
            rightAllA = false;
            break;
        }
    }
    return rightAllA;
}

/** Returns true if any of the four corner cells contains 'A'. */
private static boolean isAnyCornerA(char[][] map, int n, int m) {
    return map[0][0] == 'A' ||
           map[0][m - 1] == 'A' ||
           map[n - 1][0] == 'A' ||
           map[n - 1][m - 1] == 'A';
}

/** Returns true if any row contains only 'A' (i.e., no 'P' at all). */
private static boolean isAnyFullRow(char[][] map, int n, int m) {
    for (int i = 0; i < n; i++) {
        boolean allA = true;
        for (int j = 0; j < m; j++) {
            if (map[i][j] == 'P') {
                allA = false;
                break;
            }
        }
        if (allA) return true;
    }
    return false;
}

/** Returns true if any column contains only 'A' (i.e., no 'P' at all). */
private static boolean isAnyFullColumn(char[][] map, int n, int m) {
    for (int j = 0; j < m; j++) {
        boolean allA = true;
        for (int i = 0; i < n; i++) {
            if (map[i][j] == 'P') {
                allA = false;
                break;
            }
        }
        if (allA) return true;
    }
    return false;
}

/** Returns true if any cell on the outer border is 'A'. */
private static boolean isAnyBorderCellA(char[][] map, int n, int m) {
    // left column
    for (int i = 0; i < n; i++) {
        if (map[i][0] == 'A') return true;
    }
    // top row
    for (int j = 0; j < m; j++) {
        if (map[0][j] == 'A') return true;
    }
    // bottom row
    for (int j = 0; j < m; j++) {
        if (map[n - 1][j] == 'A') return true;
    }
    // right column
    for (int i = 0; i < n; i++) {
        if (map[i][m - 1] == 'A') return true;
    }
    return false;
}

