/**
 * Computes the distance matrix for a single input line.
 *
 * @param line the binary string representing the current row
 * @param rowIndex the index of the row being processed
 * @param matr the full distance matrix to fill
 * @param m the number of columns
 * @return {@code true} if the row contains at least one '1',
 *         {@code false} otherwise (indicating a zero‑only line).
 */
private static boolean processRow(String line, int rowIndex, int[][] matr, int m) {
    boolean[] lineb = new boolean[m];
    for (int j = 0; j < m; j++) {
        lineb[j] = line.charAt(j) == '1';
    }

    int prev = -1;
    int first = -1;
    for (int j = 0; j < m; j++) {
        if (lineb[j]) {
            matr[rowIndex][j] = 0;
            if (prev == -1) {
                // Fill cells to the left of the first '1'
                for (int k = j - 1; k >= 0; k--) {
                    matr[rowIndex][k] = matr[rowIndex][k + 1] + 1;
                }
                prev = j;
                first = j;
            } else {
                // Fill cells between two consecutive '1's
                for (int k = 1; k <= (j - prev) / 2; k++) {
                    matr[rowIndex][prev + k] = matr[rowIndex][prev + k - 1] + 1;
                    matr[rowIndex][j - k] = matr[rowIndex][j - k + 1] + 1;
                }
                prev = j;
            }
        }
    }

    // No '1' found in this line
    if (prev == -1) {
        return false;
    }

    // Fill cells to the right of the last '1'
    for (int k = prev + 1; k < m; k++) {
        matr[rowIndex][k] = matr[rowIndex][k - 1] + 1;
    }

    // Handle wrap‑around distances (circular array)
    if (m - 1 - prev > first) {
        int curr = m - 1;
        matr[rowIndex][curr] = matr[rowIndex][0] + 1;
        while (matr[rowIndex][curr] + 1 < matr[rowIndex][curr - 1]) {
            matr[rowIndex][curr - 1] = matr[rowIndex][curr] + 1;
            curr--;
        }
    } else if (m - 1 - prev < first) {
        int curr = 0;
        matr[rowIndex][curr] = matr[rowIndex][m - 1] + 1;
        while (matr[rowIndex][curr] + 1 < matr[rowIndex][curr + 1]) {
            matr[rowIndex][curr + 1] = matr[rowIndex][curr] + 1;
            curr++;
        }
    }

    return true;
}

