/**
 * Handles all assignment and consistency checks for a single vertex.
 * Mutates the shared {@code str} array and the {@code correct} flag.
 *
 * @param i the index of the vertex to process
 * @param n total number of vertices in the graph
 */
private static void evaluateVertex(int i, int n) {
    // Process neighbours that are already colored (0,2) and detect conflicts
    for (Integer ver : g.get(i)) {
        if (str[ver] == 1 || str[ver] == -1)
            continue;
        if (str[i] == -1) {
            str[i] = str[ver] == 0 ? 0 : 2;
        } else {
            if (str[i] != str[ver])
                correct = false;
        }
    }

    // Process non‑neighbours that are already colored and detect conflicts
    for (int ver = 0; ver < n; ver++) {
        if (ver == i)
            continue;
        if (g.get(i).contains(ver) || str[ver] == -1)
            continue;
        if (str[ver] == 1)
            correct = false;
        if (str[i] == -1) {
            str[i] = str[ver] == 0 ? 2 : 0;
        } else {
            if (str[i] == str[ver])
                correct = false;
        }
    }

    // Assign a default colour if still unassigned
    if (str[i] == -1)
        str[i] = 0;

    // Propagate the colour to uncoloured neighbours
    for (Integer ver : g.get(i)) {
        if (str[ver] == -1)
            str[ver] = str[i] == 0 ? 0 : 2;
    }

    // Propagate the colour to uncoloured non‑neighbours
    for (int ver = 0; ver < n; ver++) {
        if (ver == i)
            continue;
        if (!g.get(i).contains(ver) && str[ver] == -1) {
            str[ver] = str[i] == 0 ? 2 : 0;
        }
    }
}

