                connections[k][i][j] = -1;

    // horizontal connections
    for (int i = 0; i < n; i++) {
        Map<Integer, Integer> cache = new HashMap<>();
        for (int j = 0; j < m; j++) {
            if (cache.containsKey(mp[i][j])) {
                int y = cache.get(mp[i][j]);
                connections[0][i][y] = j;   // right
                connections[1][i][j] = y;   // left
            }
            cache.put(mp[i][j], j);
        }
    }
    // vertical connections
    for (int j = 0; j < m; j++) {
        Map<Integer, Integer> cache = new HashMap<>();
        for (int i = 0; i < n; i++) {
            if (cache.containsKey(mp[i][j])) {
                int x = cache.get(mp[i][j]);
                connections[2][x][j] = i;   // down
                connections[3][i][j] = x;   // up
            }
            cache.put(mp[i][j], i);
        }
    }

    boolean[][] visit = new boolean[n][m];
    int[] maxR = new int[n];
    int[] maxC = new int[m];
    Queue<Integer> queue = new LinkedList<>();

    int[] nums = new int[n * m * 2];   // temporary buffer for a component
    int nm = n * m;

    for (int i = 0; i < nm; i++) {
        Node node = nodes[i];
        if (!visit[node.x][node.y]) {
            processComponent(node.x, node.y, visit, connections, maxR, maxC, mp, nums, queue);
        }
    }

    PrintWriter pw = new PrintWriter(new OutputStreamWriter(System.out));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (j != 0) pw.print(' ');
            pw.print(mp[i][j]);
        }
        pw.println();
    }
    pw.close();
}

/**
 * Explores a connected component starting from (sx, sy), updates the maximum
 * reachable distance for each row and column, and writes the new values back
 * into {@code mp}.
 *
 * The method mutates {@code visit}, {@code maxR}, {@code maxC}, {@code mp},
 * and uses {@code nums} as a reusable buffer to avoid repeated allocations.
 */
private static void processComponent(int sx, int sy,
                                     boolean[][] visit,
                                     int[][][] connections,
                                     int[] maxR,
                                     int[] maxC,
                                     int[][] mp,
                                     int[] nums,
                                     Queue<Integer> queue) {
    int nn = 0;            // number of coordinates stored in nums (pairs)
    int val = 0;           // maximum value for the whole component

    // seed the BFS with the starting cell
    queue.add(sx);
    queue.add(sy);
    visit[sx][sy] = true;
    nums[nn++] = sx;
    nums[nn++] = sy;

    while (!queue.isEmpty()) {
        int x = queue.poll();
        int y = queue.poll();

        // update the component's maximal value based on current row/col
        val = Math.max(maxR[x] + 1, val);
        val = Math.max(maxC[y] + 1, val);

        // traverse all four directions (right, left, down, up)
        for (int k = 0; k < 4; k++) {
            if (connections[k][x][y] >= 0) {
                int xx = (k >= 2) ? connections[k][x][y] : x;
                int yy = (k >= 2) ? y : connections[k][x][y];
                if (!visit[xx][yy]) {
                    queue.add(xx);
                    queue.add(yy);
                    nums[nn++] = xx;
                    nums[nn++] = yy;
                    visit[xx][yy] = true;
                }
            }
        }
    }

    // assign the computed value to every cell of the component
    for (int i = 0; i < nn; i += 2) {
        int x = nums[i];
        int y = nums[i + 1];
        maxR[x] = val;
        maxC[y] = val;
        mp[x][y] = val;
    }
}

