		int t1 = 0, t2 = 0;
		for (int i = 0; i < N; i++) {
			a[i] = sc.nextInt();
			if (i != 0) {
				pre[0][i] = pre[0][i - 1];
				pre[1][i] = pre[1][i - 1];
			}
			if (a[i] == 1) {
				pos[0][++t1] = i;
				pre[0][i]++;
			} else {
				pos[1][++t2] = i;
				pre[1][i]++;
			}
		}

		for (int t = 1; t <= N; t++) {

			int idx = -1;
			int prevIdx = -1;
			int oneWins = 0, twoWins = 0;
			while (idx < N) {
				prevIdx = idx;
				int seenOnes = idx == -1 ? 0 : pre[0][idx], seenTwos = idx == -1 ? 0 : pre[1][idx];
				if (t + seenOnes > N || t + seenTwos > N)
					break;
				int idxOne = pos[0][t + seenOnes], idxTwo = pos[1][t + seenTwos];
				int nxtIdx = -1;
				if (idxOne == -1)
					nxtIdx = idxTwo;
				else if (idxTwo == -1)
					nxtIdx = idxOne;
				else if (idxOne < idxTwo)
					nxtIdx = idxOne;
				else
					nxtIdx = idxTwo;

