/**
 * Finds the diameter of the connected component that contains {@code start},
 * stores it in {@code ds.path} for the component's representative, and marks all
 * vertices of the component as visited.
 */
private static void processComponent(int start,
                                     ArrayList<Integer>[] adj,
                                     DisjointSet ds,
                                     boolean[] visited) {
    // First BFS – discover the component and obtain one endpoint of its diameter
    ArrayDeque<Integer> bfs = new ArrayDeque<>();
    bfs.add(start);
    visited[start] = true;

    int farthest = start;
    while (!bfs.isEmpty()) {
        int node = bfs.remove();
        farthest = node;
        for (int nxt : adj[node]) {
            if (!visited[nxt]) {
                visited[nxt] = true;
                bfs.add(nxt);
            }
        }
    }

    // Second BFS – compute the actual diameter starting from {@code farthest}
    ArrayDeque<Integer> queue = new ArrayDeque<>();
    queue.add(farthest);   // node
    queue.add(-1);         // parent (none)
    queue.add(0);          // distance from start

    int diameter = 0;
    while (!queue.isEmpty()) {
        int node = queue.remove();
        int parent = queue.remove();
        int dist = queue.remove();

        if (dist > diameter) {
            diameter = dist;
