/**
 * Fills {@code row} and {@code column} arrays based on the characters present in the map.
 * The method encodes parity constraints for each row and column:
 *   - bit 1 (value 1) indicates that an even index cell of the corresponding type was seen,
 *   - bit 2 (value 2) indicates that an odd index cell of the corresponding type was seen.
 * If both bits become set (value 3) the configuration is invalid, which is checked later
 * by the caller.
 *
 * @param map    the n×m character grid
 * @param row    array to receive per‑row parity information (size n)
 * @param column array to receive per‑column parity information (size m)
 */
private static void computeRowColumnConstraints(char[][] map, int[] row, int[] column) {
    int n = map.length;
    int m = map[0].length;

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            char cell = map[i][j];
            if (cell == '1') {
                // column parity
                if (i % 2 == 0) {
                    column[j] |= 1;
                } else {
                    column[j] |= 2;
                }
                // row parity
                if (j % 2 == 0) {
                    row[i] |= 1;
                } else {
                    row[i] |= 2;
                }
            } else if (cell == '2') {
                if (i % 2 == 0) {
                    column[j] |= 2;
                } else {
                    column[j] |= 1;
                }
                if (j % 2 == 0) {
                    row[i] |= 1;
                } else {
                    row[i] |= 2;
                }
            } else if (cell == '3') {
                if (i % 2 == 0) {
                    column[j] |= 2;
                } else {
                    column[j] |= 1;
                }
                if (j % 2 == 0) {
                    row[i] |= 2;
                } else {
                    row[i] |= 1;
                }
            } else if (cell == '4') {
                if (i % 2 == 0) {
                    column[j] |= 1;
                } else {
                    column[j] |= 2;
                }
                if (j % 2 == 0) {
                    row[i] |= 2;
                } else {
                    row[i] |= 1;
                }
            }
        }
    }
}

