/**
 * Processes a single query while keeping the simulation state.
 *
 * @param qd          the query object containing the target step (a) and its original index (b)
 * @param ll          the mutable list representing the current ordering of elements
 * @param n           the original size of the list
 * @param operations  the number of operations already performed before this query
 * @param arr         temporary array used when the list has been fully processed
 * @param ans         matrix that stores the answers for all queries
 * @return the updated number of performed operations after handling this query
 */
private static int handleQuery(NoD qd, LinkedList<Integer> ll, int n, int operations,
                               int[] arr, int[][] ans) {
    long v = qd.a - operations;

    if (operations < n - 1) {
        if (v == 1) {
            int aa = ll.pollFirst();
            int b = ll.peekFirst();
            ll.addFirst(aa);
            ans[qd.b][0] = aa;
            ans[qd.b][1] = b;
        } else {
            while (v != 1 && operations < n - 1) {
                operations++;
                v--;
                int aa = ll.pollFirst();
                int bb = ll.pollFirst();
                if (aa > bb) {
                    ll.addFirst(aa);
                    ll.addLast(bb);
                } else {
                    ll.addLast(aa);
                    ll.addFirst(bb);
                }
            }
            if (operations == n - 1) {
                for (int i = 0; i < n; i++) {
                    arr[i] = ll.pollFirst();
                }
                int el = (int) (v % (n - 1));
                if (el == 0) el = n - 1;
                ans[qd.b][0] = arr[0];
                ans[qd.b][1] = arr[el];
            } else {
                int aa = ll.pollFirst();
                int b = ll.peekFirst();
                ll.addFirst(aa);
                ans[qd.b][0] = aa;
                ans[qd.b][1] = b;
            }
        }
    } else {
        int el = (int) (v % (n - 1));
        if (el == 0) el = n - 1;
        ans[qd.b][0] = arr[0];
        ans[qd.b][1] = arr[el];
    }

    return operations;
}

