void run() {
        while (true) {
            int n = readInt();
            if (n == 0) break;
            int[] num = new int[n];
            int[] x = new int[n];
            int[] y = new int[n];
            for (int i = 0; i < n; i++) {
                num[i] = readInt();
                x[i] = readInt();
                y[i] = readInt();
            }
            int m = readInt();
            int[] start = new int[m];
            int[] goal = new int[m];
            for (int i = 0; i < m; i++) {
                start[i] = readInt();
                goal[i] = readInt();
                for (int j = 0; j < n; j++) {
                    if (start[i] == num[j]) {
                        start[i] = j;
                        break;
                    }
                }
                for (int j = 0; j < n; j++) {
                    if (goal[i] == num[j]) {
                        goal[i] = j;
                        break;
                    }
                }
            }


            for (int i = 0; i < m; i++) {
                PriorityQueue<State> que = new PriorityQueue<State>();
                que.add(new State(start[i], 0));
                double[] d = new double[n];
                int[] prev = new int[n];
                Arrays.fill(d, Double.MAX_VALUE);
                Arrays.fill(prev, -1);
                d[start[i]] = 0;
                while (!que.isEmpty()) {
                    State state = que.poll();

                    if (state.cost > d[state.pos]) {
                        continue;
                    }
                    for (int j = 0; j < n; j++) {
                        int dx = x[state.pos] - x[j];
                        int dy = y[state.pos] - y[j];
                        double l = Math.sqrt(dx*dx+dy*dy);
                        if (l <= 50 + 1e-8) {
                            if (d[j] > state.cost + l) {
                                d[j] = state.cost + l;
                                prev[j] = state.pos;

                                que.add(new State(j, state.cost + l));
                            }
                        }
                    }
                }
                ArrayList<Integer> route = new ArrayList<Integer>();
                for (int p = goal[i]; p != -1; p = prev[p]) {
                    route.add(num[p]);
                }
                Collections.reverse(route);
                if (d[goal[i]] == Double.MAX_VALUE) {
                    sysout.println("NA");
                } else {
                    sysout.println(join(route, " "));
                }
            }
        }
    }

