/**
 * Handles the situation where the current prefix of the answer still respects the
 * “all‑prime‑factors‑available” condition.
 *
 * @param idx   index in {@code ar} being processed
 * @param ar    the array being filled
 * @param tr    the TreeSet containing still‑available prime numbers
 * @param sieve smallest‑prime‑factor array
 * @return {@code true} if the prefix up to {@code idx} still satisfies the condition,
 *         {@code false} otherwise (meaning subsequent positions will be filled with
 *         the smallest remaining primes).
 */
private boolean handleEqualCase(int idx, int[] ar, TreeSet<Integer> tr, int[] sieve) {
    List<Integer> primeFactors = distinctPrimeFactors(ar[idx], sieve);

    // check whether all prime factors are still present in the set
    boolean allPresent = true;
    for (int p : primeFactors) {
        if (!tr.contains(p)) {
            allPresent = false;
            break;
        }
    }

    if (allPresent) {
        // consume the primes and keep the “equal” flag true
        for (int p : primeFactors) {
            tr.remove(p);
        }
        return true;
    }

    // need to find the next suitable number
    final int LIMIT = 200_000 + 1;
    for (int candidate = ar[idx] + 1; candidate < LIMIT; candidate++) {
        List<Integer> candFactors = distinctPrimeFactors(candidate, sieve);
        boolean missing = false;
        for (int p : candFactors) {
            if (!tr.contains(p)) {
                missing = true;
                break;
            }
        }
        if (!missing) {
            ar[idx] = candidate;
            for (int p : candFactors) {
                tr.remove(p);
            }
            break;
        }
    }
    // after picking a larger number the prefix is no longer equal to the original array
    return false;
}

/**
 * Returns a list of distinct prime factors of {@code value} using the provided
 * smallest‑prime‑factor sieve.
 *
 * @param value the number to factorise (value &gt;= 1)
 * @param sieve smallest‑prime‑factor array
 * @return list of distinct prime factors in the order they appear during division
 */
private List<Integer> distinctPrimeFactors(int value, int[] sieve) {
    List<Integer> factors = new ArrayList<>();
    java.util.HashSet<Integer> seen = new java.util.HashSet<>();
    while (value != 1) {
        int p = sieve[value];
        if (seen.add(p)) {
            factors.add(p);
        }
        value /= p;
    }
    return factors;
}

