/**
 * Constructs the lexicographically smallest palindrome that satisfies the
 * given number of zeros and ones, filling the '?' characters in the input
 * string. Returns the resulting string, or "-1" if it is impossible.
 */
private static String buildPalindrome(int zeros, int ones, String s) {
    int n = s.length();
    // If the total number of required characters does not match the length,
    // the task is impossible.
    if (zeros + ones != n) {
        return "-1";
    }

    char[] result = new char[n];
    int z = zeros;
    int o = ones;

    // Copy original characters and account for already fixed zeros/ones.
    for (int i = 0; i < n; i++) {
        char ch = s.charAt(i);
        result[i] = ch;
        if (ch == '0') {
            z--;
        } else if (ch == '1') {
            o--;
        }
    }

    // First pass: resolve positions where one side is known and the other is '?'.
    for (int i = 0; i < n / 2; i++) {
        char left = s.charAt(i);
        char right = s.charAt(n - i - 1);

        // Contradicting fixed characters make a palindrome impossible.
        if ((left == '0' && right == '1') || (left == '1' && right == '0')) {
            return "-1";
        }

        if (left == '?' && right != '?') {
            if (right == '1') {
                if (o > 0) {
                    result[i] = '1';
                    o--;
                } else {
                    return "-1";
                }
            } else { // right == '0'
                if (z > 0) {
                    result[i] = '0';
                    z--;
                } else {
                    return "-1";
                }
            }
        } else if (right == '?' && left != '?') {
            if (left == '1') {
                if (o > 0) {
                    result[n - i - 1] = '1';
                    o--;
                } else {
                    return "-1";
                }
            } else { // left == '0'
                if (z > 0) {
                    result[n - i - 1] = '0';
                    z--;
                } else {
                    return "-1";
                }
            }
        } else {
            // Both are fixed (or both '?'), nothing to do here.
            if (left != right) {
                return "-1";
            }
        }
    }

    // Second pass: fill pairs where both sides are '?'.
    for (int i = 0; i < n / 2; i++) {
        char left = s.charAt(i);
        char right = s.charAt(n - i - 1);
        if (left == '?' && right == '?') {
            if (z >= 2) {
                result[i] = result[n - i - 1] = '0';
                z -= 2;
            } else if (o >= 2) {
                result[i] = result[n - i - 1] = '1';
                o -= 2;
            } else {
                return "-1";
            }
        }
    }

    // Handle middle character for odd length strings.
    if (n % 2 == 1) {
        char mid = s.charAt(n / 2);
        if (mid == '?') {
            if (o > 0) {
                result[n / 2] = '1';
                o--;
            } else if (z > 0) {
                result[n / 2] = '0';
                z--;
            } else {
                return "-1";
            }
        }
    }

    // After all replacements, we must have used exactly the required number
    // of zeros and ones.
    if (o != 0 || z != 0) {
        return "-1";
    }

    return new String(result);
}

