/**
 * Advances the deque simulation until {@code targetPerm} (inclusive) is reached.
 * Updates {@code state} ({@code lastPerm, lastA, lastB}) and stores the answer
 * for the current {@code requestIdx} at each step.
 */
private void advanceDequeUntil(int targetPerm,
                               Deque<Integer> deque,
                               int[] state,
                               Map<Integer, Integer> ansA,
                               Map<Integer, Integer> ansB,
                               int requestIdx) {
    while (state[0] < targetPerm) {
        state[0]++; // advance permutation counter
        int A = deque.pollFirst();
        int B = deque.pollFirst();
        state[1] = A;
        state[2] = B;
        ansA.put(requestIdx, A);
        ansB.put(requestIdx, B);
        if (A > B) {
            deque.addFirst(A);
            deque.addLast(B);
        } else {
            deque.addFirst(B);
            deque.addLast(A);
        }
    }
}

/**
 * Creates a snapshot of the current deque contents in order.
 */
private List<Integer> snapshotDeque(Deque<Integer> deque) {
    List<Integer> list = new ArrayList<>();
    for (Integer v : deque) {
        list.add(v);
    }
    return list;
}

