/**
 * Matches horizontal and vertical dancers that share the same (t-p) difference.
 * The logic is symmetric for both maps; it fills the {@code ans} map with the
 * final destination index for every dancer.
 */
private void matchDancersByDiff(
        HashMap<Integer, ArrayList<Dancer>> horMap,
        HashMap<Integer, ArrayList<Dancer>> verMap,
        HashMap<Integer, Integer> ans) {

    // ----- handle groups where a horizontal list exists (and possibly a vertical list) -----
    for (Entry<Integer, ArrayList<Dancer>> kv : horMap.entrySet()) {
        ArrayList<Dancer> horList = kv.getValue();
        ArrayList<Dancer> verList = verMap.getOrDefault(kv.getKey(), null);

        if (verList == null) {
            // no vertical partner – each dancer stays at its own position
            for (Dancer d : horList)
                ans.put(d.num, d.num);
            continue;
        }

        // pair from the end of horList with the start of verList
        int hori = horList.size() - 1;
        int veri = 0;
        while (hori >= 0 && veri < verList.size()) {
            ans.put(horList.get(hori).num, verList.get(veri).num);
            hori--;
            veri++;
        }

        // if there are leftovers in the horizontal list, shift them forward
        if (horList.size() > verList.size()) {
            int shift = verList.size();
            hori = 0;
            while (!ans.containsKey(horList.get(hori).num)) {
                ans.put(horList.get(hori).num, horList.get(hori + shift).num);
                hori++;
            }
        }
    }

    // ----- handle groups where a vertical list exists (and possibly a horizontal list) -----
    for (Entry<Integer, ArrayList<Dancer>> kv : verMap.entrySet()) {
        ArrayList<Dancer> verList = kv.getValue();
        ArrayList<Dancer> horList = horMap.getOrDefault(kv.getKey(), null);

        if (horList == null) {
            // no horizontal partner – each dancer stays at its own position
            for (Dancer d : verList)
                ans.put(d.num, d.num);
            continue;
        }

        // pair from the end of verList with the start of horList
        int veri = verList.size() - 1;
        int hori = 0;
        while (veri >= 0 && hori < horList.size()) {
            ans.put(verList.get(veri).num, horList.get(hori).num);
            hori++;
            veri--;
        }

        // if there are leftovers in the vertical list, shift them forward
        if (verList.size() > horList.size()) {
            int shift = horList.size();
            veri = 0;
            while (!ans.containsKey(verList.get(veri).num)) {
                ans.put(verList.get(veri).num, verList.get(veri + shift).num);
                veri++;
            }
        }
    }
