/**
 * Computes the maximum possible area for a single digit and updates the
 * corresponding entry in {@code ans}.
 *
 * @param digit the digit (0‑9) being processed
 * @param B     the numeric grid
 * @param n     the grid size
 * @param ans   array holding the best area for each digit; {@code ans[digit]} will be updated
 */
private static void processDigit(int digit, int[][] B, int n, long[] ans) {
    // 1) Row‑wise contribution
    for (int row = 0; row < n; row++) {
        int first = -1;
        int last = -1;
        for (int col = 0; col < n; col++) {
            if (B[row][col] == digit) {
                last = col;
                if (first == -1)
                    first = col;
            }
        }
        ans[digit] = Math.max(ans[digit], (long) (last - first) * Math.max(row, n - 1 - row));
    }

    // 2) Column‑wise contribution
    for (int col = 0; col < n; col++) {
        int first = -1;
        int last = -1;
        for (int row = 0; row < n; row++) {
            if (B[row][col] == digit) {
                last = row;
                if (first == -1)
                    first = row;
            }
        }
        ans[digit] = Math.max(ans[digit], (long) (last - first) * Math.max(col, n - 1 - col));
    }

    // 3) Positions list & area using extreme coordinates
    ArrayList<Game> all = new ArrayList<>();
    ArrayList<Game1> all1 = new ArrayList<>();
    for (int row = 0; row < n; row++) {
        for (int col = 0; col < n; col++) {
            if (B[row][col] == digit) {
                all.add(new Game(row, col));
                all1.add(new Game1(row, col));
            }
        }
    }

    // No rectangle can be formed if the digit appears only once
    if (all.size() <= 1)
        return;

    Collections.sort(all);
    Collections.sort(all1);
    int size = all.size();

    // Using sorted rows (Game) – vary y, keep extreme x’s
    for (int idx = 0; idx < size; idx++) {
        int y = all.get(idx).y;
        int x = all.get(idx).x;
        long width = Math.max(x, n - 1 - x);
        long height = Math.max(all.get(size - 1).x - x, x - all.get(0).x);
        long area = width * height;
        ans[digit] = Math.max(ans[digit], area);
    }

    // Using sorted columns (Game1) – vary x, keep extreme y’s
    for (int idx = 0; idx < size; idx++) {
        int y = all1.get(idx).y;
        int x = all1.get(idx).x;
        long height = Math.max(y, n - 1 - y);
        long width = Math.max(all1.get(size - 1).y - y, y - all1.get(0).y);
        long area = width * height;
        ans[digit] = Math.max(ans[digit], area);
    }
