/**
 * Simulates the incremental accumulation process for arrays larger than 12 elements.
 *
 * The algorithm repeatedly builds a new array {@code na} where each element is the sum of
 * the previous element of {@code na} and the corresponding element of {@code a}.
 * It stops when either an overflow occurs, the last element reaches {@code k},
 * or the process would otherwise continue indefinitely.
 *
 * @param a the trimmed input array (all elements are < k)
 * @param k the target value
 * @return the number of successful iterations performed before termination
 */
private static int simulateStepsForLargeArray(long[] a, long k) {
    int n = a.length;
    int steps = 0;
    boolean overflow = false;

    while (!overflow) {
        steps++;
        long[] na = new long[n];
        for (int i = 0; i < n; i++) {
            try {
                long previous = (i > 0) ? na[i - 1] : 0L;
                na[i] = Math.addExact(previous, a[i]);
            } catch (ArithmeticException e) {
                overflow = true;
                break;
            }
        }
        if (overflow) {
            break;
        }
        if (na[n - 1] >= k) {
            break;
        }
        a = na; // continue with the newly generated array
    }
    return steps;
}

