/**
 * Processes a single test case.
 *
 * @param s binary string consisting of '0' and '1'
 * @param x distance parameter described in the original algorithm
 * @return "-1" if the configuration is impossible; otherwise a string representation
 *         of the resulting w array (each element concatenated without spaces)
 */
private static String processCase(String s, int x) {
    char[] ch = s.toCharArray();
    int[] arr = new int[ch.length];
    for (int j = 0; j < ch.length; j++) {
        arr[j] = ch[j] - '0';
    }

    int n = ch.length;
    int[] w = new int[n];
    Arrays.fill(w, 1);

    // Block 1 – disable positions that must be 0 because of a '0' in arr
    for (int j = 0; j < n; j++) {
        if (arr[j] == 0) {
            if (j - x >= 0) w[j - x] = 0;
            if (j + x < n) w[j + x] = 0;
        }
    }

    // Block 2 – verify that every '1' in arr can be satisfied
    int idx = 0;
    while (idx < n) {
        if (arr[idx] == 1) {
            boolean canSatisfy = false;

            // try left neighbour
            if (idx - x >= 0 && w[idx - x] == 1) {
                canSatisfy = true;
            }
            // try right neighbour
            else if (idx + x < n && w[idx + x] == 1) {
                canSatisfy = true;
            }

            if (!canSatisfy) {
                return "-1";
            }
        }
        idx++;
    }

    // Block 3 – build the output string from w
    StringBuilder out = new StringBuilder();
    for (int val : w) {
        out.append(val);
    }
    return out.toString();
}

