        } else {
            easy.add(in.nextInt());
        }
    }

    hard.sort(null);
    easy.sort(null);

    int ptrh = 0, ptre = 0;          // pointers into hard / easy lists
    int ctre = 0, ctrh = 0;          // how many easy / hard tasks have been taken
    int mpoint = 0;                 // best score found so far

    while (ptrh < hard.size() || ptre < easy.size()) {
        int nowh = ptrh < hard.size() ? hard.get(ptrh) : Integer.MAX_VALUE;
        int nowe = ptre < easy.size() ? easy.get(ptre) : Integer.MAX_VALUE;

        if (nowh >= nowe) { // take an easy task
            if (!isDuplicate(easy, hard, ptre, ptrh)) {
                mpoint = evaluateTarget(easy.get(ptre), ctre, ctrh, a, b,
                        easy.size(), hard.size(), mpoint);
            }
            ptre++;
            ctre++;
            if (nowh == nowe) {
                ptrh++;
                ctrh++;
            }
        } else { // take a hard task
            if (!isDuplicate(easy, hard, ptre, ptrh)) {
                mpoint = evaluateTarget(hard.get(ptrh), ctre, ctrh, a, b,
                        easy.size(), hard.size(), mpoint);
            }
            ptrh++;
            ctrh++;
        }
    }

