/**
 * Returns {@code true} if the current element (either from {@code easy} or {@code hard})
 * is a duplicate of the previous element in its own list.
 */
private boolean isDuplicate(ArrayList<Integer> easy, ArrayList<Integer> hard,
                            int ptre, int ptrh) {
    boolean dupEasy = ptre > 0 && ptre < easy.size() && easy.get(ptre).equals(easy.get(ptre - 1));
    boolean dupHard = ptrh > 0 && ptrh < hard.size() && hard.get(ptrh).equals(hard.get(ptrh - 1));
    return dupEasy || dupHard;
}

/**
 * Evaluates the maximal score achievable when the next task has deadline {@code target}.
 * {@code ctre} and {@code ctrh} are the numbers of already solved easy/hard tasks.
 * {@code a} and {@code b} are the times required for an easy/hard task.
 * {@code easySize} and {@code hardSize} are the total numbers of easy/hard tasks.
 * Returns the updated maximal score.
 */
private int evaluateTarget(int target, int ctre, int ctrh,
                           long a, long b,
                           int easySize, int hardSize,
                           int currentMpoint) {
    long timeUsed = ctre * a + ctrh * b;

    if (timeUsed == target - 1) {
        return Math.max(ctre + ctrh, currentMpoint);
    } else if (timeUsed < target - 1) {
        int incr = 0;
        long tleft = -(timeUsed - target + 1); // remaining time after reaching target-1

        int aleft = easySize - ctre;
        int bleft = hardSize - ctrh;

        if (aleft * a <= tleft) {
            tleft -= aleft * a;
            incr += aleft;
            if (bleft * b <= tleft) {
                tleft -= bleft * b;
                incr += bleft;
            } else {
                incr += tleft / b;
            }
        } else {
            incr += tleft / a;
        }

        return Math.max(currentMpoint, ctre + ctrh + incr);
    }
    return currentMpoint;
}

