/**
 * Returns true if the current element in either list is a duplicate of the previous
 * element in the same list. This mirrors the original duplicate‑check logic.
 */
private boolean isDuplicate(ArrayList<Integer> easy, ArrayList<Integer> hard,
                            int ptre, int ptrh) {
    boolean dupEasy = ptre > 0 && ptre < easy.size() && easy.get(ptre).equals(easy.get(ptre - 1));
    boolean dupHard = ptrh > 0 && ptrh < hard.size() && hard.get(ptrh).equals(hard.get(ptrh - 1));
    return dupEasy || dupHard;
}

/**
 * Calculates the best possible score if we try to reach a problem with the given
 * {@code target} time. The current numbers of solved easy/hard problems are {@code ctre}
 * and {@code ctrh}. The function returns an updated maximum point value.
 */
private int tryUpdateMpoint(long target, long a, long b,
                            int ctre, int ctrh,
                            int easySize, int hardSize,
                            int currentMpoint) {
    long spent = ctre * a + ctrh * b;
    if (spent == target - 1) {
        // we can exactly finish this problem
        return Math.max(currentMpoint, ctre + ctrh);
    } else if (spent < target - 1) {
        int incr = 0;
        long tleft = -(spent - target + 1);          // time still available after reaching target‑1
        int aLeft = easySize - ctre;
        int bLeft = hardSize - ctrh;

        if (aLeft * a <= tleft) {
            tleft -= aLeft * a;
            incr += aLeft;
            if (bLeft * b <= tleft) {
                tleft -= bLeft * b;
                incr += bLeft;
            } else {
                incr += tleft / b;
            }
        } else {
            incr += tleft / a;
        }
        return Math.max(currentMpoint, ctre + ctrh + incr);
    }
    return currentMpoint; // spent > target‑1, cannot improve
}

