/**
 * Returns true if the element at {@code idx} in {@code list} is a duplicate of the
 * previous element (i.e. the same value appears consecutively). Handles boundary checks.
 */
private boolean isDuplicate(ArrayList<Integer> list, int idx) {
    return idx > 0 && idx < list.size() && list.get(idx).equals(list.get(idx - 1));
}

/**
 * Computes the maximal number of problems that can be solved given the current
 * elapsed time ({@code curTime}), the target threshold ({@code limit}), and the
 * remaining easy/hard problems.
 *
 * @return the total number of problems achievable from the current state,
 *         or -1 if the current state already exceeds {@code limit-1}.
 */
private int computePotentialPoints(long curTime, int limit,
                                   int solvedEasy, int solvedHard,
                                   long a, long b,
                                   int totalEasy, int totalHard) {
    long needed = limit - 1L;                     // we must finish before this moment
    if (curTime == needed) {
        return solvedEasy + solvedHard;
    } else if (curTime < needed) {
        long tleft = needed - curTime;           // free time still available
        int remainingEasy = totalEasy - solvedEasy;
        int remainingHard = totalHard - solvedHard;
        int incr = 0;

        if (remainingEasy * a <= tleft) {
            tleft -= remainingEasy * a;
            incr += remainingEasy;
            if (remainingHard * b <= tleft) {
                tleft -= remainingHard * b;
                incr += remainingHard;
            } else {
                incr += (int) (tleft / b);
            }
        } else {
            incr += (int) (tleft / a);
        }
        return solvedEasy + solvedHard + incr;
    }
    return -1; // already past the threshold
}

