/* --------------------------------------------------------------------- */
/* Helper that enumerates all possibilities for the first half of the   */
/* array. It stores, for each number of factorial‑operations used, the   */
/* count of each reachable sum in «s1». When a sum equals the target     */
/* «s» it also increments the answer directly.                           */
/* --------------------------------------------------------------------- */
private void processFirstHalf(int[] arr, int len, long[] f, int k, long target,
                              HashMap<Long, Integer>[] s1, long[] ans) {
    int[] bm = new int[len];
    while (inc(bm, 0)) {
        EvalResult r = evaluate(bm, arr, f);
        if (r.overflow || r.kUsed > k) continue;

        s1[r.kUsed].put(r.sum,
                s1[r.kUsed].getOrDefault(r.sum, 0) + 1);
        if (r.sum == target) ans[0]++;
    }
}

/* --------------------------------------------------------------------- */
/* Helper that enumerates all possibilities for the second half of the  */
/* array and combines them with the data collected from the first half. */
/* --------------------------------------------------------------------- */
private void processSecondHalf(int[] arr, int len, long[] f, int k, long target,
                               HashMap<Long, Integer>[] s1, long[] ans) {
    int[] bm = new int[len];
    while (inc(bm, 0)) {
        EvalResult r = evaluate(bm, arr, f);
        if (r.overflow || r.kUsed > k) continue;

        for (int i = 0; i <= k - r.kUsed; i++) {
            ans[0] += s1[i].getOrDefault(target - r.sum, 0);
        }
    }
}

/* --------------------------------------------------------------------- */
/* Evaluates a single bitmap configuration:                              */
/*   bm[i] == 0 → element not used                                        */
/*   bm[i] == 1 → element added as is                                      */
/*   bm[i] == 2 → element replaced by its factorial (if ≤ 18)             */
/* Returns the resulting sum, the number of factorial‑operations used    */
/* and a flag indicating that an overflow/invalid state was detected.    */
/* --------------------------------------------------------------------- */
private EvalResult evaluate(int[] bm, int[] arr, long[] f) {
    long sum = 0;
    int kUsed = 0;
    boolean overflow = false;

    for (int i = 0; i < bm.length; i++) {
        if (bm[i] == 1) {
            sum += arr[i];
            if (sum < 0) {               // overflow detection for signed long
                overflow = true;
                break;
            }
        } else if (bm[i] == 2) {
            if (arr[i] > 18) {           // factorial not defined in our table
                overflow = true;
                break;
            }
            sum += f[arr[i]];
            if (sum < 0) {
                overflow = true;
                break;
            }
            kUsed++;
        }
    }
    return new EvalResult(sum, kUsed, overflow);
}

/* Simple data holder for the result of «evaluate». */
private static class EvalResult {
    final long sum;
    final int kUsed;
    final boolean overflow;

    EvalResult(long sum, int kUsed, boolean overflow) {
        this.sum = sum;
        this.kUsed = kUsed;
        this.overflow = overflow;
    }
}

