/**
 * Solves a single test case.
 *
 * @param s the original numeric string
 * @param k maximum allowed distinct digits
 * @return the smallest string ≥ s that uses at most k distinct digits
 */
private static String solveCase(String s, int k) {
    int[] digitCount = new int[10];
    int distinct = 0;
    int pos = 0;
    StringBuilder ans = new StringBuilder(s);

    // Scan forward while the distinct‑digit constraint is satisfied
    while (pos < ans.length()) {
        int d = ans.charAt(pos) - '0';
        digitCount[d]++;
        if (digitCount[d] == 1) {
            distinct++;
        }
        if (distinct > k) {
            break;
        }
        pos++;
    }

    // If the whole string already satisfies the constraint, we are done
    if (pos == ans.length()) {
        return ans.toString();
    }

    // Backtrack one position because the current digit caused overflow
    int curDigit = ans.charAt(pos) - '0';
    digitCount[curDigit]--;
    if (digitCount[curDigit] == 0) {
        distinct--;
    }

    // Core adjustment loop – find the smallest lexicographically larger
    // string that respects the distinct‑digit limit
    while (true) {
        // If we hit a '9', we must backtrack further
        if (ans.charAt(pos) == '9') {
            pos--;
            int d = ans.charAt(pos) - '0';
            digitCount[d]--;
            if (digitCount[d] == 0) {
                distinct--;
            }
            continue;
        }

        // If we can increase the current digit without exceeding the limit,
        // do it and fill the suffix with the smallest possible digits
        if (distinct < k) {
            ans.setCharAt(pos, (char) (ans.charAt(pos) + 1));
            int d = ans.charAt(pos) - '0';
            digitCount[d]++;
            if (digitCount[d] == 1) {
                distinct++;
            }

            if (distinct < k) {
                filling(ans, '0', pos + 1);
            } else {
                char smallestPresent = smallestPresentDigit(digitCount);
                filling(ans, smallestPresent, pos + 1);
            }
            break;
        }

        // Try to replace the current digit with the next larger digit that
        // already appears somewhere in the prefix
        int replacement = nextLargerExistingDigit(digitCount, ans.charAt(pos) - '0');
        if (replacement == -1) {
            // No suitable replacement → backtrack again
            pos--;
            int d = ans.charAt(pos) - '0';
            digitCount[d]--;
            if (digitCount[d] == 0) {
                distinct--;
            }
            continue;
        } else {
            // Perform the replacement and fill the rest
            ans.setCharAt(pos, (char) (replacement + '0'));
            char smallestPresent = smallestPresentDigit(digitCount);
            filling(ans, smallestPresent, pos + 1);
            break;
        }
    }

    return ans.toString();
}

/**
 * Returns the smallest digit that currently appears in the prefix
 * (i.e., has a positive count). If none exists, returns '0'.
 */
private static char smallestPresentDigit(int[] digitCount) {
    for (int i = 0; i < 10; i++) {
        if (digitCount[i] > 0) {
            return (char) (i + '0');
        }
    }
    return '0';
}

/**
 * Finds the smallest digit greater than {@code cur} that already appears
 * in the prefix (positive count). Returns -1 if no such digit exists.
 */
private static int nextLargerExistingDigit(int[] digitCount, int cur) {
    for (int i = cur + 1; i < 10; i++) {
        if (digitCount[i] > 0) {
            return i;
        }
    }
    return -1;
}

public static void main(String[] args) {
