        while (p < ans.length()) {
            d[ans.charAt(p) - '0']++;
            if (d[ans.charAt(p) - '0'] == 1) map_sz++;
            if (map_sz > k) {
                break;
            }
            p++;
        }
        if (p == ans.length()) {
            out.println(ans);
            continue;
        }
        // delegate the complex correction logic
        adjustAfterOverflow(ans, d, k, map_sz, p);
        out.println(ans);
    }
    out.flush();
