/**
 * Handles the situation where the prefix of {@code ans} already contains
 * more than {@code k} distinct digits. The method mutates the {@code ans}
 * {@link StringBuilder} and the digit‑frequency array {@code d} so that the
 * resulting string is the smallest possible number not smaller than the
 * original one and contains at most {@code k} distinct digits.
 *
 * @param ans   the mutable number representation
 * @param d     frequency of each digit (0‑9) in the current prefix
 * @param k     maximum allowed distinct digits
 * @param mapSize number of distinct digits currently present (value copy)
 * @param pos   index where the overflow was first detected (value copy)
 */
private static void adjustAfterOverflow(StringBuilder ans, int[] d, int k, int mapSize, int pos) {
    // remove the digit that caused the overflow
    d[ans.charAt(pos) - '0']--;
    if (d[ans.charAt(pos) - '0'] == 0) {
        mapSize--;
    }

    while (true) {
        // backtrack over trailing '9's
        if (ans.charAt(pos) == '9') {
            pos--;
            d[ans.charAt(pos) - '0']--;
            if (d[ans.charAt(pos) - '0'] == 0) {
                mapSize--;
            }
            continue;
        }

        // we can increase the current digit and still stay under the limit
        if (mapSize < k) {
            ans.setCharAt(pos, (char) (ans.charAt(pos) + 1));
            d[ans.charAt(pos) - '0']++;
            if (d[ans.charAt(pos) - '0'] == 1) mapSize++;
            if (mapSize < k) {
                filling(ans, '0', pos + 1);
            } else {
                char c = findSmallestUsedDigit(d);
                filling(ans, c, pos + 1);
            }
            break;
        }

        // try to replace the digit with the next higher digit already present
        int nextHigher = findNextHigherUsedDigit(d, ans.charAt(pos) - '0');
        if (nextHigher == -1) {
            // no suitable digit → backtrack further
            pos--;
            d[ans.charAt(pos) - '0']--;
            if (d[ans.charAt(pos) - '0'] == 0) {
                mapSize--;
            }
            continue;
        } else {
            ans.setCharAt(pos, (char) (nextHigher + '0'));
            char c = findSmallestUsedDigit(d);
            filling(ans, c, pos + 1);
            break;
        }
    }
}

/** Returns the smallest digit that currently appears in the prefix (or '0' if none). */
private static char findSmallestUsedDigit(int[] d) {
    for (int i = 0; i < 10; i++) {
        if (d[i] > 0) {
            return (char) (i + '0');
        }
    }
    return '0';
}

/** Returns the smallest digit larger than {@code cur} that already appears, or -1 if none. */
private static int findNextHigherUsedDigit(int[] d, int cur) {
    for (int i = cur + 1; i < 10; i++) {
        if (d[i] > 0) {
            return i;
        }
    }
    return -1;
}

/** Fills the suffix of {@code sb} starting at {@code start} with the given character. */
private static void filling(StringBuilder sb, char c, int start) {
    for (int i = start; i < sb.length(); i++) {
        sb.setCharAt(i, c);
    }
}

