                for (int i = 0; i < n; i++) {
                    for (int j = 0; j < 2; j++) {
                        s[j][i + 1] = s[j][i] + (i % 2 == j ? a[i] : 0);
                        numSameParity[j][i + 1] = numSameParity[j][i] + (i % 2 == j ? 1 : 0);
                    }
                    sBoth[i + 1] = sBoth[i] + a[i];
                }
                long sumAll = sBoth[n];

                long ans = 0;
                for (int i = 0; i <= n; i++) {
                    if (2 * sBoth[i] < sumAll) {
                        ++ans;
                    }
                }

                if (n >= 2) {
                    for (int first = 0; first < 2; first++) {
                        for (int last = 0; last < 2; last++) {
                            for (int pref = (first == 0 ? 1 : 0); pref <= n - 2; pref++) {
                                if (pref == n - 2) {
                                    if (last == 1) {
                                        continue;
                                    }
                                }


                                long sum1 = 0;
                                sum1 += (first == 1 ? a[0] : 0);
                                sum1 += (last == 1 ? a[n - 1] : 0);
                                sum1 += sBoth[pref + 1] - sBoth[1];
                                if (2 * sum1 > sumAll) {
                                    ++ans;
                                    if (ans >= MOD) {
                                        ans -= MOD;
                                    }
