/**
 * Computes the contribution to the answer for a fixed (first, last, pref) configuration.
 *
 * The logic mirrors the original nested loops, but is isolated in its own method
 * to improve readability and maintainability.
 */
private long countForPref(int first, int last, int pref, int n, int[] a, long sumAll,
                          long[][] s, long[][] numSameParity, long[] sBoth) {

    long sum1 = 0;
    sum1 += (first == 1 ? a[0] : 0);
    sum1 += (last == 1 ? a[n - 1] : 0);
    sum1 += sBoth[pref + 1] - sBoth[1];

    long result = 0;
    if (2 * sum1 > sumAll) {
        result++;                     // the case where we stop right after pref
    }

    int l = pref + 1;
    int r = n - 2;
    int parity = pref % 2;
    boolean no11 = (n - 2) % 2 == parity && last == 1;
    if (no11) {
        --r;                          // cannot use position n‑2 when it would create "11"
    }

    // binary search for the smallest index where the condition becomes true
    while (r - l > 1) {
        int m = (l + r) / 2;
        long add = s[parity][m + 1] - s[parity][pref + 1];
        if (2 * (sum1 + add) > sumAll) {
            r = m;
        } else {
            l = m;
        }
    }

    if (l >= r) {
        return result;
    }

    long add = s[parity][r + 1] - s[parity][pref + 1];
    if (2 * (sum1 + add) <= sumAll) {
        return result;
    }

    long here = numSameParity[parity][n - 1] - numSameParity[parity][r];
    if (no11) {
        --here;                       // exclude the forbidden position when needed
    }
    result += here;
    return result;
}

