/**
 * Builds a string containing the characters a‑z in normal alphabetical order,
 * respecting the frequencies stored in {@code counts}.
 */
private static String buildAlphabeticalString(int[] counts) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < 26; i++) {
        for (int j = 0; j < counts[i]; j++) {
            sb.append((char) (i + 'a'));
        }
    }
    return sb.toString();
}

/**
 * Builds the special ordering required when the second character of {@code y}
 * is 'b': all 'a's, then all 'c's, then all 'b's, followed by the remaining
 * letters in alphabetical order.
 */
private static String buildSpecialString(int[] counts) {
    StringBuilder sb = new StringBuilder();

    // a's
    for (int j = 0; j < counts[0]; j++) {
        sb.append('a');
    }
    // c's
    for (int j = 0; j < counts[2]; j++) {
        sb.append('c');
    }
    // b's
    for (int j = 0; j < counts[1]; j++) {
        sb.append('b');
    }
    // d‑z in normal order
    for (int i = 3; i < 26; i++) {
        for (int j = 0; j < counts[i]; j++) {
            sb.append((char) (i + 'a'));
        }
    }
    return sb.toString();
}

