            if (c == 'L') {
                finalHori--;
            } else if (c == 'R') {
                finalHori++;
            } else if (c == 'U') {
                finalVerti++;
            } else { // 'D'
                finalVerti--;
            }
        }

        int[] removal = findRemoval(s);

        if (finalHori == 0 && finalVerti == 0) {
            sb.append("10000000 10000000\n");
        } else if (removal != null) {
            sb.append(removal[0]).append(' ').append(removal[1]).append('\n');
