/**
 * Returns the coordinates of the first step whose removal makes the whole walk
 * return to the origin, or {@code null} if no such step exists.
 */
private static int[] findRemoval(String s) {
    int hori = 0, verti = 0;
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == 'L') {
            hori--;
        } else if (c == 'R') {
            hori++;
        } else if (c == 'U') {
            verti++;
        } else { // 'D'
            verti--;
        }

        if (returnsToOriginSkipping(s, hori, verti)) {
            return new int[] { hori, verti };
        }
    }
    return null;
}

/**
 * Simulates the walk while skipping the step that would move the cursor to
 * (skipX,skipY). Returns {@code true} if the resulting walk ends at the origin.
 */
private static boolean returnsToOriginSkipping(String s, int skipX, int skipY) {
    int posx = 0, posy = 0;
    for (int j = 0; j < s.length(); j++) {
        char c = s.charAt(j);
        if (c == 'L') {
            if (posx - 1 == skipX && posy == skipY) {
                continue;
            }
            posx--;
        } else if (c == 'R') {
            if (posx + 1 == skipX && posy == skipY) {
                continue;
            }
            posx++;
        } else if (c == 'U') {
            if (posx == skipX && posy + 1 == skipY) {
                continue;
            }
            posy++;
        } else { // 'D'
            if (posx == skipX && posy - 1 == skipY) {
                continue;
            }
            posy--;
        }
    }
    return posx == 0 && posy == 0;
}

