public void solve(final int testNumber, final InputReader in, final PrintWriter out) {
        int counter = in.nextInt();
        int queries = in.nextInt();
        int[] array = in.nextIntArray(counter);
        final int SIZE_OF_BLOCK = 1111;
        final int BLOCKS = counter / SIZE_OF_BLOCK + 1;
        long[][] blocks = new long[BLOCKS][SIZE_OF_BLOCK];
        Integer[][] sorted = new Integer[BLOCKS][SIZE_OF_BLOCK];
        long[] ad = new long[BLOCKS];
        int[] size = new int[BLOCKS];
        int block = 0;
        for (int i = 0; i < counter; ++i) {
            blocks[block][size[block]] = array[i];
            ++size[block];
            if (size[block] == SIZE_OF_BLOCK || i == counter - 1) {
                resort(sorted[block], 0, size[block], blocks[block]);
                ++block;
            }
        }
        StringBuilder answer = new StringBuilder();
        for (int query = 0; query < queries; ++query) {
            final int type = in.nextInt();
            if (type == 1) {
                int from = in.nextInt() - 1;
                int to = in.nextInt() - 1;
                int delta = in.nextInt();
                int fromBlock = from / SIZE_OF_BLOCK;
                int toBlock = to / SIZE_OF_BLOCK;
                if (fromBlock == toBlock) {
                    block = fromBlock;
                    if (ad[block] != 0) {
                        for (int i = 0; i < size[block]; ++i) {
                            blocks[block][i] += ad[block];
                        }
                        ad[block] = 0;
                    }
                    for (int i = from % SIZE_OF_BLOCK; i <= to % SIZE_OF_BLOCK; ++i) {
                        blocks[block][i] += delta;
                    }
                    resort(sorted[block], 0, size[block], blocks[block]);
                } else {
                    {
                        block = fromBlock;
                        for (int i = 0; i < size[block]; ++i) {
                            blocks[block][i] += ad[block];
                        }
                        ad[block] = 0;
                        for (int i = from % SIZE_OF_BLOCK; i < size[block]; ++i) {
                            blocks[block][i] += delta;
                        }
                        resort(sorted[block], 0, size[block], blocks[block]);
                    }
                    {
                        block = toBlock;
                        for (int i = 0; i < size[block]; ++i) {
                            blocks[block][i] += ad[block];
                        }
                        ad[block] = 0;
                        for (int i = 0; i <= to % SIZE_OF_BLOCK; ++i) {
                            blocks[block][i] += delta;
                        }
                        resort(sorted[block], 0, size[block], blocks[block]);
                    }
                    for (block = fromBlock + 1; block < toBlock; ++block) {
                        ad[block] += delta;
                    }
                }
            } else if (type == 2) {
                final int target = in.nextInt();
                int min = -1;
                int max = -2;
                for (block = 0; block < BLOCKS; ++block) {
                    int left = -1;
                    int right = size[block];
                    while (right - left > 1) {
                        int middle = (left + right) >>> 1;
                        if (blocks[block][sorted[block][middle]] + ad[block] <= target) {
                            left = middle;
                        } else {
                            right = middle;
                        }
                    }
                    if (left >= 0 && blocks[block][sorted[block][left]] + ad[block] == target) {
                        max = sorted[block][left] + SIZE_OF_BLOCK * block;
                        if (min == -1) {
                            right = left + 1;
                            left = -1;
                            while (right - left > 1) {
                                int middle = (left + right) >>> 1;
                                if (blocks[block][sorted[block][middle]] + ad[block] < target) {
                                    left = middle;
                                } else {
                                    right = middle;
                                }
                            }
                            min = sorted[block][right] + SIZE_OF_BLOCK * block;
                        }
                    }
                }
                answer.append(max - min);
                answer.append('\n');
            } else throw new AssertionError(type);
        }
        answer.append('\n');
        out.println(answer.toString());
    }

public void solve(int testNumber, FastInput in, FastOutput out) {
            int n = in.readInt();
            int s = in.readInt();
            int e = in.readInt();

            int[] x = new int[n];

            int[] a = new int[n];

            int[] b = new int[n];

            int[] c = new int[n];

            int[] d = new int[n];
            in.populate(x);
            in.populate(a);
            in.populate(b);
            in.populate(c);
            in.populate(d);

            long[][] dp = new long[n + 1][n + 1];
            long inf = (long) 1e18;
            SequenceUtils.deepFill(dp, inf);


            dp[0][0] = 0;
            for (int i = 0; i < n; i++) {
                int indegSum = i;
                int outdegSum = i;
                if (i >= s) {
                    indegSum--;
                }
                if (i >= e) {
                    outdegSum--;
                }
                for (int j = 0; j <= n; j++) {
                    int indeg = j;
                    int outdeg = outdegSum - (indegSum - j);
                    if (i > 0 && indeg == 0 && outdeg <= 0) {
                        continue;
                    }
                    if (outdeg < 0) {
                        continue;
                    }
                    if (i >= e && i >= s && (indeg == 0 || outdeg == 0)) {
                        continue;
                    }

                    if (i + 1 == s) {

                        dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + d[i] - x[i]);


                        if (j > 0) {
                            dp[i + 1][j - 1] = Math.min(dp[i + 1][j - 1], dp[i][j] + c[i] + x[i]);
                        }

                        continue;
                    }

                    if (i + 1 == e) {

                        if (j + 1 <= n) {
                            dp[i + 1][j + 1] = Math.min(dp[i + 1][j + 1], dp[i][j] + b[i] - x[i]);
                        }

                        if (outdeg > 0) {
                            dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + a[i] + x[i]);
                        }
                        continue;
                    }


                    if (j + 1 <= n) {
