/** Fills the static direction tables (up, down, left, right) used by {@code calc}. */
private static void computeDirectionTables(int[][] grid, int[] delta) {
    down = new int[H][W];
    up = new int[H][W];
    left = new int[H][W];
    right = new int[H][W];

    // right direction
    for (int a = 0; a < H; a++) {
        for (int b = 1; b < W; b++) {
            int change = grid[a][b] - grid[a][b - 1];
            right[a][b] = right[a][b - 1] + delta[(int) (Math.signum(change) + 1)];
        }
    }
    // left direction
    for (int a = 0; a < H; a++) {
        for (int b = W - 2; b >= 0; b--) {
            int change = grid[a][b] - grid[a][b + 1];
            left[a][b] = left[a][b + 1] + delta[(int) (Math.signum(change) + 1)];
        }
    }
    // down direction
    for (int b = 0; b < W; b++) {
        for (int a = 1; a < H; a++) {
            int change = grid[a][b] - grid[a - 1][b];
            down[a][b] = down[a - 1][b] + delta[(int) (Math.signum(change) + 1)];
        }
    }
    // up direction
    for (int b = 0; b < W; b++) {
        for (int a = H - 2; a >= 0; a--) {
            int change = grid[a][b] - grid[a + 1][b];
            up[a][b] = up[a + 1][b] + delta[(int) (Math.signum(change) + 1)];
        }
    }
}

/** Searches all admissible rectangles and returns the one whose clockwise value
 *  is closest to {@code target}. */
private static Result findClosestRectangle(long target) {
    long bestDiff = Long.MAX_VALUE;
    String bestCoords = "";

    for (int a = 0; a < H; a++) {
        for (int b = 0; b < W; b++) {
            for (int c = a + 2; c < H; c++) {
                int low = b + 2;
                int high = W - 1;

                while (low <= high) {
                    int mid = (low + high) >>> 1;
                    long clockwise = calc(a, b, c, mid);

                    long diff = Math.abs(clockwise - target);
                    if (diff < bestDiff) {
                        bestDiff = diff;
                        bestCoords = (a + 1) + " " + (b + 1) + " " + (c + 1) + " " + (mid + 1);
                    }

                    if (clockwise > target) {
                        high = mid - 1;
                    } else if (clockwise < target) {
                        low = mid + 1;
                    } else {
                        // Exact match – we can stop searching this line
                        break;
                    }
                }
            }
        }
    }
    return new Result(bestDiff, bestCoords);
}

/** Simple holder for the search result. */
private static class Result {
    final long diff;
    final String coords;

    Result(long diff, String coords) {
        this.diff = diff;
        this.coords = coords;
    }
}

