public static long numSubstrings(String str,int k){
	    int n=str.length();
	    int[] next1Index=new int[n];
	    int[] prev1Index=new int[n];
	    prev1Index[0]=-1;
	    for(int i=1;i<n;i++){
	        if(str.charAt(i-1)=='1'){
	            prev1Index[i]=i-1;
	        }
	        else{
	            prev1Index[i]=prev1Index[i-1];
	        }
	    }
	    next1Index[n-1]=n;
	    for(int i=n-2;i>=0;i--){
	        if(str.charAt(i+1)=='1'){
	            next1Index[i]=i+1;
	        }
	        else{
	            next1Index[i]=next1Index[i+1];
	        }
	    }
	    long ans=0;
	    int start=0,end=0;

	    if(k==0){
	        for(int i=0;i<n;){
	            if(str.charAt(i)=='0'){
	                int numZeros=0;
	                int j=i;
	                while(j<str.length() && str.charAt(j)=='0'){
	                    j++;
	                    numZeros++;
	                }
	                ans+=(1L*numZeros*(numZeros+1))/2;
	                i=j;
	            }
	            else{
	                i++;
	            }
	        }
	        return ans;
	    }


	    int num1s=0;

	    while(end<n){
	        if(str.charAt(end)=='1'){
	            num1s++;
	            if(num1s==k){
	                break;
	            }
	            end++;
	        }
	        else{
	            if(num1s==0){
	                start++;
	                end++;
	            }
	            else{
	                end++;
	            }
	        }
	    }

	    if(end>=n){
	        return 0;
	    }

	    while(end<n){
            int startingPoints=start-prev1Index[start];
            int endingPoints=next1Index[end]-end;
            ans+=(1L*startingPoints*endingPoints);
            end=next1Index[end];
            start=next1Index[start];
	    }
	    return ans;
	}

