/**
 * Returns the number of vertices that are exactly {@code p} edges below {@code v}
 * and share the same depth as {@code v}.  The result is 0 when no such vertex
 * exists (including when the ancestor {@code u} obtained by walking {@code p}
 * steps up from {@code v} is 0 or -1).
 *
 * This method encapsulates the binary‑search logic that was previously inside
 * {@link #solve(int, ScanReader, PrintWriter)}.
 */
private int countDescendantsAtSameDepth(int v, int p) {
    int u = walk(v, p);
    if (u == 0 || u == -1) {
        return 0;
    }

    int lev = depth[v];
    int lowerBound = findLowerBound(u, lev, index[v]);
    if (lowerBound == -1) {
        return 0;
    }
    int upperBound = findUpperBound(u, lev, index[v]);
    return upperBound - lowerBound + 1;
}

/**
 * Binary search for the first position (lowest index) in {@code atlevel[lev]}
 * where the LCA of {@code u} and the node at that position equals {@code u}.
 *
 * @param u   the ancestor obtained by walking up {@code p} steps from {@code v}
 * @param lev the depth level of {@code v}
 * @param startIdx the index of {@code v} inside {@code atlevel[lev]}
 * @return the lower bound index, or -1 if none satisfies the condition
 */
private int findLowerBound(int u, int lev, int startIdx) {
    int left = 0;
    int right = startIdx;
    int result = -1;
    while (left <= right) {
        int mid = (left + right) >>> 1;
        int candidate = atlevel[lev].get(mid);
        int lca = lca(u, candidate);
        if (lca == u) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    return result;
}

/**
 * Binary search for the last position (highest index) in {@code atlevel[lev]}
 * where the LCA of {@code u} and the node at that position equals {@code u}.
 *
 * @param u   the ancestor obtained by walking up {@code p} steps from {@code v}
 * @param lev the depth level of {@code v}
 * @param startIdx the index of {@code v} inside {@code atlevel[lev]}
 * @return the upper bound index, or -1 if none satisfies the condition
 */
private int findUpperBound(int u, int lev, int startIdx) {
    int left = startIdx;
    int right = atlevel[lev].size() - 1;
    int result = -1;
    while (left <= right) {
        int mid = (left + right) >>> 1;
        int candidate = atlevel[lev].get(mid);
        int lca = lca(u, candidate);
        if (lca == u) {
            result = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return result;
}

