/**
 * Returns true if there exists a previously stored row that can be combined
 * with the current {@code mat} so that for every column at least one of the
 * two rows contains a 0. The stored rows are represented as integer bit masks
 * in {@code map}.
 */
private boolean hasCompatibleRow(int[] mat, int k, Map<Integer, Integer> map) {
    int currentMask = encodeRow(mat, k);
    int allowedMask = ((1 << k) - 1) ^ currentMask;   // bits where mat[i] == 0

    // iterate over all sub‑masks of allowedMask (including 0)
    for (int sub = allowedMask; ; sub = (sub - 1) & allowedMask) {
        if (map.containsKey(sub)) {
            return true;
        }
        if (sub == 0) {
            break;
        }
    }
    return false;
}

/**
 * Encodes the row {@code mat} as an integer where bit *i* is 1 iff
 * {@code mat[i] == 1}. Works for any {@code k ≤ 31}.
 */
private int encodeRow(int[] mat, int k) {
    int val = 0;
    for (int i = 0; i < k; ++i) {
        if (mat[i] == 1) {
            val |= (1 << i);
        }
    }
    return val;
}

