/**
 * Executes a single query and returns the maximal value.
 *
 * The method contains the original heavy inner‑loop logic that was previously
 * embedded in {@code main}.  It mutates {@code bestByColor}, {@code f} and
 * {@code top2} which are allocated once per test case and reused for every
 * query to avoid repeated allocations.
 */
private static long processQuery(int a, int b, int n,
                                 int[] color, int[] value,
                                 long[] bestByColor, long[] f, int[] top2) {
    // Fill temporary structures with their initial values.
    Arrays.fill(bestByColor, -INF);
    Arrays.fill(top2, -1);
    long ans = 0L;

    for (int i = 0; i < n; i++) {
        // Base value using coefficient b.
        f[i] = (long) b * value[i];

        // Extend a sequence that ends with the same colour using coefficient a.
        if (bestByColor[color[i]] != -INF) {
            long best = bestByColor[color[i]] + (long) a * value[i];
            f[i] = Math.max(f[i], best);
        }

        // Try to extend a sequence that ends with a different colour
        // (the best colour stored in top2[0] or top2[1]).
        if (top2[0] != -1) {
            int bestColor = top2[0];
            if (bestColor == color[i]) {
                if (top2[1] != -1) {
                    int secondBestColor = top2[1];
                    if (bestByColor[secondBestColor] == -INF) {
                        throw new RuntimeException("wtf2");
                    }
                    long best = bestByColor[secondBestColor] + (long) b * value[i];
                    f[i] = Math.max(f[i], best);
                }
            } else {
                if (bestByColor[bestColor] == -INF) {
                    throw new RuntimeException("wtf");
                }
                long best = bestByColor[bestColor] + (long) b * value[i];
                f[i] = Math.max(f[i], best);
            }
        }

        // Update the best value for the current colour.
        bestByColor[color[i]] = Math.max(bestByColor[color[i]], f[i]);

        // Maintain the two colours with the highest {@code bestByColor} values.
        if (top2[0] != color[i] && top2[1] != color[i]) {
            if (top2[1] == -1 || bestByColor[top2[1]] < bestByColor[color[i]]) {
                top2[1] = color[i];
            }
        }
        if (top2[1] != -1) {
            if (top2[0] == -1 || bestByColor[top2[0]] < bestByColor[top2[1]]) {
                int tmp = top2[0];
                top2[0] = top2[1];
                top2[1] = tmp;
            }
        }

        // Global answer for this query.
        ans = Math.max(ans, f[i]);
    }
    return ans;
}

