/**
 * Determines the output value for a pair (ue, mae) based on the six
 * integers stored in {@code d}. The logic mirrors the original nested
 * if‑else structure but is encapsulated in a dedicated, well‑named
 * method, improving readability and maintainability.
 *
 * @param ue   the first value of the query
 * @param mae  the second value of the query
 * @param d    an array of six integers used for the lookup
 * @return the corresponding integer from {@code d}
 */
private static int resolve(int ue, int mae, int[] d) {
    // ue matches d[0]
    if (ue == d[0]) {
        if (mae == d[1]) return d[2];
        else if (mae == d[2]) return d[4];
        else if (mae == d[3]) return d[1];
        else if (mae == d[4]) return d[3];
    }
    // ue matches d[1]
    else if (ue == d[1]) {
        if (mae == d[0]) return d[3];
        else if (mae == d[2]) return d[0];
        else if (mae == d[3]) return d[5];
        else if (mae == d[5]) return d[2];
    }
    // ue matches d[2]
    else if (ue == d[2]) {
        if (mae == d[0]) return d[1];
        else if (mae == d[1]) return d[5];
        else if (mae == d[4]) return d[0];
        else if (mae == d[5]) return d[4];
    }
    // ue matches d[3]
    else if (ue == d[3]) {
        if (mae == d[0]) return d[4];
        else if (mae == d[1]) return d[0];
        else if (mae == d[4]) return d[5];
        else if (mae == d[5]) return d[1];
    }
    // ue matches d[4]
    else if (ue == d[4]) {
        if (mae == d[0]) return d[2];
        else if (mae == d[2]) return d[5];
        else if (mae == d[3]) return d[0];
        else if (mae == d[5]) return d[3];
    }
    // ue matches d[5]
    else if (ue == d[5]) {
        if (mae == d[1]) return d[3];
        else if (mae == d[2]) return d[1];
        else if (mae == d[3]) return d[4];
        else if (mae == d[4]) return d[2];
    }

    // If the input combination is not covered by the original logic,
    // return a sentinel value (the original code never reached this point).
    return -1;
}

