/*--------------------------------------------------------------
 *  Helper methods – each one has a single, well‑defined purpose.
 *--------------------------------------------------------------*/

private static void precomputeG(int limit) {
    // base case for single‑digit numbers
    for (int i = 0; i <= 9; i++) {
        g[i] = i;
    }
    // fill the rest using the product‑of‑non‑zero‑digits rule
    for (int i = 10; i <= limit; i++) {
        int product = productOfNonZeroDigits(i);
        g[i] = g[product];
    }
}

/** Returns the product of the non‑zero decimal digits of {@code n}. */
private static int productOfNonZeroDigits(int n) {
    int result = 1;
    while (n > 0) {
        int digit = n % 10;
        if (digit > 0) {
            result *= digit;
        }
        n /= 10;
    }
    return result;
}

/** Builds {@code glist}, an array of lists that groups numbers by their {@code g} value. */
private static void initGList(int limit) {
    for (int i = 0; i <= 9; i++) {
        glist[i] = new ArrayList<>();
        glist[i].add(-1);               // sentinel value kept from original logic
    }
    for (int i = 0; i <= limit; i++) {
        glist[g[i]].add(i);
    }
}

