    long bestTotal = evaluateBestTotal(skills, maxSkill);

    out.println(bestTotal <= 0 ? 0 : bestTotal);
}

/* --------------------------------------------------------------------- *
 * Helper methods – each one handles a single, well‑defined responsibility *
 * --------------------------------------------------------------------- */

private LinkedHashMap<Integer, Skills> createSkillsMap(int m) {
    LinkedHashMap<Integer, Skills> map = new LinkedHashMap<>();
    for (int i = 0; i < m; i++) {
        map.put(i, new Skills());
    }
    return map;
}

private void fillSkills(LinkedHashMap<Integer, Skills> skills, int n, InputReader in) {
    for (int i = 0; i < n; i++) {
        int skillIndex = in.nextInt() - 1;
        int value = in.nextInt();
        skills.get(skillIndex).al.add(value);
    }
}

private int computeMaxSkill(LinkedHashMap<Integer, Skills> skills, int m) {
    int max = 0;
    for (int i = 0; i < m; i++) {
        Skills s = skills.get(i);
        s.calcPrefixSum();                     // prepares prefix sums for later queries
        max = Math.max(s.al.size(), max);      // longest list determines the upper bound
    }
    return max;
}

/**
 * Iterates over all possible team sizes (1 … maxSkill) and keeps the
 * maximum total sum of positive contributions.  Skills that yield a
 * non‑positive contribution for a given team size are removed so that
 * subsequent iterations do not recompute them.
 */
private long evaluateBestTotal(LinkedHashMap<Integer, Skills> skills, int maxSkill) {
    long best = 0L;

    for (int size = 1; size <= maxSkill; size++) {
        long currentTotal = 0L;
        List<Integer> toRemove = new ArrayList<>();

        for (Map.Entry<Integer, Skills> entry : skills.entrySet()) {
            long contribution = entry.getValue().getSum(size);
            if (contribution > 0) {
                currentTotal += contribution;
            } else {
                toRemove.add(entry.getKey());
            }
        }

        // Remove skills that no longer contribute positively
        for (Integer key : toRemove) {
            skills.remove(key);
        }

        best = Math.max(best, currentTotal);
    }
    return best;
}

public void solve(int testNumber, InputReader in, OutputWriter out) {
    int n = in.nextInt();
    int m = in.nextInt();

    // Build the skills map and fill it with the input data
    LinkedHashMap<Integer, Skills> skills = buildSkillsMap(n, m, in);

    // If no skill groups were created, the answer is 0
    if (skills.isEmpty()) {
        out.println(0);
        return;
    }

    // Determine the largest team size after prefix‑sum preparation
    int maxSkill = computeMaxTeamSize(skills);

    // Find the maximum obtainable total across all possible team sizes
    long totalMax = computeMaximumTotal(skills, maxSkill);

    out.println(totalMax <= 0 ? 0 : totalMax);
}

/**
 * Creates a map of {@code Skills} objects, one per team, and populates it
 * with the input values.
 */
private static LinkedHashMap<Integer, Skills> buildSkillsMap(int n, int m, InputReader in) {
    LinkedHashMap<Integer, Skills> skills = new LinkedHashMap<>();
    for (int i = 0; i < m; i++) {
        skills.put(i, new Skills());
    }

    for (int i = 0; i < n; i++) {
        int teamIdx = in.nextInt() - 1;   // teams are 1‑based in the input
        int value   = in.nextInt();
        skills.get(teamIdx).al.add(value);
    }
    return skills;
}

/**
 * Runs {@code calcPrefixSum()} for every {@code Skills} instance and returns
 * the size of the largest skill list.
 */
private static int computeMaxTeamSize(LinkedHashMap<Integer, Skills> skills) {
    int maxSkill = 0;
    for (Skills s : skills.values()) {
        s.calcPrefixSum();
        maxSkill = Math.max(s.al.size(), maxSkill);
    }
    return maxSkill;
}

/**
 * For each possible team size (1 … maxSkill) calculates the sum of contributions
 * of all teams that have a positive contribution for that size.
 * Teams with a non‑positive contribution are removed from the map to avoid
 * needless work in subsequent iterations.
 */
private static long computeMaximumTotal(LinkedHashMap<Integer, Skills> skills, int maxSkill) {
    long totalMax = 0L;

    for (int size = 1; size <= maxSkill; size++) {
        long total = 0L;
        List<Integer> toRemove = new ArrayList<>();

        for (Map.Entry<Integer, Skills> entry : skills.entrySet()) {
            long contribution = entry.getValue().getSum(size);
            if (contribution > 0) {
                total += contribution;
            } else {
                toRemove.add(entry.getKey());
            }
        }

        // Remove teams that can no longer contribute positively
        for (Integer key : toRemove) {
            skills.remove(key);
        }

        totalMax = Math.max(totalMax, total);
    }
    return totalMax;
}

