/** Reads exactly {@code length} integers from {@code sc} into {@code arr}. */
private static void readArray(FastReader sc, int[] arr) {
    for (int i = 0; i < arr.length; i++) {
        arr[i] = sc.nextInt();
    }
}

/** Builds the index lookup table: for each value v present in {@code a},
 *  {@code index[v-1]} stores the position of v in {@code a}. */
private static int[] buildIndex(int[] a) {
    final int MAX_VALUE = 200_001;          // matches original fixed size
    int[] index = new int[MAX_VALUE];
    for (int i = 0; i < a.length; i++) {
        // values are 1‑based, array is 0‑based
        index[a[i] - 1] = i;
    }
    return index;
}

/** Computes the answer array according to the original algorithm. */
private static int[] computeAnswers(int[] a, int[] b) {
    int n = a.length;
    int[] ans = new int[n];
    int[] index = buildIndex(a);

    int min = 0;
    int max = n - 1;

